window.__ARXIV_DATA__ = {"papers":[{"id":"2607.18237v1","title":"The Many Senses of Visual Similarity: A Text-Prompted Image Perceptual Metric","abstract":"Human visual similarity judgments are context-dependent. For example, two images may be similar in shape but distinct in color. Existing perceptual similarity metrics, however, collapse these nuances into a single scalar value, offering no mechanism to condition on specific aspects. To bridge this gap, we introduce a large-scale dataset of human similarity judgments over image triplets, where each triplet is annotated across multiple, free-form semantic aspects of similarity. Benchmarking a broad range of frontier vision-language models (VLMs) reveals a considerable performance gap compared to human annotators' consensus. Leveraging our data, we fine-tune a VLM to produce our Text-Prompted Image Perceptual Similarity (TPIPS) metric, capturing multiple senses of visual similarity depending on the specified text prompt. We demonstrate that TPIPS aligns more closely with human perception and generalizes reliably beyond the training distribution. Finally, we show that TPIPS unlocks new capabilities in text-guided retrieval, compositional search, and the fine-grained evaluation of generative models. Our code, data, and trained models are at https://peterwang512.github.io/TPIPS","authors":["Sheng-Yu Wang","Yotam Nitzan","Aaron Hertzmann","Jun-Yan Zhu","Eli Shechtman","Alexei A. Efros","Richard Zhang"],"published":"2026-07-20T17:59:51Z","updated":"2026-07-20T17:59:51Z","abstract_url":"https://arxiv.org/abs/2607.18237v1","html_url":"https://arxiv.org/html/2607.18237v1","pdf_url":"https://arxiv.org/pdf/2607.18237v1.pdf","matched_keywords":["retrieval"],"source_used":"abstract","source_text_chars":1269,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 retrieval 相关；摘要显示其主要贡献为：Human visual similarity judgments are context-dependent. For example, two images may be similar in shape but distinct in color. Existing perceptual similarity metrics, however, collapse these nuances into a single scalar value, offering no mechanism to condit...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"abstract","created_at":"2026-07-21T04:12:05+00:00","status":"fallback"},"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.18227v1","title":"FlowMimic: Mask-free Visual Editing and Generation with Pixel-pair Warped Flow Field for Online Video Editing Data Generation and Modality Mimicry","abstract":"In line with the prevailing direction of vision research, we explore the integration of both generation and editing capabilities for video and image modalities within a single model. Current approaches to collecting video editing data typically depend on labour-intensive, time-consuming curated procedures--involving object mask annotation, the use of error-introducing pair synthesis via I2V model and ControlNet-like guidance, and VLM-based quality filtering or refinement--and demonstrate limited task scalability. As a result, the diversity of editing tasks remains substantially narrower than that available for image editing models. We develop a pixel-pair temporal warped flow field that can directly generate corresponding video editing samples in real time from image editing samples, and we demonstrate across multiple levels of video editing tasks that a model can learn video editing using only such data. We regard the image modality as a particular form of the video modality. Accordingly, we design a modality mimic generation loss and a modality mimic editing loss to relatively align the capabilities--and thereby the output distributions--of the two modalities through mutual imitation. Moreover, language-based visual editing entails the comprehension of the editing instruction and the reference visual content, the localization of the region corresponding to that instruction within the reference visual contents, and the modification of that region alone. Existing approaches predominantly rely on external aids, such as fine-tuning an additional MLLM or explicitly supplying a mask sequence as auxiliary input during inference. In contrast, we aspire for the model to internalize this capability. To that end, we introduce sense-related tasks--for instance, referring expression segmentation--along with corresponding editing-region-aware latent-level loss and attention-level loss.","authors":["Dingyun Zhang","Lixue Gong","Wei Liu"],"published":"2026-07-20T17:58:03Z","updated":"2026-07-20T17:58:03Z","abstract_url":"https://arxiv.org/abs/2607.18227v1","html_url":"https://arxiv.org/html/2607.18227v1","pdf_url":"https://arxiv.org/pdf/2607.18227v1.pdf","matched_keywords":["video","instance"],"source_used":"abstract","source_text_chars":2054,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, instance 相关；摘要显示其主要贡献为：In line with the prevailing direction of vision research, we explore the integration of both generation and editing capabilities for video and image modalities within a single model. Current approaches to collecting video editing data typically depend on labo...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"abstract","created_at":"2026-07-21T04:12:05+00:00","status":"fallback"},"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.18218v1","title":"GigaPath-Flash and GigaTIME-Flash: Efficient Pathology Foundation Models for Whole-Slide and Tumor Microenvironment Analysis","abstract":"Foundation models have emerged as a driving force in computational pathology, with the potential to transform cancer diagnosis, prognosis, and treatment selection by learning transferable representations from large-scale histopathology data. A growing landscape of pathology foundation models now spans diverse data sources, architectures, and downstream applications. However, most pretrained models operate only at the image-tile level, use restrictive licenses, and remain computationally expensive, limiting large-scale slide-level clinical and research use. Here, we introduce GigaPath-Flash and GigaTIME-Flash, efficient models for whole-slide pathology AI and spatial proteomics prediction. GigaPath-Flash combines a 22M-parameter ViT-S tile encoder with a 21M-parameter LongNet slide encoder, both pretrained on large-scale real-world histopathology data. Its compact tile encoder is distilled from the billion-parameter GigaPath (ViT-g) teacher and shared by both models. GigaPath-Flash retains 97% of GigaPath's average slide-level performance with 50x less compute. GigaTIME-Flash extends this backbone to predict the tumor immune microenvironment directly from routine H&E images. It surpasses the original CNN-based GigaTIME in prediction quality while running 6x faster and using 8x less GPU memory. Together with GigaPath and GigaTIME, these models form an open-weight, Apache-2.0-licensed family pretrained on large-scale real-world clinical data. By releasing all models and weights, we provide accessible building blocks for computational pathology, immuno-oncology, and precision health.","authors":["Naoto Usuyama","Jeya Maria Jose Valanarasu","Sicong Yao","Hanwen Xu","Jaspreet Bagga","Guanghui Qin","Robert E. Kramer","Cliff Wong","Soohee Lee","Hao Qiu","Theodore Zhengde Zhao","Racheli Ben Shimol","Angela Crabtree","Kevin Matlock","Eduardo Alejandro Lozano Garcia","Naiteek Sangani","Alberto Santamaria-Pang","Jason Entenmann","Alexandra Q. Bartlett","Bill J. Wright","Bernard A. Fox","Brian Piening","Sheng Zhang","Sheng Wang","Tristan Naumann","Carlo Bifulco","Hoifung Poon"],"published":"2026-07-20T17:52:33Z","updated":"2026-07-20T17:52:33Z","abstract_url":"https://arxiv.org/abs/2607.18218v1","html_url":"https://arxiv.org/html/2607.18218v1","pdf_url":"https://arxiv.org/pdf/2607.18218v1.pdf","matched_keywords":["representation"],"source_used":"html","source_text_chars":29313,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 representation 相关；摘要显示其主要贡献为：Foundation models have emerged as a driving force in computational pathology, with the potential to transform cancer diagnosis, prognosis, and treatment selection by learning transferable representations from large-scale histopathology data. A growing landsca...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-21T04:12:06+00:00","status":"fallback"},"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.18217v1","title":"HOMIE: Human-object Centric Video Personalization via Multimodal Intelligent Enchancement","abstract":"Human-object centric video personalization (HOCVP) is a core task within subject-driven video generation. However, existing methods suffer from two key limitations. First, most approaches focusing on inter-subject personalization still struggle to strike a balance between high subject fidelity and accurate interaction patterns between humans and diverse objects, especially when objects represent abstract concepts such as logos. Second, while intra-subject references (e.g., OCR maps, multi-view inputs) are expected to enhance subject fidelity, most existing works lack mechanisms to understand such latent correspondence. To address both challenges, we propose HOMIE, an HOCVP framework that tackles both inter- and intra-subject input settings in a unified manner. Compared to previous approaches, HOMIE proposes a better MLLM integration strategy to extract knowledge of reference-level relationships without compromising the controllability of text encoders or incurring costly re-alignment. Specifically, we introduce global multimodal guidance within self-attention to better align MLLM-derived semantic features with VAE tokens. Furthermore, we propose modality-reference embedding to differentiate tokens from MLLM features and VAE tokens and associate intra-subject reference image tokens. Extensive experiments validate that our method achieves state-of-the-art performance across various HOCVP tasks. Project Page: https://yiyangcai.github.io/homie-page.github.io/","authors":["Yiyang Cai","Nan Chen","Rongchang Xie","Junwen Pan","Chunyang Jiang","Cheng Chen","Wen Zhou","Zhenbang Sun","Wei Xue","Wenhan Luo","Yike Guo"],"published":"2026-07-20T17:51:35Z","updated":"2026-07-20T17:51:35Z","abstract_url":"https://arxiv.org/abs/2607.18217v1","html_url":"https://arxiv.org/html/2607.18217v1","pdf_url":"https://arxiv.org/pdf/2607.18217v1.pdf","matched_keywords":["video","multimodal"],"source_used":"html","source_text_chars":75020,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, multimodal 相关；摘要显示其主要贡献为：Human-object centric video personalization (HOCVP) is a core task within subject-driven video generation. However, existing methods suffer from two key limitations. First, most approaches focusing on inter-subject personalization still struggle to strike a ba...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-21T04:12:06+00:00","status":"fallback"},"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.18198v1","title":"Three-Body Scattering for Generative Modeling","abstract":"Modern generative models typically rely on an adversarial critic, a prescribed noise-to-data path, or an autoregressive factorization. Instead, we show that a proper distributional energy can induce sample-level motion and provide direct regression supervision for a one-step generator. Three-Body Scattering Modeling (TBSM) for generation turns the energy distance into a constant-size per-projectile interaction: each projectile is attracted toward one real source and repelled from one independently generated source. Conditioned on the projectile and its condition, its expectation equals the $2$-Wasserstein gradient-flow velocity of $\\frac12D_E^2(P_θ,Q)$. A batch of $B$ frozen-target events yields $O(B)$ sample-level losses, each using one reference for its condition instead of the minibatch-wide all-pairs field used by methods such as Drifting Models. Tracking this conditional expectation online can reduce field noise. Using scattering in frozen image features, TBSM trains one-step generators on ImageNet-256, achieving FID${}=2.23$ with pixel-space PixelDiT-XL and FID${}=1.63$ with latent-space DiT-XL at NFE${}=1$. We provide a design map relating diffusion-related supervision, Drift-like dynamics, and GAN-like objectives. These results establish tracked scattering as a route to high-dimensional one-step generation. Code: https://github.com/sp12138/TBSM.","authors":["Peng Sun","Zhenglin Cheng","Deyuan Liu","Jun Xie","Xinyi Shang","Tao Lin"],"published":"2026-07-20T17:38:12Z","updated":"2026-07-20T17:38:12Z","abstract_url":"https://arxiv.org/abs/2607.18198v1","html_url":"https://arxiv.org/html/2607.18198v1","pdf_url":"https://arxiv.org/pdf/2607.18198v1.pdf","matched_keywords":["diffusion"],"source_used":"html","source_text_chars":159801,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 diffusion 相关；摘要显示其主要贡献为：Modern generative models typically rely on an adversarial critic, a prescribed noise-to-data path, or an autoregressive factorization. Instead, we show that a proper distributional energy can induce sample-level motion and provide direct regression supervisio...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-21T04:12:06+00:00","status":"fallback"},"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.18153v1","title":"Robust Multimodal Dynamic Object Segmentation","abstract":"Dynamic object segmentation plays a critical role in many visual applications such as static scene reconstruction from dynamic videos. However, existing optical flow-based methods fail to ensure consistent static/dynamic segmentation along object boundaries, while 3D reconstruction-based approaches are highly sensitive to reconstruction errors. To address these limitations, we present a dynamic object segmentation framework that can generate both precise and complete dynamic masks by integrating multimodal cues including 2D point tracks, 3D reconstruction, and semantic information. We design a network combining Transformer architectures with feature clustering aggregation modules to perform static/dynamic classification of multimodal feature trajectories. It enables the model to adaptively determine which type of feature should dominate based on the characteristics of each scene, while also mitigating the impact of feature degradation. Additionally, we introduce a novel point-query-based SAM post-processing method capable of handling multiple objects within a single mask. Extensive experiments demonstrate that our approach achieves state-of-the-art performance in both dynamic object segmentation and static scene reconstruction tasks.","authors":["Zhe Xin","Hanzhi Chang","Penghui Huang","Yinian Mao","Guoquan Huang"],"published":"2026-07-20T16:51:48Z","updated":"2026-07-20T16:51:48Z","abstract_url":"https://arxiv.org/abs/2607.18153v1","html_url":"https://arxiv.org/html/2607.18153v1","pdf_url":"https://arxiv.org/pdf/2607.18153v1.pdf","matched_keywords":["video","3d","multimodal"],"source_used":"html","source_text_chars":44163,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, 3d, multimodal 相关；摘要显示其主要贡献为：Dynamic object segmentation plays a critical role in many visual applications such as static scene reconstruction from dynamic videos. However, existing optical flow-based methods fail to ensure consistent static/dynamic segmentation along object boundaries,...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-21T04:12:06+00:00","status":"fallback"},"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.18151v1","title":"Plenoptic Condensation: A Novel Approach to Generalized Scene Reconstruction","abstract":"We present a novel Generalized Scene Reconstruction (GSR) approach called Plenoptic Condensation (PCon). PCon uses a multi-stage reconstruction pipeline, initially converting images into \"soupy\" scene elements with low (representational) power, then adaptively condensing the \"soup\" into \"structured\" elements of higher power capable of efficiently representing, for example, sharp edges and smooth reflective surfaces. PCon scene models called Reality Models (Relms) enable spatially varying representational power, which is essential for high-fidelity rendering, measurement, and scene understanding. We showcase several in-the-wild PCon reconstructions captured with consumer phone cameras and drones. In one case called \"Damaged Fiat\", PCon is benchmarked against two state-of-the-art (SOTA) GSR methods: NeRO and RT-Splatting. Referring to Figure 1 below, PCon reconstructs the car hood more than twice as accurately as the SOTA methods. But more importantly, the local damage profile error for PCon is 35 um (0.035 mm), whereas the two other SOTA methods are essentially unable to measure the damage at all. Our project website is available at https://quidient.github.io/pcon-2026.html.","authors":["Brevin Tilmon","Alex DeJournett","John Leffingwell","Scott Ackerson"],"published":"2026-07-20T16:50:19Z","updated":"2026-07-20T16:50:19Z","abstract_url":"https://arxiv.org/abs/2607.18151v1","html_url":"https://arxiv.org/html/2607.18151v1","pdf_url":"https://arxiv.org/pdf/2607.18151v1.pdf","matched_keywords":["representation"],"source_used":"html","source_text_chars":53537,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 representation 相关；摘要显示其主要贡献为：We present a novel Generalized Scene Reconstruction (GSR) approach called Plenoptic Condensation (PCon). PCon uses a multi-stage reconstruction pipeline, initially converting images into \"soupy\" scene elements with low (representational) power, then adaptivel...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-21T04:12:06+00:00","status":"fallback"},"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.18150v1","title":"Lossless-INR: Lossless Volumetric Implicit Neural Representations","abstract":"Implicit neural representation (INR) methods provide continuous coordinate-to-value mappings and integrate naturally with direct volume rendering, making them attractive for representing volumetric data. However, existing INR-based approaches for volumetric data are inherently lossy, and even small reconstruction errors can propagate through rendering and downstream analysis. In this work, we explore Lossless-INR, a lossless INR framework for 3D scientific volumetric data based on bit-plane decomposition. By decomposing each voxel value into binary bit-planes, we reformulate reconstruction as per-bit binary classification, so that exact recovery reduces to predicting every bit correctly. To make this optimization tractable while keeping the representation compact, we combine an octree block-partitioning strategy that adaptively subdivides complex regions with a ternary feature-grid network whose grid entries are parameterized by a ternary set of values. Experiments on diverse volumetric datasets show that this design can achieve zero bit-error rate and bit-exact reconstruction, enabling faithful rendering and downstream analysis with a compact representation. The code is available at https://github.com/TouKaienn/Lossless-INR.","authors":["Kaiyuan Tang","Daniel Burke","Chaoli Wang"],"published":"2026-07-20T16:50:15Z","updated":"2026-07-20T16:50:15Z","abstract_url":"https://arxiv.org/abs/2607.18150v1","html_url":"https://arxiv.org/html/2607.18150v1","pdf_url":"https://arxiv.org/pdf/2607.18150v1.pdf","matched_keywords":["3d","representation"],"source_used":"html","source_text_chars":31394,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d, representation 相关；摘要显示其主要贡献为：Implicit neural representation (INR) methods provide continuous coordinate-to-value mappings and integrate naturally with direct volume rendering, making them attractive for representing volumetric data. However, existing INR-based approaches for volumetric d...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-21T04:12:06+00:00","status":"fallback"},"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.18142v1","title":"O-VAD: Industrial Video Anomaly Detection through Object-Centric Tracking and Reasoning","abstract":"Industrial Video Anomaly Detection (IVAD) aims to identify anomalous objects and events in an industrial process, which is crucial for modern manufacturing and quality control systems. Existing VLM-based anomaly reasoning methods are capable of detecting open-ended anomalies in general domains. However, their performance declines in industrial settings characterized by intricate object transformations, strict physics, and procedural constraints. To tackle the complexity of such interaction-intensive detection, we introduce a training-free agentic framework for anomaly detection free of domain-specific knowledge, emphasizing object state evolution like humans inspectors. It is designed to track spatial-temporal dynamics and underlying transformations of detected objects over time, and then reason over the object-wise temporal state trajectories to identify abnormal objects in grounded frames. Our method overcomes limitations of prior approaches that rely on retraining on normal clips or injecting domain knowledge as context for test-time inference. Extensive experiments on three IVAD datasets demonstrate that our method outperforms frontier VLMs, agentic frameworks, and traditional VAD methods fine-tuned on the respective datasets, while providing interpretable reports over anomaly processes and types.","authors":["Mei Yuan","Qi Long","Qifeng Wu","Zhenyang Li","Yizhou Zhao","Lei Wang","Yang Liu","Min Xu"],"published":"2026-07-20T16:36:00Z","updated":"2026-07-20T16:36:00Z","abstract_url":"https://arxiv.org/abs/2607.18142v1","html_url":"https://arxiv.org/html/2607.18142v1","pdf_url":"https://arxiv.org/pdf/2607.18142v1.pdf","matched_keywords":["video","agent"],"source_used":"html","source_text_chars":131977,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, agent 相关；摘要显示其主要贡献为：Industrial Video Anomaly Detection (IVAD) aims to identify anomalous objects and events in an industrial process, which is crucial for modern manufacturing and quality control systems. Existing VLM-based anomaly reasoning methods are capable of detecting open...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-21T04:12:06+00:00","status":"fallback"},"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.18116v1","title":"SGA: Plug&Play Geometric Verification for Educational Video Synthesis","abstract":"Recent work leverages Large Language Models (LLMs) to generate executable code for pedagogical animations using libraries such as Manim. However, ensuring spatial correctness and visual legibility remains challenging, as existing frameworks emphasize pedagogical content while overlooking geometric occlusions. We propose the Symbolic Geometric Agent (SGA), a plug-and-play module for code-centric animation pipelines that intercepts LLM-generated code, performs partial execution to extract symbolic scene graphs, and applies targeted refinement when spatial conflicts are detected. We further introduce the Manim Visual Quality Score (MVQS), a deterministic rendering-free proxy for spatial integrity. Experiments on the MMMC-Code benchmark across four LLM backbones and two agentic pipelines show that SGA achieves a peak MVQS of 73.11 (Code2Video + GPT-5.1), corresponding to a 16.1% relative improvement over the raw baseline, and improves MVQS in 7 of 8 backbone x pipeline configurations.","authors":["Lopez Jhon","Hinojosa Carlos","Ghanem Bernard"],"published":"2026-07-20T16:11:19Z","updated":"2026-07-20T16:11:19Z","abstract_url":"https://arxiv.org/abs/2607.18116v1","html_url":"https://arxiv.org/html/2607.18116v1","pdf_url":"https://arxiv.org/pdf/2607.18116v1.pdf","matched_keywords":["video","agent"],"source_used":"html","source_text_chars":62878,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, agent 相关；摘要显示其主要贡献为：Recent work leverages Large Language Models (LLMs) to generate executable code for pedagogical animations using libraries such as Manim. However, ensuring spatial correctness and visual legibility remains challenging, as existing frameworks emphasize pedagogi...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-21T04:12:06+00:00","status":"fallback"},"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.18109v1","title":"SpEmoC: A Balanced Speaker-Segment Multimodal Emotion Benchmark","abstract":"Understanding human emotions in spoken conversations is a key challenge in affective computing, with applications in empathetic AI, human computer interaction, and mental health monitoring. However, existing datasets vary in scale, emotion distribution, modality alignment, and data partitioning strategies, which can influence reliable cross-dataset generalization and minority-emotion modeling. We introduce SpEmoC a Speaking segment Emotion for Conversations comprising 306,544 raw clips from 3,100 English language movies and TV series. From these, 30,000 high quality, class balanced clips are curated, featuring synchronized visual, audio, and textual modalities annotated for seven emotions through a hybrid pipeline that integrates pretrained models with human validation. SpEmoC uses strict movie- and series-level splits to prevent content overlap between split sets, allowing more reliable evaluation of model generalization. The dataset also maintains a near-balanced distribution across seven emotions, including minority classes such as Fear and Disgust, which supports more balanced learning across categories. Extensive experiments, including in-domain benchmarking, cross-dataset transfer, low-data training, class-imbalance analysis, and modality transfer show that balanced data and careful splitting lead to more stable performance across emotions when models are evaluated on other datasets. These results highlight the importance of dataset design for robust and transferable multimodal emotion recognition.","authors":["Sania Bano","Shahzad Ahmad","Santosh Kumar Vipparthi","Sukalpa Chanda","Subrahmanyam Murala"],"published":"2026-07-20T16:08:24Z","updated":"2026-07-20T16:08:24Z","abstract_url":"https://arxiv.org/abs/2607.18109v1","html_url":"https://arxiv.org/html/2607.18109v1","pdf_url":"https://arxiv.org/pdf/2607.18109v1.pdf","matched_keywords":["multimodal"],"source_used":"html","source_text_chars":44840,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 multimodal 相关；摘要显示其主要贡献为：Understanding human emotions in spoken conversations is a key challenge in affective computing, with applications in empathetic AI, human computer interaction, and mental health monitoring. However, existing datasets vary in scale, emotion distribution, modal...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-21T04:12:06+00:00","status":"fallback"},"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.18080v1","title":"Sparse Evidence Can Suffice: Agentic Evidence Seeking for Multimodal Video Misinformation Detection","abstract":"Multimodal video misinformation detection is commonly formulated as a holistic video-understanding task, where the entire video and its associated content are processed and judged in a single pass. However, real-world misinformation often exhibits a sparse and compositional evidence structure: a reliable decision may depend on only a few coupled clues, while most video content contributes limited additional information. Exhaustive multimodal reasoning may therefore introduce substantial redundancy and obscure decisive evidence. This motivates decoupling evidence acquisition from verification: first identifying sparse, decision-relevant clues and then judging veracity based on the acquired evidence. Accordingly, we propose SIEVE, a framework for Sparse Interactive Evidence Verification via Extraction in multimodal video misinformation detection. An evidence-seeking agent actively explores the available multimodal evidence and constructs a compact evidence package, which is then used by a verifier to determine veracity. The agent is trained with supervised evidence-seeking trajectories and an evidence-aware reinforcement learning objective that promotes informative evidence acquisition while discouraging unnecessary or invalid interactions. Experiments on multiple video misinformation benchmarks show that SIEVE consistently outperforms the evaluated baselines and supports reliable verification using compact evidence packages. Moreover, the resulting acquisition process provides an explicit and inspectable evidence trail, improving the transparency and groundedness of multimodal misinformation detection.","authors":["Haochen Zhao","Yongxiu Xu","Xinkui Lin","Dong Xie","Jiarui Lu","Yuqi Qian","Yubin Wang","Hongbo Xu","Gaopeng Gou"],"published":"2026-07-20T15:48:31Z","updated":"2026-07-20T15:48:31Z","abstract_url":"https://arxiv.org/abs/2607.18080v1","html_url":"https://arxiv.org/html/2607.18080v1","pdf_url":"https://arxiv.org/pdf/2607.18080v1.pdf","matched_keywords":["video","agent","multimodal"],"source_used":"html","source_text_chars":71542,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, agent, multimodal 相关；摘要显示其主要贡献为：Multimodal video misinformation detection is commonly formulated as a holistic video-understanding task, where the entire video and its associated content are processed and judged in a single pass. However, real-world misinformation often exhibits a sparse an...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-21T04:12:07+00:00","status":"fallback"},"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.18078v1","title":"VGOcc: Learning Visual-Geometric Gaussians for Vision-Centric 3D Driving Occupancy Prediction","abstract":"Vision-only occupancy prediction requires recovering a semantic 3D occupancy field from calibrated surround-view images, where each view provides observations with ambiguous depth along camera rays. Existing methods have progressed from dense structured representations to sparse Gaussian primitives, improving the efficiency of 3D scene representation. However, Gaussian learning still relies primarily on image domain features, which provide limited explicit geometric information for volumetric reasoning. Our key observation is that effective Gaussian occupancy modeling requires not only sparse primitives, but also richer geometric and semantic learning cues. In this paper, we propose VGOcc, which learns visual and geometric cues from foundation models for Gaussian modeling. VGOcc incorporates these cues into primitive initialization and refinement, yielding a representation termed Visual-Geometric Gaussians tailored to semantic occupancy prediction. Specifically, we propose Visual-Geometric Gaussian Birth to form spatially balanced Gaussian centers from ray depth hypotheses, while visual semantic features initialize primitive attributes. Next, we design Pose-Aware Feature Learning to combine foundation tokens with camera embeddings and calibrated ray information. Features from neighboring views are then aggregated at projected 3D locations for each Gaussian refinement stage. Finally, Gaussian decoder refines birth Gaussians with pose-aware features and renders them into semantic occupancy. Experiments on nuScenes demonstrate that VGOcc achieves state-of-the-art performance in vision-only 3D occupancy prediction. Codes will be available at https://github.com/JHLin42in/VGOcc.","authors":["Junhong Lin","Xianda Guo","Kangli Wang","Yuqi Ye","Xiaoyu Liang","Yanlun Peng","Wei Gao"],"published":"2026-07-20T15:46:30Z","updated":"2026-07-20T15:46:30Z","abstract_url":"https://arxiv.org/abs/2607.18078v1","html_url":"https://arxiv.org/html/2607.18078v1","pdf_url":"https://arxiv.org/pdf/2607.18078v1.pdf","matched_keywords":["3d","representation"],"source_used":"html","source_text_chars":50048,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d, representation 相关；摘要显示其主要贡献为：Vision-only occupancy prediction requires recovering a semantic 3D occupancy field from calibrated surround-view images, where each view provides observations with ambiguous depth along camera rays. Existing methods have progressed from dense structured repre...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-21T04:12:07+00:00","status":"fallback"},"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.18067v1","title":"QIRF Quantum-Inspired Non-Orthogonal Function-Space Compression for 3D Gaussian Splatting","abstract":"3D Gaussian Splatting (3DGS) achieves high-quality real-time rendering by representing a scene with a large collection of anisotropic Gaussian primitives. However, complex scenes often require millions of Gaussians, resulting in substantial storage and rendering costs. Existing compression methods mainly reduce redundancy through primitive-wise pruning, attribute quantization, clustering, or neural coding, while redundancy caused by strongly overlapping and non-orthogonal Gaussian basis functions remains largely unexplored. We present QIRF, a quantum-inspired non-orthogonal function-space compression method for 3D Gaussian Splatting. QIRF models neighboring Gaussian primitives as a local non-orthogonal basis and formulates primitive reduction as a subspace-aware selection problem. Specifically, an analytic Gaussian overlap matrix and a radiance-response density matrix are constructed to characterize functional redundancy and rendering relevance. Generalized eigendecomposition is then used to identify the dominant local subspace and select representative Gaussian primitives. An RRDM-based response model and detail-aware safeguarding further preserve visually important high-frequency structures under aggressive pruning. Experiments on 13 scenes from Mip-NeRF 360, Tanks and Temples, and Deep Blending show that QIRF reduces the Gaussian count and raw PLY storage by 71.7 percent on average, corresponding to approximately 3.54 times compression, while maintaining reconstruction quality comparable to 3DGS and achieving a marginal average PSNR improvement of 0.10 dB. QIRF also improves the average rendering speed over 3DGS by 34.3 percent. These results suggest that non-orthogonal function-space redundancy is an important yet underexplored source of representational redundancy in explicit Gaussian radiance fields.","authors":["Shizeng Jiang","Hao Zhang","Xuerui Ma","Ying Hu","Tao Zhang"],"published":"2026-07-20T15:34:45Z","updated":"2026-07-20T15:34:45Z","abstract_url":"https://arxiv.org/abs/2607.18067v1","html_url":"https://arxiv.org/html/2607.18067v1","pdf_url":"https://arxiv.org/pdf/2607.18067v1.pdf","matched_keywords":["3d","representation"],"source_used":"html","source_text_chars":44702,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d, representation 相关；摘要显示其主要贡献为：3D Gaussian Splatting (3DGS) achieves high-quality real-time rendering by representing a scene with a large collection of anisotropic Gaussian primitives. However, complex scenes often require millions of Gaussians, resulting in substantial storage and render...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-21T04:12:07+00:00","status":"fallback"},"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.18062v1","title":"UniETP: Unifying Environments for Generalizable Embodied Task Planning","abstract":"This paper focuses on the problem of Embodied Task Planning, where an agent is required to execute a sequence of atomic actions within an interactive environment to complete a user-specified task. Though a variety of simulators and datasets have previously been built for this task, these efforts are largely isolated, with each using its own observation format, action type, and task domain. This fragmentation complicates comprehensive model evaluation and hinders the scalability of training data. As an effort towards generalizable embodied planning, we propose UniETP, a unified interface integrating four commonly-used simulators (AI2-THOR, VirtualHome, Habitat, BEHAVIOR). UniETP is characterized by both standardization and diversity. On one hand, it formalizes all the simulators into a consistent observation and action space, and builds an evaluation system to support complicated task goal. On the other hand, it enhances task diversity and complexity across dimensions like task logic, instance grounding, and instruction understanding, constructing a new dataset with varied levels of difficulty in an automatic manner. Extensive experiments on the proposed benchmark are conducted to evaluate the embodied planning capabilities of recent models and analyze the performance bottlenecks. Codes and data will be available at https://github.com/woyut/UniETP .","authors":["Peiran Xu","Jiaqi Zheng","Ziyou Wang","Yadong Mu"],"published":"2026-07-20T15:30:16Z","updated":"2026-07-20T15:30:16Z","abstract_url":"https://arxiv.org/abs/2607.18062v1","html_url":"https://arxiv.org/html/2607.18062v1","pdf_url":"https://arxiv.org/pdf/2607.18062v1.pdf","matched_keywords":["agent","instance"],"source_used":"html","source_text_chars":61544,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 agent, instance 相关；摘要显示其主要贡献为：This paper focuses on the problem of Embodied Task Planning, where an agent is required to execute a sequence of atomic actions within an interactive environment to complete a user-specified task. Though a variety of simulators and datasets have previously be...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-21T04:12:07+00:00","status":"fallback"},"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.18040v1","title":"When 2D Cues Fail: Improving Image Manipulation Localization with Reliable 3D Geometry","abstract":"Existing image manipulation localization (IML) methods rely heavily on 2D forensic cues, such as low-level artifacts, noise traces, and semantic inconsistencies in the manipulated image. While effective in many cases, these cues become much less discriminative when manipulated regions are well blended with their surrounding context in appearance. In such cases, a manipulated region may remain locally appearance-consistent, but still violate the geometric structure of the surrounding scene. This limitation motivates us to go beyond purely 2D evidence and introduce geometric reasoning into IML. To this end, we leverage monocular reconstruction to obtain auxiliary geometric cues, including depth and surface normals. However, a key challenge lies in the fact that reconstructed geometry on manipulated images is inherently noisy and cannot be used naively. Rather than treating depth and normals as direct evidence, we estimate their reliability and exploit them selectively for localization. Based on this principle, we design a geometry-aware framework (GFrame) that fuses reliable geometric cues with RGB features and propagates them across scales to improve fine-grained localization. Extensive experiments show that the proposed method achieves excellent performance under limited budget constraints. These results indicate that reliable 3D geometry provides complementary forensic evidence beyond traditional 2D cues for IML. Related code will be released.","authors":["Guofeng Yu","Zhiqing Guo","Dan Ma","Gaobo Yang"],"published":"2026-07-20T15:08:46Z","updated":"2026-07-20T15:08:46Z","abstract_url":"https://arxiv.org/abs/2607.18040v1","html_url":"https://arxiv.org/html/2607.18040v1","pdf_url":"https://arxiv.org/pdf/2607.18040v1.pdf","matched_keywords":["3d"],"source_used":"html","source_text_chars":48516,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d 相关；摘要显示其主要贡献为：Existing image manipulation localization (IML) methods rely heavily on 2D forensic cues, such as low-level artifacts, noise traces, and semantic inconsistencies in the manipulated image. While effective in many cases, these cues become much less discriminativ...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-21T04:12:07+00:00","status":"fallback"},"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.18033v1","title":"Benchmarking NACTI Species Recognition in Long-Tailed Regimes","abstract":"As with most ``in the wild'' collections of the natural world, the North America Camera Trap Images (NACTI) dataset exhibits long-tailed class imbalance, with the largest class covering over 50% of its 3.7M images. Building on the PyTorch Wildlife model, we systematically evaluate Long-Tail Recognition (LTR) methodologies to benchmark species recognition performance, including specialised loss functions and LTR-sensitive regularisation. Our optimised configuration achieves state-of-the-art 99.40% Top-1 accuracy on the NACTI test split, significantly outperforming standard baselines and previously reported top performances. To assess robustness under domain shifts (e.g., night-time captures, occlusion, motion-blur), we extend our evaluation across three independent reduced-bias test sets (including ENA-Detection, Caltech Camera Traps and Missouri Camera Traps). Across these out-of-distribution (OOD) evaluations, our LTR-enhanced model consistently demonstrates substantially stronger generalisation capabilities compared to standard cross-entropy approaches. However, qualitative and quantitative analyses underline that current LTR optimisations cannot fully overcome representational bottlenecks, resulting in catastrophic predictive breakdown for rare `Tail' classes under severe domain shift. For maximum reproducibility, all dataset splits, key code, and network weights are published with this paper at https://github.com/ZehuaLiuY/Species-Classification.","authors":["Zehua Liu","Tilo Burghardt"],"published":"2026-07-20T15:00:53Z","updated":"2026-07-20T15:00:53Z","abstract_url":"https://arxiv.org/abs/2607.18033v1","html_url":"https://arxiv.org/html/2607.18033v1","pdf_url":"https://arxiv.org/pdf/2607.18033v1.pdf","matched_keywords":["representation"],"source_used":"html","source_text_chars":47428,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 representation 相关；摘要显示其主要贡献为：As with most ``in the wild'' collections of the natural world, the North America Camera Trap Images (NACTI) dataset exhibits long-tailed class imbalance, with the largest class covering over 50% of its 3.7M images. Building on the PyTorch Wildlife model, we s...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-21T04:12:07+00:00","status":"fallback"},"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.18014v1","title":"SAMRI-3D: Adapting SAM2 for 3D MRI Segmentation with Global Volume Tokens","abstract":"Foundation models such as Segment Anything Model 2 (SAM2) have transformed natural-image and video segmentation, and recent work has begun adapting them to medical imaging. These adaptations, however, are largely general-purpose models that treat MRI as one modality among many; large-scale, MRI-specific modelling and benchmarking remain limited, even though MRI's low soft-tissue contrast leaves many boundaries effectively invisible on individual slices. We present SAMRI-3D, a benchmark and method for 3D MRI segmentation with SAM2. The SAMRI-3D benchmark is the largest MRI-only evaluation to date - 10,392 volumes from 34 datasets (27 public, 7 in-house) spanning 12 anatomical domains and 10+ sequences, with explicit seen/unseen splits. Freezing the image encoder and fine-tuning only the lightweight decoder and memory modules raises mean Dice from 0.58 (zero-shot SAM2) to 0.76, surpassing recent SAM-based medical models (SAMed-2 0.69, Medical-SAM2 0.49, SAM-Med3D 0.37) with strong statistical significance. To target invisible boundaries, we introduce Global Volume Tokens (GVT): persistent memory tokens trained with a Truncated Signed Distance Field (TSDF) reconstruction objective that is discarded at inference (zero added cost). This full model, SAMRI-3D, attains the best accuracy (0.78) and lowest variance across all 34 datasets and, uniquely, shows no drop on 8 held-out datasets (0.79 unseen vs. 0.78 seen); per-sequence analysis confirms the TSDF objective helps most where per-slice contrast is weakest. We will release the benchmark, code, and models in this paper.","authors":["Zhao Wang","Wei Dai","Hongfu Sun","Craig Engstrom","Shekhar S. Chandra"],"published":"2026-07-20T14:48:11Z","updated":"2026-07-20T14:48:11Z","abstract_url":"https://arxiv.org/abs/2607.18014v1","html_url":"https://arxiv.org/html/2607.18014v1","pdf_url":"https://arxiv.org/pdf/2607.18014v1.pdf","matched_keywords":["video","3d"],"source_used":"html","source_text_chars":141455,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, 3d 相关；摘要显示其主要贡献为：Foundation models such as Segment Anything Model 2 (SAM2) have transformed natural-image and video segmentation, and recent work has begun adapting them to medical imaging. These adaptations, however, are largely general-purpose models that treat MRI as one m...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-21T04:12:07+00:00","status":"fallback"},"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17999v1","title":"Do Maps Still Matter for Machines: Revisiting the Role of Choropleth Maps in Foundation Model Spatial Understanding","abstract":"Spatial understanding is crucial for foundation models (FMs), and maps have long helped humans organize and reason about geographic information. This study examines whether choropleth maps remain useful for machine spatial understanding when models can directly process structured geodata. We introduce ChoroplethMap-Bench, a controlled benchmark containing 2,400 synthetic choropleth maps, corresponding GeoJSON data, and 12,000 questions across five cognitive dimensions: Identify, Spatial Recognition, Compare, Rank, and Delineate. We evaluate 22 open-source and proprietary models under three input conditions: Data Only, Map Only, and Data + Map. The results show that maps substantially improve spatial reasoning, especially when combined with symbolic data and for tasks requiring higher-level understanding of spatial patterns. We further analyze the effects of map type, color hue, and spatial structure, as well as prompting strategies, language, geographic context, decoding settings, classification methods, and response stability. Overall, the Data + Map condition achieves the strongest performance, demonstrating that maps remain valuable external representations for foundation model spatial reasoning.","authors":["Zhiwei Wei","Yonghe Sun","Zhenjia Liu","Wenjia Xu","Chao He","Weihua Dong","Chunbo Liu","Hua Liao"],"published":"2026-07-20T14:32:10Z","updated":"2026-07-20T14:32:10Z","abstract_url":"https://arxiv.org/abs/2607.17999v1","html_url":"https://arxiv.org/html/2607.17999v1","pdf_url":"https://arxiv.org/pdf/2607.17999v1.pdf","matched_keywords":["representation"],"source_used":"html","source_text_chars":100970,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 representation 相关；摘要显示其主要贡献为：Spatial understanding is crucial for foundation models (FMs), and maps have long helped humans organize and reason about geographic information. This study examines whether choropleth maps remain useful for machine spatial understanding when models can direct...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-21T04:12:07+00:00","status":"fallback"},"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17994v1","title":"HAS: Highlight-guided Attention Steering for Multimodal LLM Video Summarization","abstract":"Video understanding has become more and more important with the growth of Artificial Intelligence (AI) for video generation. Recently, Multimodal Large Language Model(M-LLM) has shown its capability in video understanding. Video summarization, a specific domain of video understanding, has proven its importance for efficient navigation and retrieval. Both video understanding and video summarization require a good selection of key frames in a video. Current video summarization methods heavily focus on the selected key frames and correlated segment captions. However, existing approaches overlook the perspective of treating the importance of the frames globally. We argue that using discrete selected frames for summarization will not only reduce the understanding coherence, but also lost important information in the video, as well as wasting the original capacity of the MLLMs. In this paper, we propose HAS, a Highlight-guided Attention Steering method for video summarization. We consider a challenging but practical setting where the video given to MLLMs for summarize should be continuous but with highlight guidance. HAS mainly consists of two parts: The first part is to find a continuous frame-level highlight distribution for the video globally. The second part is to apply the highlight distribution as an attention steering vector for the MLLM, targeting a better understanding of the video, and thus during the model inference time, putting more attention on the highlighted frames, while avoiding lost entire information on less highlighted frames through putting less attention instead of forgetting them. We evaluated HAS on a variety of benchmarks, and it has shown convincing performance in video summarization.","authors":["Rui Chu","Yingjie Lao"],"published":"2026-07-20T14:27:06Z","updated":"2026-07-20T14:27:06Z","abstract_url":"https://arxiv.org/abs/2607.17994v1","html_url":"https://arxiv.org/html/2607.17994v1","pdf_url":"https://arxiv.org/pdf/2607.17994v1.pdf","matched_keywords":["video","retrieval","multimodal"],"source_used":"html","source_text_chars":43458,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, retrieval, multimodal 相关；摘要显示其主要贡献为：Video understanding has become more and more important with the growth of Artificial Intelligence (AI) for video generation. Recently, Multimodal Large Language Model(M-LLM) has shown its capability in video understanding. Video summarization, a specific doma...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-21T04:12:07+00:00","status":"fallback"},"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17985v1","title":"Keyframe-Anchored Identity Preservation for Sequential-Action Video Generation","abstract":"Identity-preserving text-to-video generation aims to synthesize a video that accurately follows a textual description while maintaining the recognizability of a user-specified subject throughout. The IPVG26 challenge extends this framework from a single holistic prompt to a temporally structured specification. The model additionally receives a sequence of timestamped action captions and must render the subject performing these actions in the specified order. This temporal structure presents a challenge not encountered in previous identity-preserving generation tasks, as the subject must continuously perform a scripted sequence of distinct actions while maintaining a consistent identity. However, end-to-end video generators are prone to appearance drift as motion accumulates and the depicted actions change. We address this challenge with a training-free, three-stage pipeline framework. An action-aware prompt polishment stage first rewrites the inputs into image-generation prompts that specify the terminal state of each action. An identity-preserving generation stage then produces the keyframe sequence by conditioning each frame jointly on the reference identity and its predecessor, thereby decoupling time-invariant appearance from time-varying pose. Finally, an identity-aware inference enhancement stage synthesizes the intermediate segments using multi-reference guidance and identity-driven noise searching, both of which reinforce identity fidelity during sampling. Our method ranked third on the official Track 2 leaderboard, demonstrating competitive performance and strong generality.","authors":["Zhenjie Liu","Binyan Chen","Hao Chen","Tong Pan","Shangfei Wang"],"published":"2026-07-20T14:16:49Z","updated":"2026-07-20T14:16:49Z","abstract_url":"https://arxiv.org/abs/2607.17985v1","html_url":"https://arxiv.org/html/2607.17985v1","pdf_url":"https://arxiv.org/pdf/2607.17985v1.pdf","matched_keywords":["video"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17967v1","title":"Fine-Detail Monocular Geometry Estimation with Self-Guided Sparse Volumetric Refinement","abstract":"Monocular geometry estimation has recently achieved impressive performance across diverse scenes. However, state-of-the-art models still face notable distortion in local 3D structure, especially in fine details, like thin structures and small objects. We attribute this limitation to an architectural mismatch: most current models decode 3D geometry within a 2D parameterization, where feature interactions are governed by image-plane proximity rather than true 3D spatial relationships. This inadvertently mixes features from geometrically distant surfaces, resulting in over-smoothed geometry particularly around thin or elongated structure. In this paper, we propose a fine-detail monocular geometry estimation with Self-Guided Sparse 3D Refinement (SSR) that lifts monocular geometry modeling from 2D image space to 3D space for high-fidelity metric-scale point maps. Our model lifts the coarse point map from a foundation base model onto a sparse voxel shell and refines it via SSR. The SSR employs sparse convolutions that aggregate features based on 3D spatial locality, avoiding feature mixing across depth discontinuities. Extensive experiments on diverse datasets demonstrate that our method significantly outperforms existing approaches in recovering fine detailed 3D geometry across both quantitative metrics and qualitative visualizations.","authors":["Lingyu Kong","Ruicheng Li","Ruicheng Wang","Sicheng Xu","Chengtang Yao","Jianfeng Xiang","Jiaolong Yang"],"published":"2026-07-20T14:07:32Z","updated":"2026-07-20T14:07:32Z","abstract_url":"https://arxiv.org/abs/2607.17967v1","html_url":"https://arxiv.org/html/2607.17967v1","pdf_url":"https://arxiv.org/pdf/2607.17967v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17965v1","title":"Exploration Matters for Escaping the Blur Trap in 3D Gaussian Splatting","abstract":"3D Gaussian Splatting (3DGS) employs Gaussian primitives for explicit scene representation, facilitating real-time, high-fidelity reconstruction and novel view synthesis of complex scenes. However, the explicit modeling inherent in 3DGS introduces a gradient bias during optimization, rendering its non-convex optimization process highly susceptible to convergence toward local suboptimal solutions. This constitutes a fundamental limitation in 3DGS optimization, which we term the Blur Trap. To address this limitation, we integrate simple explicit exploration into the 3DGS optimization framework. First, through rigorous mathematical analysis of the 3DGS optimization formulation, we identify the underlying optimization bias responsible for the Blur Trap and categorize it into two distinct subtypes: the Far-Side Blur Trap and the Near-Side Blur Trap. Subsequently, we propose two highly straightforward exploration strategies (Random Seeding and Random Splitting) to mitigate the far-side and near-side blur traps, respectively. Experimental validation demonstrates that the incorporation of these exploration operators effectively and complementarily overcome the Blur Trap, achieving high-quality rendering performance across multiple datasets. Project page: https://chengbo-wang.github.io/ExploreGS/","authors":["Chengbo Wang","Guozheng Ma","Jinhong Wu","Tie Ji","Yizhen Lao"],"published":"2026-07-20T14:05:54Z","updated":"2026-07-20T14:05:54Z","abstract_url":"https://arxiv.org/abs/2607.17965v1","html_url":"https://arxiv.org/html/2607.17965v1","pdf_url":"https://arxiv.org/pdf/2607.17965v1.pdf","matched_keywords":["3d","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17938v1","title":"MuViSeg: Multi-View Segment Correspondences from Dense Geometry Priors","abstract":"Classical image correspondence is solved at the level of sparse keypoints or dense pixels, but the systems that consume these matches - object-level mapping, topological navigation, scene-graph maintenance - reason about whole objects. Recent work narrows this gap by matchng directly at the level of instance segments: a class-agnostic segmenter partitions each image, and per-segment descriptors are obtained by pooling features from large 3D foundation models over the masks. We build on this segment-level matching paradigm and propose three learned matching heads: a LightGlue-style attention head with DoubleSoftmax scoring on frozen MASt3R descriptors; a DPT-style multi-scale fusion module that exposes layered spatial detail from the VGGT foundation model before pooling; and - as our main contribution - a multi-view extension that performs joint self-attention over segments drawn from several views at once, recovering transitive correspondences that strictly pairwise matchers cannot reach. Under a stratified zero-shot protocol on Replica and Virtual KITTI 2 with controlled viewpoint baselines from 0 deg to 180 deg, the LightGlue-style head improves over a parameter-free Sinkhorn matcher on the same MASt3R backbone by +4.85 AUPRC on Replica and +25.9 AUPRC on Virtual KITTI 2. Dropped into the RoboHop topological navigation pipeline on the Habitat-Matterport 3D (HM3D) Instance Image Navigation benchmark without retraining, our multi-view variant raises success rate from 50% to 70%, and our LightGlue-style head raises SPL from 45.7 to 59.1.","authors":["Denis Fatykhoph","Timur Akhtyamov","Konstantin Pakulev","German Devchich","Gonzalo Ferrer"],"published":"2026-07-20T13:35:48Z","updated":"2026-07-20T13:35:48Z","abstract_url":"https://arxiv.org/abs/2607.17938v1","html_url":"https://arxiv.org/html/2607.17938v1","pdf_url":"https://arxiv.org/pdf/2607.17938v1.pdf","matched_keywords":["3d","instance"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17916v1","title":"Packet-Loss Robust 3D Gaussian Compression via Atomic Packaging and GNN-based Error Concealment","abstract":"3D Gaussian Splatting (3DGS) and recent compression schemes such as HAC++ enable high-fidelity real-time neural rendering, but their bitstreams are fragile under packet loss during network streaming. Existing compression methods often separate correlated anchor attributes into independent streams, so losing one packet can create attribute-inconsistent broken anchors and severe rendering artifacts. We propose a packet-loss robust 3DGS transmission and error concealment framework. On the encoder side, anchor-level atomic packaging jointly encapsulates all attributes of each anchor, converting corrupted-attribute failures into clean missing-anchor erasures. Stratified random grouping further disperses packet losses across the spatial domain to avoid large contiguous voids. On the decoder side, we formulate recovery as prior-aware attribute inpainting. A Context-Aware Residual Interpolation (CARI) branch uses hash-grid prior predictions and neighboring residuals to build a robust baseline, while a lightweight two-layer graph neural network with cross-attention over hash-grid priors refines high-frequency attribute residuals. Attribute-wise confidence control falls back to interpolation when learned predictions are unreliable. Experiments under 20 percent random packet loss on BungeeNeRF, Mip-NeRF 360, and Tanks and Temples show that the proposed method substantially improves over no-concealment transmission and limits average PSNR degradation to about 3 dB relative to the lossless HAC++ reference.","authors":["Yuxuan Tao","Xuerui Ma","Hao Zhang","Chunhua Peng"],"published":"2026-07-20T13:13:38Z","updated":"2026-07-20T13:13:38Z","abstract_url":"https://arxiv.org/abs/2607.17916v1","html_url":"https://arxiv.org/html/2607.17916v1","pdf_url":"https://arxiv.org/pdf/2607.17916v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17896v1","title":"Locality-Aware Density Control for Efficient Gaussian-based Image Representation","abstract":"2D Gaussian Splatting is an attractive direction for image representation due to its explicit formulation, fast rasterization, and favorable decoding efficiency. The representation quality of this paradigm depends on the proper allocation of Gaussian capacity to the demanding regions. However, existing methods fail to allocate Gaussian capacity efficiently during optimization: under-reconstructed content is often refined in a fragmented pixel-wise manner, while neighboring optimized Gaussians with similar attributes are redundantly retained. This inefficiency motivates the need for a density control framework that jointly addresses insufficient allocation in under-reconstructed regions and redundant allocation in over-reconstructed regions. Our key insight is that this framework should exploit two complementary forms of locality: the local continuity of reconstruction errors in image space for improved Gaussian allocation, and the local similarity of neighboring Gaussians in Gaussian space for redundant elimination. Based on this insight, we propose Locality-Aware Density Control (LocoADC), a plug-and-play framework that improves Gaussian capacity utilization through Region-wise Gaussian Densification (RGD) and Similarity-Driven Gaussian Merging (SDGM) strategies, together with a local color consistency constraint for more reliable merging. Extensive experiments on diverse datasets show that LocoADC consistently improves multiple baselines by enabling more effective local Gaussian allocation, including a 2.93 dB PSNR gain over GI on the CLIC dataset under the same 30k Gaussian budget. Code is available at: \\textit{https://github.com/ChenJiaCong-1005/LocoADC}.","authors":["Jiacong Chen","Qingyu Mao","Xiandong Meng","Shuai Liu","Chao Li","Fanyang Meng","Youneng Bao","Yongsheng Liang"],"published":"2026-07-20T12:44:12Z","updated":"2026-07-20T12:44:12Z","abstract_url":"https://arxiv.org/abs/2607.17896v1","html_url":"https://arxiv.org/html/2607.17896v1","pdf_url":"https://arxiv.org/pdf/2607.17896v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17849v1","title":"AlphaOracle: Oracle bone script decipherment via human-workflow-inspired deep learning","abstract":"Approximately 3,000 of the 4,500 oracle bone script (OBS) characters remain undeciphered due to fragmentary inscriptions and sparse evidence. Current AI approaches fail to replicate expert workflows that integrate form analysis, contextual semantics, and philological reasoning. We introduce AlphaOracle, a human-workflow-inspired framework that systematizes OBS decipherment using the largest digitized corpus to date. Its multi-stage pipeline comprises: (i) rubbing parsing; (ii) radical-based morphological analysis with diachronic modeling; (iii) contextual retrieval with semantic alignment; and (iv) philological validation against classical sources. Each stage generates explicit, confidence-weighted evidence chains, culminating in interpretable reports for scholarly verification. Across multiple test characters, AlphaOracle's readings strongly agreed with expert interpretations. In a study of 86 domain specialists, it reduced analysis time by 64% and 79% of participants rated it highly useful. Notably, AlphaOracle resolves the character \"Lao\" as a toponymic or clan designation, offering concrete revisions to Shang administrative and social interpretations. These results suggest that computational methods aligned with philological practice can facilitate OBS research and provide a conceptual reference for studies of other undeciphered scripts.","authors":["Yuliang Liu","Haisu Guan","Pengjie Wang","Xinyu Wang","Jinpeng Wan","Kaile Zhang","Handong Zheng","Xingchen Liu","Zhebin Kuang","Huanxin Yang","Bang Li","Yongge Liu","Lianwen Jin","Xiang Bai"],"published":"2026-07-20T11:46:00Z","updated":"2026-07-20T11:46:00Z","abstract_url":"https://arxiv.org/abs/2607.17849v1","html_url":"https://arxiv.org/html/2607.17849v1","pdf_url":"https://arxiv.org/pdf/2607.17849v1.pdf","matched_keywords":["retrieval"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17842v1","title":"CaT-GS: Efficient 3DGS Rendering for Large Scale Scenes via Inter-frame Caching and Tile Scheduling","abstract":"Recent breakthroughs in 3D Gaussian Splatting (3DGS) have advanced neural rendering with high fidelity and speed. However, its performance degrades significantly in large-scale scenes due to the computational burden of tile-based rasterization. Existing optimization efforts either require costly scene re-training or focus on narrow aspects of the pipeline, overlooking critical inefficiencies in real-world deployments. Through a comprehensive analysis, we identify three primary sources of redundancy and low GPU utilization: redundant inter-frame pre-processing, viewpoint-based occlusion redundancy, and severe tile-level load imbalance. To address these issues, we propose CaT-GS, a novel and efficient 3DGS rendering pipeline. CaT-GS introduces a speculative multi-frame preprocessing method to eliminate redundant computations across consecutive frames, and an inter-frame caching mechanism to eliminate viewpoint redundant rendering stages. Furthermore, it refactors rasterization tasks with a dedicated kernel to mitigate tile load imbalance, significantly boosting GPU utilization. Extensive experiments demonstrate that CaT-GS achieves a speedup of up to 10 times over the original 3DGS and up to 70% over previous state-of-the-art methods, establishing a new benchmark for high-fidelity, real-time rendering of large-scale scenes.","authors":["Tingjia Zhang","Bo Chen","Shengzhong Liu","Fan Wu","Guihai Chen"],"published":"2026-07-20T11:33:51Z","updated":"2026-07-20T11:33:51Z","abstract_url":"https://arxiv.org/abs/2607.17842v1","html_url":"https://arxiv.org/html/2607.17842v1","pdf_url":"https://arxiv.org/pdf/2607.17842v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17833v1","title":"Consistent Feature Transport for Image Relighting","abstract":"Image relighting modifies illumination while preserving non-lighting content such as identity and geometry. Existing diffusion-based methods often suffer from unstable illumination changes or inconsistent content preservation under complex lighting, as they lack an explicit mechanism to learn feature transformations between images. We reformulate relighting as an illumination feature transport problem and introduce Consistent Feature Transport (CFT), a training principle that explicitly enforces illumination-consistent transport between source and target image distributions. Built upon rectified flow, CFT jointly models noise-to-image generation and illumination-consistent source-to-target transport through trajectory-level supervision. This dual-transport formulation encourages isolation of illumination-specific variations while preserving content-aligned features. To support complex lighting scenarios, we construct a large-scale portrait relighting dataset with diverse relighting effects. Experiments show consistent improvements over existing state-of-the-art relighting approaches and demonstrate that CFT can generalize to other editing tasks, including style transfer. Code is available at https://github.com/Dixin-Lab/CFT.","authors":["Bohan Zhang","Huanwei Liang","Yuhan He","Hongteng Xu","Quxiao Chao","Luoqi Liu","Dixin Luo","Ting Liu"],"published":"2026-07-20T11:25:36Z","updated":"2026-07-20T11:25:36Z","abstract_url":"https://arxiv.org/abs/2607.17833v1","html_url":"https://arxiv.org/html/2607.17833v1","pdf_url":"https://arxiv.org/pdf/2607.17833v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17810v1","title":"Vis2Reg: Visibility-Aware Landmark-Free Geometric 3D--2D Registration for Liver Laparoscopy","abstract":"Accurate 3D--2D liver registration, which aligns preoperative 3D models to partial, view-dependent intraoperative surface observations, is critical for AR-guided laparoscopic surgery but remains challenging due to severe occlusion, limited visibility, and the lack of 3D ground-truth supervision. Existing landmark-free approaches perform partial-to-complete geometric alignment, yet robust self-supervision under extreme partial visibility remains difficult. We propose Vis2Reg, a visibility-aware registration framework that explicitly constrains deformation using mask-consistent visible regions. We introduce a visibility-aware self-supervision that derives a visible-domain 3D supervision signal from intraoperative masks, enabled by differentiable point rasterization and mask-guided back-projection. This formulation improves robustness under severe occlusion while maintaining fully self-supervised learning. Vis2Reg combines a robust geometric rigid initialization module with an implicit neural deformation field for stable alignment. Vis2Reg achieves a Dice score of 92.6\\% and a Chamfer Distance of 1.43 mm on real intraoperative datasets, with 111 ms per-frame inference time, demonstrating both accuracy and practical efficiency.","authors":["Jiaming Feng","Xukun Zhang","Shahid Farid","Sharib Ali"],"published":"2026-07-20T10:56:52Z","updated":"2026-07-20T10:56:52Z","abstract_url":"https://arxiv.org/abs/2607.17810v1","html_url":"https://arxiv.org/html/2607.17810v1","pdf_url":"https://arxiv.org/pdf/2607.17810v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17803v1","title":"FF-ProCams: Feed-Forward Gaussian Splatting for Projector-Camera System","abstract":"Projector-camera (ProCams) systems achieve active scene perception and controllable appearance manipulation via structured illumination, serving as a core infrastructure for spatial augmented reality, projection mapping, and surface reflectance acquisition. Existing inverse-rendering methods for ProCams deliver high-fidelity results but rely on time-consuming per-scene optimization, while mainstream feed-forward 3D reconstruction models produce baked appearance that cannot adapt to spatially varying projector illumination. To resolve this accuracy-efficiency trade-off, we propose FF-ProCams, a Feed-Forward 3D Gaussian inverse-rendering framework for ProCams. A hybrid Mamba2-Transformer encoder aggregates cross-view geometric and photometric cues from sparse multi-view observations, and lightweight heads predict a relightable Gaussian representation in a single forward pass. We further design a projector-aware differentiable renderer to synthesize camera observations under arbitrary active illumination and ProCams poses. To enable feed-forward training, we construct a large-scale synthetic ProCams dataset covering diverse object geometries and surface materials. Experiments show FF-ProCams achieves high-fidelity projector-aware rendering, generalizes to unseen patterns, and supports novel projector-camera poses. Using only 8 input views, it outperforms optimization-based baselines with 297 views while reducing test-time reconstruction to 0.13 seconds (a three-to-five-order-of-magnitude speedup). The code and data are available at https://github.com/CPREgroup/FF-ProCams/.","authors":["Ziyao Wang","Yuqi Li","Wenxing Zheng","Jiaying Chen","Chong Wang"],"published":"2026-07-20T10:42:16Z","updated":"2026-07-20T10:42:16Z","abstract_url":"https://arxiv.org/abs/2607.17803v1","html_url":"https://arxiv.org/html/2607.17803v1","pdf_url":"https://arxiv.org/pdf/2607.17803v1.pdf","matched_keywords":["3d","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17790v1","title":"ReViV: Reconstructing the Viewer and the View in 4D from Monocular Egocentric Video","abstract":"Egocentric devices, such as wearable front-facing cameras, provide a unique perspective for capturing the continuous interaction between a human viewer and the surrounding environment. A holistic and efficient multimodal model capable of reconstructing this 4D representation is therefore highly desirable. However, existing approaches often rely on auxiliary inputs such as pre-computed camera trajectories, treat scene perception and human ego-motion modeling as separate problems despite their strong interdependency, and suffer from slow inference time. To address these limitations, we present ReViV, the first unified framework for holistic egocentric 4D reconstruction that extracts both viewer and view dynamics from a single monocular RGB video. We formulate the task as learning the full joint probability distribution over multimodal signals, including RGB video, camera trajectory, gaze direction, full-body motion, hand motion, and depth. Powered by a Masked Generative Egocentric Transformer, ReViV operates within a single feed-forward architecture to simultaneously reconstruct the temporally consistent 4D reconstruction across the viewer and the view with fast inference speed. Extensive experiments on diverse benchmarks, including HoloAssist, HOT3D, ARCTIC, Aria Digital Twin, and TACO, demonstrate that ReViV achieves state-of-the-art accuracy and efficiency across holistic ego-body, hand, and gaze reconstruction, camera tracking, while maintaining highly competitive egocentric depth estimation without relying on heavy task-specific priors. Code and models are fully open-sourced: https://reviv4d.github.io/.","authors":["Xiaozhong Lyu","Gen Li","Zhiyin Qian","Xucong Zhang","Marc Pollefeys","Siyu Tang"],"published":"2026-07-20T10:22:53Z","updated":"2026-07-20T10:22:53Z","abstract_url":"https://arxiv.org/abs/2607.17790v1","html_url":"https://arxiv.org/html/2607.17790v1","pdf_url":"https://arxiv.org/pdf/2607.17790v1.pdf","matched_keywords":["video","3d","representation","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17782v1","title":"BrainNext: A General-Purpose Self-Supervised Foundation Model for Brain MRI Analysis","abstract":"Foundation models pretrained using self-supervised learning have transformed computer vision by learning transferable representations from large-scale unlabeled data. However, existing foundation models for neuroimaging remain limited by task-specific training, slice-based learning strategies, or relatively small pretraining datasets, restricting their generalizability across diverse brain MRI applications. In this work, we present BrainNext, a general-purpose self-supervised foundation model for volumetric brain MRI analysis. BrainNext combines masked autoencoder (MAE) pretraining with a native three-dimensional Bi-Directional xLSTM-UNet architecture to learn rich anatomical representations from 60,551 unlabeled brain MRI examinations spanning multiple MRI modalities. The pretrained model is subsequently adapted to downstream tasks through lightweight task-specific fine-tuning. We evaluate BrainNext on the Foundation Models for Medical Imaging (FOMO) 2025 Method Track, encompassing classification, segmentation, and brain-age estimation, where it achieved second place overall and ranked first in the meningioma segmentation task on the official FOMO 2025 challenge leaderboard, demonstrating strong transferability across heterogeneous neuroimaging tasks. These results highlight the potential of large-scale self-supervised pretraining to learn robust and transferable volumetric representations, establishing BrainNext as a scalable foundation model for diverse brain MRI applications.","authors":["Moona Mazher","Abdul Qayyum","Steven A. Niederer","Daniel C. Alexander"],"published":"2026-07-20T10:15:02Z","updated":"2026-07-20T10:15:02Z","abstract_url":"https://arxiv.org/abs/2607.17782v1","html_url":"https://arxiv.org/html/2607.17782v1","pdf_url":"https://arxiv.org/pdf/2607.17782v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17778v1","title":"CDIS: Cross-Dimensional Class-Agnostic 3D Instance Segmentation via 2D Mask Tracking and 3D-2D Projection Merging","abstract":"Class-agnostic 3D instance segmentation is critical for robotic systems operating in unknown environments, enabling perception of previously unseen objects for reliable manipulation and navigation. Existing approaches typically project per-frame 2D instance masks into 3D and merge them, which often breaks object identities across time and yields fragmented 3D instances. We introduce Cross-Dimensional Class-Agnostic 3D Instance Segmentation (CDIS), a zero-shot framework that explicitly tracks 2D instance masks across frames and associates them with 3D superpoints, creating a feedback loop between 2D and 3D. This cross-dimensional reasoning links temporally stable 2D tracks with spatially coherent 3D regions, producing globally consistent 3D instance labels without any 3D-specific training. Experiments on benchmark datasets demonstrate that CDIS achieves higher accuracy and consistency than state-of-the-art zero-shot methods, while remaining efficient and scalable to diverse real-world environments.","authors":["Juno Kim","Hye-Jung Yoon","Yesol Park","Byoung-Tak Zhang"],"published":"2026-07-20T10:09:12Z","updated":"2026-07-20T10:09:12Z","abstract_url":"https://arxiv.org/abs/2607.17778v1","html_url":"https://arxiv.org/html/2607.17778v1","pdf_url":"https://arxiv.org/pdf/2607.17778v1.pdf","matched_keywords":["3d","instance"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17770v1","title":"Measuring Monosemanticity in Sparse Autoencoders via Latent Activation Coherence","abstract":"Within Explainable Artificial Intelligence, mechanistic interpretability uses Sparse Autoencoders (SAEs) to extract more interpretable features from neural representations. However, assessing their monosemanticity, and thus explanation quality, remains challenging. Existing metrics require external concept labels or depend on pretrained embedding models, making them sensitive to encoder's geometry. We introduce the Tversky Monosemanticity Score (TMS), a label-free metric that operationalizes monosemanticity as activation-set coherence of binarized SAE latents, and does not require external embedding encoders. We evaluate TMS on SAEs trained on features from pretrained vision and vision-language models (DINOv3, CLIP, BLIP2), two common SAE regimes (TopK, BatchTopK), multiple sparsity levels, and expansion factors. Our results show that TMS is less affected by encoder anisotropy than its embedding-based alternative, while remaining aligned with established monosemanticity indicators. TMS also reveals distinct SAE training dynamics across base models. Moreover, under encoder anisotropy, TMS provides a stronger indication of probe-based concept deletion effectiveness, while being competitive otherwise.","authors":["Katarzyna Filus","Sebastian Pokuciński"],"published":"2026-07-20T10:03:37Z","updated":"2026-07-20T10:03:37Z","abstract_url":"https://arxiv.org/abs/2607.17770v1","html_url":"https://arxiv.org/html/2607.17770v1","pdf_url":"https://arxiv.org/pdf/2607.17770v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17769v1","title":"From Sign Language Generation to Humanoid Execution: Vision-Language Guided Retargeting with Collision Mitigation","abstract":"Recent sign language generation (SLG) systems increasingly output dense 3D body representations, which better preserve full-body kinematics and geometry for downstream embodiment on humanoid robots. However, these generated motions frequently exhibit self-intersections such as hand-hand and hand-torso penetration. While such artifacts may be tolerated in offline rendering, they become critical in humanoid execution as they lead to infeasible inverse-kinematics (IK) solutions, collisions, and unstable retargeted trajectories. We present a system-level framework that bridges SLG outputs to humanoid joint-space execution via two components. First, we introduce a volumetric SMPL-X collision-mitigation module that projects generated signing motions toward physically plausible configurations while minimally deviating from the original trajectory. Second, we propose a vision-language-guided retargeting algorithm built on an IK backbone: a VLM serves as a visual critic over rendered humanoid motion, identifies embodiment-specific failure modes, and triggers targeted task-space corrections. Our results highlight collision handling and perception-guided refinement as key missing components for reliable humanoid signing.","authors":["Nabeela Khan","Bowen Wu","Runwu Shi","Benjamin Yen","Takeshi Ashizawa","Carlos Toshinori Ishi","Takashi Minato","Kazuhiro Nakadai"],"published":"2026-07-20T10:02:18Z","updated":"2026-07-20T10:02:18Z","abstract_url":"https://arxiv.org/abs/2607.17769v1","html_url":"https://arxiv.org/html/2607.17769v1","pdf_url":"https://arxiv.org/pdf/2607.17769v1.pdf","matched_keywords":["3d","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17768v1","title":"To Blend In, First Decouple: Rethinking Camouflage Image Generation via Context-Decoupled Representations","abstract":"Camouflage image generation (CIG) focuses on generating visually concealed objects that seamlessly blend into their backgrounds. Existing methods typically follow either background-guided paradigms that adapt object appearance via style transfer, or foreground-guided strategies that outpaint surrounding regions conditioned on object features. However, they still suffer from appearance discrepancy and background artifacts. We attribute these limitations to cross-context representation leakage, where object and background cues are entangled in a coupled conditional space, resulting in ambiguous control and degraded camouflage fidelity. To tackle this, we propose a new context-decoupled generative paradigm, termed CamoDreamer, which aims to isolate contextual conditional guidance and explicitly decouple latent camouflage features into coordinated object and background control streams. First, a Contrast-aware Contextual Bridge is designed to model cross-context discrepancies and construct contrast-aware dual conditional guidance. Second, Context-Decoupled Assimilation Streams are employed to separate generative interactions conditioned on the dual guidance, while facilitating background rendering with target-aware cues in the latent space. Finally, a Frequency-Adaptive Contextual Blend module integrates complementary high-frequency textures and low-frequency structures from decoupled features to improve holistic coherence. Extensive experiments demonstrate that CamoDreamer consistently outperforms existing methods with a substantial margin, while maintaining a relatively lightweight design.","authors":["Wenzhuang Wang","Yifan Zhao","Mingcan Ma","Yunlong Che","Haoran Chen","Ming Liu","Jia Li"],"published":"2026-07-20T10:01:36Z","updated":"2026-07-20T10:01:36Z","abstract_url":"https://arxiv.org/abs/2607.17768v1","html_url":"https://arxiv.org/html/2607.17768v1","pdf_url":"https://arxiv.org/pdf/2607.17768v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17754v1","title":"DA-Fusion: Deformable Attention-Based RGB-D Fusion Transformer for Unseen Object Instance Segmentation","abstract":"In logistics automation, precise segmentation of unseen objects is crucial for efficient robotic manipulation in cluttered environments. Tasks such as bin-picking and shelf-picking require robust perception to handle occlusions, varying object shapes, and complex spatial arrangements. Traditional RGB-based methods tend to over-segment objects due to their reliance on texture, while depth-based methods often under-segment by focusing primarily on geometric features. To address these limitations, we propose DA-Fusion, a deformable attention-based RGB-D fusion Transformer designed for unseen object instance segmentation. DA-Fusion effectively combines the strengths of both RGB and depth data, enhancing segmentation accuracy in cluttered and multi-layered object environments. We also introduce the Object Clutter Bin Dataset (OCBD), a benchmark dataset specifically tailored for evaluating bin-picking scenarios in top-down views. Extensive evaluations demonstrate that DA-Fusion outperforms state-of-the-art methods across diverse environments, making it particularly suited for real-world logistics tasks.","authors":["Yesol Park","Hye-Jung Yoon","Juno Kim","Byoung-Tak Zhang"],"published":"2026-07-20T09:47:16Z","updated":"2026-07-20T09:47:16Z","abstract_url":"https://arxiv.org/abs/2607.17754v1","html_url":"https://arxiv.org/html/2607.17754v1","pdf_url":"https://arxiv.org/pdf/2607.17754v1.pdf","matched_keywords":["instance"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17718v1","title":"PC-Seg: Progressive Cross-View Consistency for 3D OCT Segmentation from Sparse 2D Annotations","abstract":"Volumetric segmentation of optical coherence tomography (OCT) images is essential for diagnosing ocular diseases but requires labor-intensive voxel-wise annotations. While semi-supervised learning (SSL) can reduce annotation costs, most existing methods process data slice by slice and fail to exploit the inherent 3D spatial context. We propose PC-Seg, a progressive cross-view consistency framework that learns high-accuracy 3D segmentation models from sparse 2D annotations. Unlike conventional multi-view approaches, PC-Seg uses a single 2D model to learn cross-view consistency from standard B-scans and orthogonal slices, thereby generating reliable volumetric pseudo-labels. These pseudo-labels are then distilled into a 3D model, followed by a co-training stage in which the 2D and 3D models mutually refine each other through ensemble pseudo-labeling. Experiments on the MSHC and Duke DME datasets demonstrate that PC-Seg achieves accuracy comparable to fully supervised learning while using labels for only about 0.7% of the training data, outperforming state-of-the-art semi-supervised and retinal layer segmentation methods. Our code is publicly available at https://github.com/gsisaoki/pc-seg-official.","authors":["Tsubasa Konno","Takahiro Ninomiya","Yukun Zhou","Koichi Ito","Siegfried K. Wagner","Yiqun Lin","Pearse A. Keane","Toru Nakazawa","Takafumi Aoki"],"published":"2026-07-20T09:12:04Z","updated":"2026-07-20T09:12:04Z","abstract_url":"https://arxiv.org/abs/2607.17718v1","html_url":"https://arxiv.org/html/2607.17718v1","pdf_url":"https://arxiv.org/pdf/2607.17718v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17675v1","title":"ShotPlan: Cinematic Video Generation with Learnable Planning Token","abstract":"Current video generation models achieve impressive results in single-shot generation, yet remain limited in cinematic video generation, where coherent narratives and effective multi-shot composition require explicit shot planning. To address this challenge, we propose ShotPlan, a framework for explicit multi-shot cinematic video generation built upon a video diffusion foundation model. Our method introduces learnable planning tokens that capture shot-level transition cues and can be seamlessly integrated with the original video generation tokens to control transition timestamps. Unlike standard video generation tokens, the proposed planning tokens are equipped with Fractional Temporal Rotary Position Embedding (FRoPE), enabling shot transitions to be modeled at the frame level. Experiments demonstrate that ShotPlan significantly outperforms existing cinematic video generation methods, offering more flexible shot management and stronger inter-shot consistency.","authors":["Su Guo","Guangce Liu","Haosen Yang","Jiepeng Wang","Cong Liu","Junqi Liu","Haibin Huang","Hongxun Yao","Chi Zhang","Xuelong Li"],"published":"2026-07-20T08:27:18Z","updated":"2026-07-20T08:27:18Z","abstract_url":"https://arxiv.org/abs/2607.17675v1","html_url":"https://arxiv.org/html/2607.17675v1","pdf_url":"https://arxiv.org/pdf/2607.17675v1.pdf","matched_keywords":["video","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17669v1","title":"Attention from Above: A Multimodal Model for Drone-Based Object Localization","abstract":"Drone-based object detection technology has advanced rapidly, becoming increasingly sophisticated and efficient. Recently, research trends have expanded beyond the detection of predefined objects toward the identification of specified target objects. For example, desired targets can be specified through textual prompts, enabling accurate detection of objects of interest. To address this demand, this paper proposes an efficient multimodal-based object detection model aimed at improving small object detection performance. The proposed method is built upon the YOLO-World framework and replaces the C2f layers used in the YOLOv8 backbone with attention-based A2C2f layers. This modification enables more precise representation of local features, particularly for small objects or objects with well-defined boundaries. In addition, the incorporation of attention mechanisms and parallel processing structures significantly enhances the model's computational accuracy. Comparative experiments conducted on the VisDrone dataset demonstrate that the proposed model outperforms the original YOLO-World model. Specifically, precision increases from 43.0% to 45.1%, recall from 32.8% to 35.0%, the F1 score from 37.2% to 39.4%, mAP@0.5 from 32.5% to 35.2%, and mAP@0.5-0.95 from 18.5% to 19.9%, confirming a substantial improvement in detection accuracy. These results verify that the proposed approach provides an effective and highly accurate solution for object detection in drone-based image and video application environments.","authors":["Hyun-Ki Jung"],"published":"2026-07-20T08:21:12Z","updated":"2026-07-20T08:21:12Z","abstract_url":"https://arxiv.org/abs/2607.17669v1","html_url":"https://arxiv.org/html/2607.17669v1","pdf_url":"https://arxiv.org/pdf/2607.17669v1.pdf","matched_keywords":["video","representation","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17660v1","title":"RayOcc: Occlusion-Aware Ray Occupancy Estimation via Gaussian Mixture Intensity","abstract":"Camera-only 3D semantic occupancy prediction aims to infer voxel-wise scene semantics from multi-view images, yet remains fundamentally challenging due to depth ambiguity and occlusion. Along a single camera ray, multiple spatially separated surfaces may coexist, making occupancy inherently a multi-label existence problem rather than a single-depth estimation task. However, most existing approaches favor a single dominant depth hypothesis per ray, limiting their ability to model volumetric scenes under complex occlusion. To address this limitation, we introduce RayOcc, an occlusion-aware ray occupancy framework that reformulates ray modeling as multi-label existence prediction. Instead of predicting a categorical depth distribution, RayOcc estimates a non-normalized Gaussian mixture intensity along each ray and converts it into interval-wise occupancy probabilities via a Poisson event formulation, allowing multiple occupied hypotheses to coexist without enforcing mutual competition across depth. The predicted mixture components are interpreted as occupancy hypotheses to initialize sparse 3D Gaussian primitives, which are refined and rasterized for semantic occupancy prediction. Experiments on the nuScenes benchmark show that RayOcc achieves state-of-the-art overall IoU and mIoU among the compared Gaussian-based occupancy methods.","authors":["Junho Kim","Seongwon Lee"],"published":"2026-07-20T08:10:58Z","updated":"2026-07-20T08:10:58Z","abstract_url":"https://arxiv.org/abs/2607.17660v1","html_url":"https://arxiv.org/html/2607.17660v1","pdf_url":"https://arxiv.org/pdf/2607.17660v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17657v1","title":"OrientSAM: Mitigating Camera-Centric Shortcut in Multimodal Spatial Reasoning via Orientation-Aware Spatial Alignment","abstract":"Multimodal large language models (MLLMs) still struggle with spatial reasoning that requires perspective transformation. In particular, they often rely on camera-centric cues rather than reasoning from the reference object's viewpoint, leading to systematic errors in non-camera reference settings. In this paper, we first analyze this failure mode and show that object orientation is a key factor underlying such camera-centric shortcut behavior. To address this issue, we propose OrientSAM, an orientation-aware spatial alignment framework for multimodal models. OrientSAM injects explicit orientation information into multimodal representations through orientation-aware tokens and Fourier-based angle encoding, and further adopts a curriculum learning strategy to progressively improve perspective-aware reasoning. In addition, we build a spatial data construction pipeline to generate orientation-aware spatial supervision from large-scale images. Experiments on Spatial-MM, ViewSpatial, and 3DSRBench show that OrientSAM consistently outperforms strong baselines, especially on non-camera-view, person-centric, and orientation-sensitive tasks. The results further demonstrate that explicit orientation modeling is important for mitigating camera-centric shortcut behavior and enabling more robust allocentric spatial reasoning in multimodal models.","authors":["Wenxiao Fan","Hang Yin","Kan Li"],"published":"2026-07-20T08:07:22Z","updated":"2026-07-20T08:07:22Z","abstract_url":"https://arxiv.org/abs/2607.17657v1","html_url":"https://arxiv.org/html/2607.17657v1","pdf_url":"https://arxiv.org/pdf/2607.17657v1.pdf","matched_keywords":["3d","representation","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17656v1","title":"BMFA: Boundary-Minority Free-Energy Adaptive Screening","abstract":"Vision Transformers process spatially redundant tokens efficiently only when coarse token summaries preserve the evidence required by exponential attention aggregation. We identify a boundary-minority underestimation failure in which a spatially small, high-response region contributes dominant Gibbs mass while remaining nearly invisible to a block mean. We formalize the failure through the discrepancy between normalized log-mean-exp free energy and mean summarization, prove that minority Gibbs mass can remain non-vanishing as its spatial support and mean contribution vanish, and characterize the limitations of finite-order moment corrections. Building on the resulting analysis, we introduce Boundary-Minority Free-Energy Adaptive Screening (BMFA), which constructs a hierarchical piecewise-constant approximation and recursively refines blocks according to a computable lower-bound increment of local free energy. Controlled synthetic tests, COCO and LVIS diagnostic probes, closed-loop DeiT-Tiny evaluations, and ImageNet-1K experiments establish a consistent evidence chain. BMFA reduces the mean synthetic underestimate from 2.582 to 0.261 at a 5.794% leaf ratio, lowers the COCO image-edge mean gap from 2.254 to 0.526, and preserves 71.520% ImageNet Top-1 accuracy at a 55.861% leaf ratio. The current prototype evaluates selection quality after full QK computation; the reported leaf ratio therefore characterizes representation granularity rather than verified sparse-kernel speedup.","authors":["Wenyan Xu","Alizer Wong"],"published":"2026-07-20T08:07:18Z","updated":"2026-07-20T08:07:18Z","abstract_url":"https://arxiv.org/abs/2607.17656v1","html_url":"https://arxiv.org/html/2607.17656v1","pdf_url":"https://arxiv.org/pdf/2607.17656v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17639v1","title":"Direct Clinical Joint Angle Extraction from Parametric Body Model Rotation Matrices","abstract":"Quantitative joint angles are rarely available in routine care because the tools are slow, costly, or confined to a laboratory. We show that clinical joint angles can be read directly from the per-segment rotation matrices a parametric body model already produces, with no inverse-kinematics or musculoskeletal-model fitting step. On the OpenCap LabValidation cohort, using the GEM-X body-model estimator on single-smartphone video, our pooled mean absolute error is 4.50 degrees over the fifteen joint angles that match the OpenCap Monocular reference set, the same accuracy range as OpenCap Monocular's 4.8 degrees on the same cohort and reference standard, from a much simpler pipeline. The step that connects a body model to clinical angles is a small calibration table rather than an optimisation, so the same procedure transfers unchanged to other body models: repeating it on SAM 3D Body, changing only the table, gives 4.66 degrees, statistically indistinguishable from GEM-X, and runs in real time from a live single-camera stream. The method needs no per-recording inputs beyond the video itself: no participant height, no camera-intrinsics database, no per-subject model scaling. This broadens where movement analysis is practical, from in-clinic and at-home recording to telerehabilitation and large-scale decentralised studies.","authors":["Joey Páolo Kardolus","Daan Hendriks","Jaap Jansen"],"published":"2026-07-20T07:47:56Z","updated":"2026-07-20T07:47:56Z","abstract_url":"https://arxiv.org/abs/2607.17639v1","html_url":"https://arxiv.org/html/2607.17639v1","pdf_url":"https://arxiv.org/pdf/2607.17639v1.pdf","matched_keywords":["video","3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17638v1","title":"Reviving Ancient Paintings via Poem: A Colorization Framework for Aligning Cultural Semantics","abstract":"The irreversible fading of ancient paintings disrupts the \"congruence between poems and paintings\", a core aesthetic principle where visual imagery harmonizes with literary inscriptions. Although diffusion models provide strong generative priors, restoring historically faithful colors remains difficult: visual restoration is inherently ambiguous, while direct text guidance often causes modern semantic bias, over-saturation, and cross-boundary color leakage. To address this, we propose PoemColor, a poem-guided ancient painting colorization framework. Our method aligns poetic cultural semantics with painting restoration through two key designs. First, the Poetic Painting Projector (P3) converts implicit poetic context into a classical color-aware condition via poem-to-palette pretraining, reducing the ambiguity of poem-to-color mapping. Second, Structure-Aware Semantic Attention (SASA) regulates how poetic color semantics are injected into the diffusion backbone by jointly controlling their propagation direction and regional injection strength. In addition, we construct a hybrid restoration dataset that integrates synthetic degradation with expert-restored artifacts, providing both scalable supervision and real classical color references. Extensive experiments demonstrate that our framework significantly outperforms state-of-the-art methods, delivering controllable colorization that revives both historical authenticity and poetic semantics.","authors":["Junming Gao","Biao Zhu","Xiaosong Wang","Tan Tang"],"published":"2026-07-20T07:46:37Z","updated":"2026-07-20T07:46:37Z","abstract_url":"https://arxiv.org/abs/2607.17638v1","html_url":"https://arxiv.org/html/2607.17638v1","pdf_url":"https://arxiv.org/pdf/2607.17638v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17634v1","title":"MixDiffusion: Mixing Diffusion-based Uni-condition Text-to-Image Generation Models for Multi-condition Image Synthesis","abstract":"Recent advances in text-to-image (T2I) generation have enabled controllable image synthesis by incorporating conditions beyond text. However, most existing diffusion-based methods are limited to a single type of control condition (e.g., bounding boxes or keypoints), which restricts their flexibility. To address this limitation, we propose MixDiffusion, a training-free diffusion framework for multi-condition T2I generation. MixDiffusion theoretically supports an arbitrary number of control conditions, including bounding boxes, keypoints, sketches, depth maps, reference images, and text, by collaboratively integrating multiple pre-trained uni-condition diffusion models. The key insight of the proposed approach is to derive the predicted noise distribution in each denoising step of the diffusion-based multi-condition image generation model from the predicted noise distributions of multiple diffusion-based uni-condition models with a derived integration formula, which is supported by rigorous theory proof. Owing to its training-free nature, MixDiffusion is easy to deploy and readily extensible to new control modalities.","authors":["Pengcheng Wan","Liang Han","Lin Xu","Bowen Xiao","Liqiang Nie"],"published":"2026-07-20T07:40:56Z","updated":"2026-07-20T07:40:56Z","abstract_url":"https://arxiv.org/abs/2607.17634v1","html_url":"https://arxiv.org/html/2607.17634v1","pdf_url":"https://arxiv.org/pdf/2607.17634v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17625v1","title":"Brain-Aligned Multi-Stream Video Transformers with Sparse Self-Selection","abstract":"Modern video transformers typically ignore principles from primate vision and are rarely evaluated against neural data, limiting their biological interpretability. We introduce a sparse winner-takes-all token selection module that replaces dense self-attention to improve efficiency and approximate competitive routing observed in biological visual circuits. We further propose a neuro-inspired split-and-fuse video transformer which uses two complementary pathways: a high-resolution, low-frame-rate \"what\" stream and a low-resolution, high-frame-rate \"where\" stream, fused before classification. On Kinetics-400 and Something-Something V2, our best variant operates on the Pareto frontier of accuracy versus inference time among models of comparable scale and pretraining, and showing improved robustness to spatial perturbations. Using representational similarity analysis between model embeddings and time-resolved EEG recordings for the same video stimuli, our model attains a peak brain-model correlation of 0.18 (about 78% of the noise ceiling) and consistently outperforms strong video transformer baselines, suggesting that pathway specialization and sparse competition are useful inductive biases for efficient, brain-aligned video understanding.","authors":["Amir Hosein Fadaei","Mahyar Maleki","Mohammad-Reza A. Dehaqani"],"published":"2026-07-20T07:30:16Z","updated":"2026-07-20T07:30:16Z","abstract_url":"https://arxiv.org/abs/2607.17625v1","html_url":"https://arxiv.org/html/2607.17625v1","pdf_url":"https://arxiv.org/pdf/2607.17625v1.pdf","matched_keywords":["video","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17612v1","title":"Rarity-Aware Discrete Diffusion with Spatially Consistent Decoding for Photo-Realistic Image Super-Resolution","abstract":"Continuous diffusion models have become the dominant paradigm for photo-realistic image Super-Resolution (SR), but they typically formulate reconstruction as continuous signal-level denoising and incorporate semantic priors through external conditioning modules. This makes it less direct to exploit the unified token-based scaling paradigm of modern multimodal models. Autoregressive models provide a more native semantic representation by modeling images as discrete visual tokens, yet their causal decoding is inefficient for high-resolution reconstruction. Discrete diffusion offers a promising middle ground by enabling non-causal, parallel prediction over visual tokens. However, directly adapting discrete diffusion to SR remains non-trivial due to two task-specific challenges: (1) the long-tailed distribution of visual tokens, which under-represents rare but perceptually critical textures; and (2) spatially inconsistent parallel decoding, which may introduce isolated artifacts. To address these issues, we propose DiMOO-SR, a rarity-aware multimodal discrete diffusion framework for photo-realistic image SR. During training, Inverse Frequency Sampling (IFS) prioritizes under-represented but information-rich tokens. During inference, Spatial Consistency Ranking (SCR) refines token confidence using local neighborhood agreement to improve structural coherence. Extensive experiments on widely used real-world SR benchmarks demonstrate that DiMOO-SR achieves competitive perceptual quality with only a few parallel decoding steps, highlighting the potential of discrete diffusion for generative image super-resolution. The code will be released upon publication.","authors":["Ao Li","Yapeng Du","Yi Xin","Lei Zhu","Le Zhang","Guangtao Zhai","Ce Zhu","Xiaohong Liu"],"published":"2026-07-20T07:01:01Z","updated":"2026-07-20T07:01:01Z","abstract_url":"https://arxiv.org/abs/2607.17612v1","html_url":"https://arxiv.org/html/2607.17612v1","pdf_url":"https://arxiv.org/pdf/2607.17612v1.pdf","matched_keywords":["representation","multimodal","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17611v1","title":"Coarse-to-fine Framework for Generative MEF via Implicit Neural Representation","abstract":"Multi-exposure fusion (MEF) expands the luminance range beyond what a single exposure can capture. Combining images taken at different exposure levels requires handling geometric differences while naturally merging their complementary brightness information. It often demands generative completion where details are missing. Diffusion-based generative methods address these challenges, however, they are computationally expensive and struggle to preserve fine structures in saturated regions. We propose LIIFusion, a coarse-to-fine framework that balances fusion quality and efficiency in generative MEF. The coarse stage performs low resolution generative fusion, enhanced by an adaptive exposure correction that recovers structure lost in saturated over-exposed areas. The fine stage adapts a local implicit image function into a multi-exposure fusion function: conditioned on the HR OE/UE sources and the coarse output, it queries arbitrary target coordinates and fuses source evidence regardless of the HR input resolution. LIIFusion achieves up to 3.5$\\times$ speed-up over existing generative methods while maintaining or improving structural fidelity and perceptual quality. We believe this framework provides an effective pathway toward making generative MEF more practical in real-world applications.","authors":["Sangmin Han","Jinho Kim","Jinwoo Kim","Dongyoung Kim","Seon Joo Kim"],"published":"2026-07-20T07:00:47Z","updated":"2026-07-20T07:00:47Z","abstract_url":"https://arxiv.org/abs/2607.17611v1","html_url":"https://arxiv.org/html/2607.17611v1","pdf_url":"https://arxiv.org/pdf/2607.17611v1.pdf","matched_keywords":["representation","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17599v1","title":"ConsiSpace: Learning Geometric Consistency Matters for Video Spatial Reasoning","abstract":"Video spatial reasoning is essential for navigation-oriented perception and long-video question answering, where models must infer spatial relations across long horizons under changing viewpoints. However, existing multimodal large language models (MLLMs) remain largely semantic-centric, and often fail to reliably aggregate consistent spatial evidence from redundant video observations, leading to inefficient or unstable reasoning. To address these issues, we propose ConsiSpace, a geometry-consistency-aware framework for geometry-sensitive video spatial reasoning that turns spatial consistency into both an evidence organization principle and an explicit post-SFT learning signal. We build a geometry-consistent memory (GCM) including implicit evidence tokens and explicit geometric cues, and leverage efficient organization strategies to compactly preserve task-related spatial evidence. Furthermore, we utilize unified consistency self-supervised reinforcement learning (UC-SSRL) after supervised fine-tuning to improve cross-view stability, with answer-, metric-, and topology-consistency rewards. Extensive experiments on three spatial-reasoning benchmarks, VSI-Bench, OSI-Bench, and MMSI-Video-Bench, show consistent gains, improving the average score by 12.6 points over the strongest baselines.","authors":["Ting Huang","Zhenyu Zhang","Wenyuan Huang","Jian Yang","Hao Tang"],"published":"2026-07-20T06:40:45Z","updated":"2026-07-20T06:40:45Z","abstract_url":"https://arxiv.org/abs/2607.17599v1","html_url":"https://arxiv.org/html/2607.17599v1","pdf_url":"https://arxiv.org/pdf/2607.17599v1.pdf","matched_keywords":["video","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17585v1","title":"Pixel-Space Diffusion Transformers","abstract":"Latent diffusion models (LDMs) enable efficient high-resolution image synthesis by denoising in a VAE-compressed latent space. However, fixed visual tokenizers can discard fine textures and structural details, while separate representation and diffusion training creates a mismatch between reconstruction and generation objectives. These limitations have renewed interest in pixel-space diffusion, which models raw pixels directly, removes the VAE bottleneck, and supports end-to-end optimization. This formulation better matches the demands of high-fidelity generation but introduces challenges in high-dimensional modeling, including noise scheduling, loss weighting, token efficiency, and scalable architecture design. Pixel-space modeling also offers a promising basis for unified multimodal systems: raw pixels, text, and task conditions can be represented in a shared token space and jointly processed by a single Transformer, narrowing the gap between visual understanding and generation. This paper reviews Pixel-Space Diffusion Transformers (pDiTs) from the perspectives of model architecture, continuous generative mechanisms, and unified multimodal modeling. We summarize representative methods, identify key technical challenges, and discuss future directions toward high-fidelity, end-to-end vision foundation models that integrate generation and understanding.","authors":["Renye Yan","Jikang Cheng","You Wu","Ling Liang","Wei Peng","Athanasios V. Vasilakos","Qingyu Zhao","Yu Zhang","Ehsan Adeli","Kilian M. Pohl","Guoying Zhao"],"published":"2026-07-20T06:04:08Z","updated":"2026-07-20T06:04:08Z","abstract_url":"https://arxiv.org/abs/2607.17585v1","html_url":"https://arxiv.org/html/2607.17585v1","pdf_url":"https://arxiv.org/pdf/2607.17585v1.pdf","matched_keywords":["representation","multimodal","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17572v1","title":"AGG: Jacobian-Aggregated Group Gradient for Efficient GRPO Training of Diffusion Models","abstract":"Group Relative Policy Optimization (GRPO) is a powerful reinforcement learning algorithm for aligning generative models with human preferences. While successful in large language models~\\cite{shao2024deepseekmathpushinglimitsmathematical}, its extension to diffusion and flow matching models introduces a severe computational bottleneck: gradients must be back-propagated through the high-capacity DiT backbone at \\emph{every} timestep of the sampling trajectory, making high-resolution text-to-image (T2I) training prohibitively expensive. Training-free DiT inference acceleration methods (e.g., $Δ$-DiT, ScalingCache) exploit the fact that DiT hidden states and velocity predictions vary \\emph{smoothly and nearly linearly} along the trajectory. We ask whether the same linearity can reduce the backward-pass cost of DiT RL training, and answer affirmatively with \\textbf{JAGG} (\\textbf{J}acobian-\\textbf{A}ggregated \\textbf{G}roup \\textbf{G}radient), which reduces full transformer backward passes from $W$ to $2$ per group of $W$ consecutive steps. JAGG approximates intermediate-step Jacobians via $t$-weighted interpolation of the endpoint Jacobians, then aggregates per-step upstream signals into two composite gradients applied through a single joint backward pass. We prove this interpolation is \\emph{exact} when the velocity is linear in $(z,t)$, and a cosine-similarity routing rule (\\texttt{jagg\\_frac}) deploys JAGG only where the assumption holds. Experiments on T2I benchmarks show JAGG delivers $\\sim$2$\\times$ backward speedup with negligible quality degradation.","authors":["Ruiyi Ding","Jie Li","He Kang","Ziyan Liu","Chengru Song","Yuan chen"],"published":"2026-07-20T05:30:40Z","updated":"2026-07-20T05:30:40Z","abstract_url":"https://arxiv.org/abs/2607.17572v1","html_url":"https://arxiv.org/html/2607.17572v1","pdf_url":"https://arxiv.org/pdf/2607.17572v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17563v1","title":"FlexiGrad: Adaptive Gradient Modulation for Hierarchical Fine-Grained Classification","abstract":"Many fine-grained recognition tasks contain hierarchical labels such as order, family and species. Although this supervision should be beneficial, jointly optimising all levels often leads to unstable training because coarse and fine classifiers impose inconsistent gradients on the shared backbone. This hierarchical gradient conflict prevents the model from learning a coherent coarse-to-fine representation. In this paper, we propose FlexiGrad, a simple and parameter-free method that regulates gradient interactions during backpropagation. FlexiGrad removes only the harmful conflicting component when tasks disagree and reinforces the shared direction when they partially agree through a smooth hierarchy-aware weighting function. This produces stable optimisation and preserves both global structure and fine-grained discriminative cues. FlexiGrad integrates into existing architectures without modification while improves multi-granularity accuracy on CUB-200-2011, FGVC-Aircraft and Stanford Cars. The code will be available at PRIS-CV/FlexiGrad.","authors":["Zilu Zhou","Dongliang Chang","Junhan Chen","Zhanyu Ma"],"published":"2026-07-20T05:18:19Z","updated":"2026-07-20T05:18:19Z","abstract_url":"https://arxiv.org/abs/2607.17563v1","html_url":"https://arxiv.org/html/2607.17563v1","pdf_url":"https://arxiv.org/pdf/2607.17563v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17551v1","title":"Hierarchy-Aware and Anatomy-Guided Learning for Lung Ultrasound Video Classification","abstract":"Lung ultrasound (LUS) is a bedside tool for assessing pulmonary edema in patients at risk due to heart failure or impaired kidney function. However, automated LUS analysis remains challenging because of speckle noise, imaging artifacts, and operator-dependent acquisition variability. In this work, we present a deep learning framework for multi-class LUS video classification that explores two components: hierarchy-aware training, and anatomy-guided learning. Starting from a strong baseline, we introduce hierarchical training strategies and then introduce pleural line mask supervision to guide model attention toward anatomically relevant regions. We study four clinically relevant classes--healthy, B-lines, consolidations, and mixed B-lines with consolidations--using an open-access dataset of 1,886 videos from 219 patients, evaluated with patient-level five-fold cross-validation. Results show that hierarchy-aware training improves pathological separation relative to flat classification, while mask-guided attention supervision achieves the highest mean macro-F1 of 65.7\\% and produces more localized attention patterns. Transfer experiments on the external COVID-BLUeS dataset further show competitive and parameter-efficient adaptation while preserving pleural-focused attention behavior. These findings suggest that combining clinically structured objectives with anatomy-guided supervision is a practical approach to robust, interpretable LUS video analysis. Code and model implementations are available at https://github.com/Alya-Almsouti/LUS-video-classification.","authors":["Alya Almsouti","Lotfi Mecharbat","Noha Aboukhater","Yousef Alabrach","Siddiq Anwar","Andre Kumar","Ibrahim Almakky","Mohammad Yaqub"],"published":"2026-07-20T04:55:28Z","updated":"2026-07-20T04:55:28Z","abstract_url":"https://arxiv.org/abs/2607.17551v1","html_url":"https://arxiv.org/html/2607.17551v1","pdf_url":"https://arxiv.org/pdf/2607.17551v1.pdf","matched_keywords":["video"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17523v1","title":"Thinking in Video: Can Video Generators Really Reason About the Real World?","abstract":"Recent advances in world models and video generation have given rise to an emerging reasoning paradigm that leverages video generative models to simulate, predict, and reason about real-world dynamics. We redefine this paradigm as Thinking in Video, where video is not merely an output artifact but a medium for constructing, extending, and verifying causal thought. However, this promise remains unverified: convincing rollouts may reflect memorized appearances rather than causal understanding, while existing metrics separate perceptual fidelity from semantic logic. To evaluate whether video generators support such reasoning, we introduce the Causal-Generative Dual-Judge (CGDJ), auditing World Model Consistency from two perspectives. Explicit Causal Perception tests whether a generator reads a video scenario as a reasoning problem through spatio-temporal flattened visual question answering, while Implicit Generative Perception-Prediction Gap evaluates whether it renders the causal consequence as a consistent future video. Applying CGDJ to representative open- and closed-source generators reveals a clear Perception-Prediction Gap: open-source models produce plausible dynamics despite near-zero explicit causal perception, whereas advanced closed-source systems show stronger but still limited alignment between reasoning and generation. Further analysis exposes audio-visual misalignment, where models verbalize correct causal logic more reliably than they render it, challenging the \"world simulator\" narrative.","authors":["Yongheng Zhang","Guang Yang","Ruihan Hou","Qiguang Chen","Ziang Liu","Xiaolong Liu","Manman Zhang","Yanchao Hao","Zheng Wei","Hao Wu","Libo Qin","Peishan Dai","Yinghui Li","Di Yin","Xing Sun"],"published":"2026-07-20T03:56:43Z","updated":"2026-07-20T03:56:43Z","abstract_url":"https://arxiv.org/abs/2607.17523v1","html_url":"https://arxiv.org/html/2607.17523v1","pdf_url":"https://arxiv.org/pdf/2607.17523v1.pdf","matched_keywords":["video"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17504v1","title":"DecoyFace: Beyond Obfuscation via Controllable and Imperceptible Identity Misdirection for Privacy-Preserving Face Recognition","abstract":"Split face recognition reduces client-side computation but exposes intermediate features to feature inversion attacks and unauthorized analysis by honest-but-curious (HBC) servers. Existing privacy-preserving face recognition methods mainly aim to resist unauthorized reconstruction, typically producing features whose inversion yields visibly degraded results, which may reveal the existence of protection and motivate adaptive attacks. To address this issue, we propose DecoyFace, an imperceptible decoy-oriented framework that steers unauthorized reconstruction toward a plausible but incorrect identity while preserving recognition utility. The key idea is to decompose the intermediate representation into a reconstruction-sensitive subspace and its complementary subspace. The client injects decoy identity cues into the reconstruction-sensitive subspace, while limited recognition-relevant evidence from the true sample is retained in the complementary subspace. On the server side, an authorized canonicalization module suppresses decoy-dominant components and recovers a recognition-friendly representation. This design addresses both attacker-side inversion from intercepted features and HBC server-side reconstruction from canonicalized representations. Experiments show that DecoyFace preserves competitive recognition accuracy while substantially reducing identity leakage to 2.93% under U-Net attacks and 0.74% under Flow-Matching attacks while yielding visually plausible and imperceptible reconstructions, with over 99.78% face validity on LFW dataset.","authors":["Zhihan Ren","Lijun He","Xinyao Wang","Xinzhu Fu","Fan Li"],"published":"2026-07-20T03:19:00Z","updated":"2026-07-20T03:19:00Z","abstract_url":"https://arxiv.org/abs/2607.17504v1","html_url":"https://arxiv.org/html/2607.17504v1","pdf_url":"https://arxiv.org/pdf/2607.17504v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17482v1","title":"Generative Transmission: Rethinking Computation, Bandwidth, and Memory in Communication","abstract":"Under the AI Flow framework, communication is shifting from transmitting fidelity-oriented information flows toward delivering task-oriented and perception-oriented token flows across heterogeneous network resources. Video communication is a fundamental component of modern information networks. However, under ultra-low-bandwidth and weak-network conditions, conventional video coding and transmission methods, which are primarily optimized for pixel-level fidelity, often struggle to balance visual usability, transmission efficiency, and robustness to unstable links. With the rapid advancement of generativemodels, video communication is also moving from precise signal reconstruction toward receiver-side perceptual utility and system-level usability. In this paper, we propose Generative Transmission (GenTrans) for video communication under ultra-low-bandwidth and weak-network conditions. Built upon Generative Video Compression (GVC), GenTrans formulates video transmission as a joint optimization problem involving bandwidth, computation, and memory, rather than treating it merely as a signal coding task. By leveraging generative priors, cross-clip memory reuse, runtime state reuse, and weak-network-aware transport, GenTrans significantly reduces transmission overhead while enabling visually coherent and practically useful reconstruction. Experimental results show that GenTrans supports effective video transmission under ultra-low-bitrate and weak-network conditions, achieving improved transmission efficiency, decoding efficiency, and robustness while preserving perceptual quality.","authors":["Xiangyu Chen","Jixiang Luo","Yuankai Fan","Haibin Huang","Chi Zhang","Xuelong Li"],"published":"2026-07-20T02:11:26Z","updated":"2026-07-20T02:11:26Z","abstract_url":"https://arxiv.org/abs/2607.17482v1","html_url":"https://arxiv.org/html/2607.17482v1","pdf_url":"https://arxiv.org/pdf/2607.17482v1.pdf","matched_keywords":["video"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17467v1","title":"DA-MergeLoRA: Hypernetwork-Based LoRA Merging for Few-Shot Test-Time Domain Adaptation","abstract":"Few-shot Test-Time Domain Adaptation (FSTT-DA) seeks to adapt models to novel domains using only a handful of unlabeled target samples. This setting is more realistic than typical domain adaptation setups, which assume access to target data during source training. However, prior FSTT-DA approaches fail to effectively leverage source domain-specific knowledge, relying on shallow batch normalization updates, prompt-based methods that treat the model as a black box, or ensembling strategies that do not capture cross-domain relationships. To address these limitations, we introduce a new FSTT-DA framework that integrates LoRA fine-tuning with model merging. In our approach, separate LoRA modules are fine-tuned on CLIP's vision encoder for each source domain. Since LoRA modifies only a small fraction of the model's parameters, it retains the base model's generalized knowledge while internally learning domain-specific features. To adapt the learned knowledge to a specific target domain, we propose a hypernetwork trained via meta-learning that generates per-column merging factors to combine LoRA modules. Given a small batch of target images, the hypernetwork produces merging weights that fuse source LoRA modules into a single adapted representation. Our results demonstrate state-of-the-art performance across various domain adaptation datasets. Our code is publicly available at https://github.com/nahbois4321/DA-MergeLoRA.","authors":["Siobhan Reid","Zhixiang Chi","Li Gu","Omid Reza Heidari","Ziqiang Wang","Yang Wang"],"published":"2026-07-20T01:45:37Z","updated":"2026-07-20T01:45:37Z","abstract_url":"https://arxiv.org/abs/2607.17467v1","html_url":"https://arxiv.org/html/2607.17467v1","pdf_url":"https://arxiv.org/pdf/2607.17467v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17441v1","title":"An Explainable FFT-Based Spatial-Frequency Fusion Framework for Deepfake Detection","abstract":"Deepfake generation has raised growing concerns regarding digital media authenticity, misinformation, identity fraud, and public trust. Recent studies show that combining spatial and frequency features leads to stronger detection results than using independently. This paper presents MSCA-FFT, a Fast Fourier Transform (FFT)-based multi-scale cross-attention framework for image-level deepfake detection. The model combines a partially fine-tuned Xception spatial branch with an FFT-based frequency branch. The frequency branch processes the log-scaled FFT magnitude spectrum through shallow convolutional layers, avoiding inverse frequency-to-image reconstruction used in DCT-based pipelines. The spatial and frequency representations are refined by transformer encoders, fused through cross-attention, and passed to an MLP classifier for real/fake prediction. Experimental results show that MSCA-FFT achieves consistently higher performance than the DCT-based state-of-the-art spatial-frequency fusion method and the compared baseline models. The ablation study further indicates that the FFT-based frequency branch provides complementary spectral cues when fused with spatial features. In addition, FFT-based frequency analysis and Grad-CAM/LIME explanations show consistent evidence around manipulation-sensitive facial regions, including the eyes, mouth, nose, and facial boundaries.","authors":["Pamela Kirui","Cho Hyuk","Qingzhong Liu","Haodi Jiang"],"published":"2026-07-19T23:45:40Z","updated":"2026-07-19T23:45:40Z","abstract_url":"https://arxiv.org/abs/2607.17441v1","html_url":"https://arxiv.org/html/2607.17441v1","pdf_url":"https://arxiv.org/pdf/2607.17441v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"}],"favorites":[],"latest":{"generated_at_utc":"2026-07-21T04:12:05+00:00","category":"cs.CV","keywords":["video","retrieval","3d","agent","representation","instance","multimodal","diffusion"],"fetch_window_hours":72,"daily_window_hours":30,"match_count":60,"new_or_recent_papers":[{"id":"2607.18237v1","title":"The Many Senses of Visual Similarity: A Text-Prompted Image Perceptual Metric","abstract":"Human visual similarity judgments are context-dependent. For example, two images may be similar in shape but distinct in color. Existing perceptual similarity metrics, however, collapse these nuances into a single scalar value, offering no mechanism to condition on specific aspects. To bridge this gap, we introduce a large-scale dataset of human similarity judgments over image triplets, where each triplet is annotated across multiple, free-form semantic aspects of similarity. Benchmarking a broad range of frontier vision-language models (VLMs) reveals a considerable performance gap compared to human annotators' consensus. Leveraging our data, we fine-tune a VLM to produce our Text-Prompted Image Perceptual Similarity (TPIPS) metric, capturing multiple senses of visual similarity depending on the specified text prompt. We demonstrate that TPIPS aligns more closely with human perception and generalizes reliably beyond the training distribution. Finally, we show that TPIPS unlocks new capabilities in text-guided retrieval, compositional search, and the fine-grained evaluation of generative models. Our code, data, and trained models are at https://peterwang512.github.io/TPIPS","authors":["Sheng-Yu Wang","Yotam Nitzan","Aaron Hertzmann","Jun-Yan Zhu","Eli Shechtman","Alexei A. Efros","Richard Zhang"],"published":"2026-07-20T17:59:51Z","updated":"2026-07-20T17:59:51Z","abstract_url":"https://arxiv.org/abs/2607.18237v1","html_url":"https://arxiv.org/html/2607.18237v1","pdf_url":"https://arxiv.org/pdf/2607.18237v1.pdf","matched_keywords":["retrieval"],"source_used":"abstract","source_text_chars":1269,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 retrieval 相关；摘要显示其主要贡献为：Human visual similarity judgments are context-dependent. For example, two images may be similar in shape but distinct in color. Existing perceptual similarity metrics, however, collapse these nuances into a single scalar value, offering no mechanism to condit...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"abstract","created_at":"2026-07-21T04:12:05+00:00","status":"fallback"},"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.18227v1","title":"FlowMimic: Mask-free Visual Editing and Generation with Pixel-pair Warped Flow Field for Online Video Editing Data Generation and Modality Mimicry","abstract":"In line with the prevailing direction of vision research, we explore the integration of both generation and editing capabilities for video and image modalities within a single model. Current approaches to collecting video editing data typically depend on labour-intensive, time-consuming curated procedures--involving object mask annotation, the use of error-introducing pair synthesis via I2V model and ControlNet-like guidance, and VLM-based quality filtering or refinement--and demonstrate limited task scalability. As a result, the diversity of editing tasks remains substantially narrower than that available for image editing models. We develop a pixel-pair temporal warped flow field that can directly generate corresponding video editing samples in real time from image editing samples, and we demonstrate across multiple levels of video editing tasks that a model can learn video editing using only such data. We regard the image modality as a particular form of the video modality. Accordingly, we design a modality mimic generation loss and a modality mimic editing loss to relatively align the capabilities--and thereby the output distributions--of the two modalities through mutual imitation. Moreover, language-based visual editing entails the comprehension of the editing instruction and the reference visual content, the localization of the region corresponding to that instruction within the reference visual contents, and the modification of that region alone. Existing approaches predominantly rely on external aids, such as fine-tuning an additional MLLM or explicitly supplying a mask sequence as auxiliary input during inference. In contrast, we aspire for the model to internalize this capability. To that end, we introduce sense-related tasks--for instance, referring expression segmentation--along with corresponding editing-region-aware latent-level loss and attention-level loss.","authors":["Dingyun Zhang","Lixue Gong","Wei Liu"],"published":"2026-07-20T17:58:03Z","updated":"2026-07-20T17:58:03Z","abstract_url":"https://arxiv.org/abs/2607.18227v1","html_url":"https://arxiv.org/html/2607.18227v1","pdf_url":"https://arxiv.org/pdf/2607.18227v1.pdf","matched_keywords":["video","instance"],"source_used":"abstract","source_text_chars":2054,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, instance 相关；摘要显示其主要贡献为：In line with the prevailing direction of vision research, we explore the integration of both generation and editing capabilities for video and image modalities within a single model. Current approaches to collecting video editing data typically depend on labo...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"abstract","created_at":"2026-07-21T04:12:05+00:00","status":"fallback"},"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.18218v1","title":"GigaPath-Flash and GigaTIME-Flash: Efficient Pathology Foundation Models for Whole-Slide and Tumor Microenvironment Analysis","abstract":"Foundation models have emerged as a driving force in computational pathology, with the potential to transform cancer diagnosis, prognosis, and treatment selection by learning transferable representations from large-scale histopathology data. A growing landscape of pathology foundation models now spans diverse data sources, architectures, and downstream applications. However, most pretrained models operate only at the image-tile level, use restrictive licenses, and remain computationally expensive, limiting large-scale slide-level clinical and research use. Here, we introduce GigaPath-Flash and GigaTIME-Flash, efficient models for whole-slide pathology AI and spatial proteomics prediction. GigaPath-Flash combines a 22M-parameter ViT-S tile encoder with a 21M-parameter LongNet slide encoder, both pretrained on large-scale real-world histopathology data. Its compact tile encoder is distilled from the billion-parameter GigaPath (ViT-g) teacher and shared by both models. GigaPath-Flash retains 97% of GigaPath's average slide-level performance with 50x less compute. GigaTIME-Flash extends this backbone to predict the tumor immune microenvironment directly from routine H&E images. It surpasses the original CNN-based GigaTIME in prediction quality while running 6x faster and using 8x less GPU memory. Together with GigaPath and GigaTIME, these models form an open-weight, Apache-2.0-licensed family pretrained on large-scale real-world clinical data. By releasing all models and weights, we provide accessible building blocks for computational pathology, immuno-oncology, and precision health.","authors":["Naoto Usuyama","Jeya Maria Jose Valanarasu","Sicong Yao","Hanwen Xu","Jaspreet Bagga","Guanghui Qin","Robert E. Kramer","Cliff Wong","Soohee Lee","Hao Qiu","Theodore Zhengde Zhao","Racheli Ben Shimol","Angela Crabtree","Kevin Matlock","Eduardo Alejandro Lozano Garcia","Naiteek Sangani","Alberto Santamaria-Pang","Jason Entenmann","Alexandra Q. Bartlett","Bill J. Wright","Bernard A. Fox","Brian Piening","Sheng Zhang","Sheng Wang","Tristan Naumann","Carlo Bifulco","Hoifung Poon"],"published":"2026-07-20T17:52:33Z","updated":"2026-07-20T17:52:33Z","abstract_url":"https://arxiv.org/abs/2607.18218v1","html_url":"https://arxiv.org/html/2607.18218v1","pdf_url":"https://arxiv.org/pdf/2607.18218v1.pdf","matched_keywords":["representation"],"source_used":"html","source_text_chars":29313,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 representation 相关；摘要显示其主要贡献为：Foundation models have emerged as a driving force in computational pathology, with the potential to transform cancer diagnosis, prognosis, and treatment selection by learning transferable representations from large-scale histopathology data. A growing landsca...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-21T04:12:06+00:00","status":"fallback"},"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.18217v1","title":"HOMIE: Human-object Centric Video Personalization via Multimodal Intelligent Enchancement","abstract":"Human-object centric video personalization (HOCVP) is a core task within subject-driven video generation. However, existing methods suffer from two key limitations. First, most approaches focusing on inter-subject personalization still struggle to strike a balance between high subject fidelity and accurate interaction patterns between humans and diverse objects, especially when objects represent abstract concepts such as logos. Second, while intra-subject references (e.g., OCR maps, multi-view inputs) are expected to enhance subject fidelity, most existing works lack mechanisms to understand such latent correspondence. To address both challenges, we propose HOMIE, an HOCVP framework that tackles both inter- and intra-subject input settings in a unified manner. Compared to previous approaches, HOMIE proposes a better MLLM integration strategy to extract knowledge of reference-level relationships without compromising the controllability of text encoders or incurring costly re-alignment. Specifically, we introduce global multimodal guidance within self-attention to better align MLLM-derived semantic features with VAE tokens. Furthermore, we propose modality-reference embedding to differentiate tokens from MLLM features and VAE tokens and associate intra-subject reference image tokens. Extensive experiments validate that our method achieves state-of-the-art performance across various HOCVP tasks. Project Page: https://yiyangcai.github.io/homie-page.github.io/","authors":["Yiyang Cai","Nan Chen","Rongchang Xie","Junwen Pan","Chunyang Jiang","Cheng Chen","Wen Zhou","Zhenbang Sun","Wei Xue","Wenhan Luo","Yike Guo"],"published":"2026-07-20T17:51:35Z","updated":"2026-07-20T17:51:35Z","abstract_url":"https://arxiv.org/abs/2607.18217v1","html_url":"https://arxiv.org/html/2607.18217v1","pdf_url":"https://arxiv.org/pdf/2607.18217v1.pdf","matched_keywords":["video","multimodal"],"source_used":"html","source_text_chars":75020,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, multimodal 相关；摘要显示其主要贡献为：Human-object centric video personalization (HOCVP) is a core task within subject-driven video generation. However, existing methods suffer from two key limitations. First, most approaches focusing on inter-subject personalization still struggle to strike a ba...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-21T04:12:06+00:00","status":"fallback"},"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.18198v1","title":"Three-Body Scattering for Generative Modeling","abstract":"Modern generative models typically rely on an adversarial critic, a prescribed noise-to-data path, or an autoregressive factorization. Instead, we show that a proper distributional energy can induce sample-level motion and provide direct regression supervision for a one-step generator. Three-Body Scattering Modeling (TBSM) for generation turns the energy distance into a constant-size per-projectile interaction: each projectile is attracted toward one real source and repelled from one independently generated source. Conditioned on the projectile and its condition, its expectation equals the $2$-Wasserstein gradient-flow velocity of $\\frac12D_E^2(P_θ,Q)$. A batch of $B$ frozen-target events yields $O(B)$ sample-level losses, each using one reference for its condition instead of the minibatch-wide all-pairs field used by methods such as Drifting Models. Tracking this conditional expectation online can reduce field noise. Using scattering in frozen image features, TBSM trains one-step generators on ImageNet-256, achieving FID${}=2.23$ with pixel-space PixelDiT-XL and FID${}=1.63$ with latent-space DiT-XL at NFE${}=1$. We provide a design map relating diffusion-related supervision, Drift-like dynamics, and GAN-like objectives. These results establish tracked scattering as a route to high-dimensional one-step generation. Code: https://github.com/sp12138/TBSM.","authors":["Peng Sun","Zhenglin Cheng","Deyuan Liu","Jun Xie","Xinyi Shang","Tao Lin"],"published":"2026-07-20T17:38:12Z","updated":"2026-07-20T17:38:12Z","abstract_url":"https://arxiv.org/abs/2607.18198v1","html_url":"https://arxiv.org/html/2607.18198v1","pdf_url":"https://arxiv.org/pdf/2607.18198v1.pdf","matched_keywords":["diffusion"],"source_used":"html","source_text_chars":159801,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 diffusion 相关；摘要显示其主要贡献为：Modern generative models typically rely on an adversarial critic, a prescribed noise-to-data path, or an autoregressive factorization. Instead, we show that a proper distributional energy can induce sample-level motion and provide direct regression supervisio...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-21T04:12:06+00:00","status":"fallback"},"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.18153v1","title":"Robust Multimodal Dynamic Object Segmentation","abstract":"Dynamic object segmentation plays a critical role in many visual applications such as static scene reconstruction from dynamic videos. However, existing optical flow-based methods fail to ensure consistent static/dynamic segmentation along object boundaries, while 3D reconstruction-based approaches are highly sensitive to reconstruction errors. To address these limitations, we present a dynamic object segmentation framework that can generate both precise and complete dynamic masks by integrating multimodal cues including 2D point tracks, 3D reconstruction, and semantic information. We design a network combining Transformer architectures with feature clustering aggregation modules to perform static/dynamic classification of multimodal feature trajectories. It enables the model to adaptively determine which type of feature should dominate based on the characteristics of each scene, while also mitigating the impact of feature degradation. Additionally, we introduce a novel point-query-based SAM post-processing method capable of handling multiple objects within a single mask. Extensive experiments demonstrate that our approach achieves state-of-the-art performance in both dynamic object segmentation and static scene reconstruction tasks.","authors":["Zhe Xin","Hanzhi Chang","Penghui Huang","Yinian Mao","Guoquan Huang"],"published":"2026-07-20T16:51:48Z","updated":"2026-07-20T16:51:48Z","abstract_url":"https://arxiv.org/abs/2607.18153v1","html_url":"https://arxiv.org/html/2607.18153v1","pdf_url":"https://arxiv.org/pdf/2607.18153v1.pdf","matched_keywords":["video","3d","multimodal"],"source_used":"html","source_text_chars":44163,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, 3d, multimodal 相关；摘要显示其主要贡献为：Dynamic object segmentation plays a critical role in many visual applications such as static scene reconstruction from dynamic videos. However, existing optical flow-based methods fail to ensure consistent static/dynamic segmentation along object boundaries,...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-21T04:12:06+00:00","status":"fallback"},"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.18151v1","title":"Plenoptic Condensation: A Novel Approach to Generalized Scene Reconstruction","abstract":"We present a novel Generalized Scene Reconstruction (GSR) approach called Plenoptic Condensation (PCon). PCon uses a multi-stage reconstruction pipeline, initially converting images into \"soupy\" scene elements with low (representational) power, then adaptively condensing the \"soup\" into \"structured\" elements of higher power capable of efficiently representing, for example, sharp edges and smooth reflective surfaces. PCon scene models called Reality Models (Relms) enable spatially varying representational power, which is essential for high-fidelity rendering, measurement, and scene understanding. We showcase several in-the-wild PCon reconstructions captured with consumer phone cameras and drones. In one case called \"Damaged Fiat\", PCon is benchmarked against two state-of-the-art (SOTA) GSR methods: NeRO and RT-Splatting. Referring to Figure 1 below, PCon reconstructs the car hood more than twice as accurately as the SOTA methods. But more importantly, the local damage profile error for PCon is 35 um (0.035 mm), whereas the two other SOTA methods are essentially unable to measure the damage at all. Our project website is available at https://quidient.github.io/pcon-2026.html.","authors":["Brevin Tilmon","Alex DeJournett","John Leffingwell","Scott Ackerson"],"published":"2026-07-20T16:50:19Z","updated":"2026-07-20T16:50:19Z","abstract_url":"https://arxiv.org/abs/2607.18151v1","html_url":"https://arxiv.org/html/2607.18151v1","pdf_url":"https://arxiv.org/pdf/2607.18151v1.pdf","matched_keywords":["representation"],"source_used":"html","source_text_chars":53537,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 representation 相关；摘要显示其主要贡献为：We present a novel Generalized Scene Reconstruction (GSR) approach called Plenoptic Condensation (PCon). PCon uses a multi-stage reconstruction pipeline, initially converting images into \"soupy\" scene elements with low (representational) power, then adaptivel...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-21T04:12:06+00:00","status":"fallback"},"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.18150v1","title":"Lossless-INR: Lossless Volumetric Implicit Neural Representations","abstract":"Implicit neural representation (INR) methods provide continuous coordinate-to-value mappings and integrate naturally with direct volume rendering, making them attractive for representing volumetric data. However, existing INR-based approaches for volumetric data are inherently lossy, and even small reconstruction errors can propagate through rendering and downstream analysis. In this work, we explore Lossless-INR, a lossless INR framework for 3D scientific volumetric data based on bit-plane decomposition. By decomposing each voxel value into binary bit-planes, we reformulate reconstruction as per-bit binary classification, so that exact recovery reduces to predicting every bit correctly. To make this optimization tractable while keeping the representation compact, we combine an octree block-partitioning strategy that adaptively subdivides complex regions with a ternary feature-grid network whose grid entries are parameterized by a ternary set of values. Experiments on diverse volumetric datasets show that this design can achieve zero bit-error rate and bit-exact reconstruction, enabling faithful rendering and downstream analysis with a compact representation. The code is available at https://github.com/TouKaienn/Lossless-INR.","authors":["Kaiyuan Tang","Daniel Burke","Chaoli Wang"],"published":"2026-07-20T16:50:15Z","updated":"2026-07-20T16:50:15Z","abstract_url":"https://arxiv.org/abs/2607.18150v1","html_url":"https://arxiv.org/html/2607.18150v1","pdf_url":"https://arxiv.org/pdf/2607.18150v1.pdf","matched_keywords":["3d","representation"],"source_used":"html","source_text_chars":31394,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d, representation 相关；摘要显示其主要贡献为：Implicit neural representation (INR) methods provide continuous coordinate-to-value mappings and integrate naturally with direct volume rendering, making them attractive for representing volumetric data. However, existing INR-based approaches for volumetric d...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-21T04:12:06+00:00","status":"fallback"},"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.18142v1","title":"O-VAD: Industrial Video Anomaly Detection through Object-Centric Tracking and Reasoning","abstract":"Industrial Video Anomaly Detection (IVAD) aims to identify anomalous objects and events in an industrial process, which is crucial for modern manufacturing and quality control systems. Existing VLM-based anomaly reasoning methods are capable of detecting open-ended anomalies in general domains. However, their performance declines in industrial settings characterized by intricate object transformations, strict physics, and procedural constraints. To tackle the complexity of such interaction-intensive detection, we introduce a training-free agentic framework for anomaly detection free of domain-specific knowledge, emphasizing object state evolution like humans inspectors. It is designed to track spatial-temporal dynamics and underlying transformations of detected objects over time, and then reason over the object-wise temporal state trajectories to identify abnormal objects in grounded frames. Our method overcomes limitations of prior approaches that rely on retraining on normal clips or injecting domain knowledge as context for test-time inference. Extensive experiments on three IVAD datasets demonstrate that our method outperforms frontier VLMs, agentic frameworks, and traditional VAD methods fine-tuned on the respective datasets, while providing interpretable reports over anomaly processes and types.","authors":["Mei Yuan","Qi Long","Qifeng Wu","Zhenyang Li","Yizhou Zhao","Lei Wang","Yang Liu","Min Xu"],"published":"2026-07-20T16:36:00Z","updated":"2026-07-20T16:36:00Z","abstract_url":"https://arxiv.org/abs/2607.18142v1","html_url":"https://arxiv.org/html/2607.18142v1","pdf_url":"https://arxiv.org/pdf/2607.18142v1.pdf","matched_keywords":["video","agent"],"source_used":"html","source_text_chars":131977,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, agent 相关；摘要显示其主要贡献为：Industrial Video Anomaly Detection (IVAD) aims to identify anomalous objects and events in an industrial process, which is crucial for modern manufacturing and quality control systems. Existing VLM-based anomaly reasoning methods are capable of detecting open...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-21T04:12:06+00:00","status":"fallback"},"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.18116v1","title":"SGA: Plug&Play Geometric Verification for Educational Video Synthesis","abstract":"Recent work leverages Large Language Models (LLMs) to generate executable code for pedagogical animations using libraries such as Manim. However, ensuring spatial correctness and visual legibility remains challenging, as existing frameworks emphasize pedagogical content while overlooking geometric occlusions. We propose the Symbolic Geometric Agent (SGA), a plug-and-play module for code-centric animation pipelines that intercepts LLM-generated code, performs partial execution to extract symbolic scene graphs, and applies targeted refinement when spatial conflicts are detected. We further introduce the Manim Visual Quality Score (MVQS), a deterministic rendering-free proxy for spatial integrity. Experiments on the MMMC-Code benchmark across four LLM backbones and two agentic pipelines show that SGA achieves a peak MVQS of 73.11 (Code2Video + GPT-5.1), corresponding to a 16.1% relative improvement over the raw baseline, and improves MVQS in 7 of 8 backbone x pipeline configurations.","authors":["Lopez Jhon","Hinojosa Carlos","Ghanem Bernard"],"published":"2026-07-20T16:11:19Z","updated":"2026-07-20T16:11:19Z","abstract_url":"https://arxiv.org/abs/2607.18116v1","html_url":"https://arxiv.org/html/2607.18116v1","pdf_url":"https://arxiv.org/pdf/2607.18116v1.pdf","matched_keywords":["video","agent"],"source_used":"html","source_text_chars":62878,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, agent 相关；摘要显示其主要贡献为：Recent work leverages Large Language Models (LLMs) to generate executable code for pedagogical animations using libraries such as Manim. However, ensuring spatial correctness and visual legibility remains challenging, as existing frameworks emphasize pedagogi...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-21T04:12:06+00:00","status":"fallback"},"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.18109v1","title":"SpEmoC: A Balanced Speaker-Segment Multimodal Emotion Benchmark","abstract":"Understanding human emotions in spoken conversations is a key challenge in affective computing, with applications in empathetic AI, human computer interaction, and mental health monitoring. However, existing datasets vary in scale, emotion distribution, modality alignment, and data partitioning strategies, which can influence reliable cross-dataset generalization and minority-emotion modeling. We introduce SpEmoC a Speaking segment Emotion for Conversations comprising 306,544 raw clips from 3,100 English language movies and TV series. From these, 30,000 high quality, class balanced clips are curated, featuring synchronized visual, audio, and textual modalities annotated for seven emotions through a hybrid pipeline that integrates pretrained models with human validation. SpEmoC uses strict movie- and series-level splits to prevent content overlap between split sets, allowing more reliable evaluation of model generalization. The dataset also maintains a near-balanced distribution across seven emotions, including minority classes such as Fear and Disgust, which supports more balanced learning across categories. Extensive experiments, including in-domain benchmarking, cross-dataset transfer, low-data training, class-imbalance analysis, and modality transfer show that balanced data and careful splitting lead to more stable performance across emotions when models are evaluated on other datasets. These results highlight the importance of dataset design for robust and transferable multimodal emotion recognition.","authors":["Sania Bano","Shahzad Ahmad","Santosh Kumar Vipparthi","Sukalpa Chanda","Subrahmanyam Murala"],"published":"2026-07-20T16:08:24Z","updated":"2026-07-20T16:08:24Z","abstract_url":"https://arxiv.org/abs/2607.18109v1","html_url":"https://arxiv.org/html/2607.18109v1","pdf_url":"https://arxiv.org/pdf/2607.18109v1.pdf","matched_keywords":["multimodal"],"source_used":"html","source_text_chars":44840,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 multimodal 相关；摘要显示其主要贡献为：Understanding human emotions in spoken conversations is a key challenge in affective computing, with applications in empathetic AI, human computer interaction, and mental health monitoring. However, existing datasets vary in scale, emotion distribution, modal...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-21T04:12:06+00:00","status":"fallback"},"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.18080v1","title":"Sparse Evidence Can Suffice: Agentic Evidence Seeking for Multimodal Video Misinformation Detection","abstract":"Multimodal video misinformation detection is commonly formulated as a holistic video-understanding task, where the entire video and its associated content are processed and judged in a single pass. However, real-world misinformation often exhibits a sparse and compositional evidence structure: a reliable decision may depend on only a few coupled clues, while most video content contributes limited additional information. Exhaustive multimodal reasoning may therefore introduce substantial redundancy and obscure decisive evidence. This motivates decoupling evidence acquisition from verification: first identifying sparse, decision-relevant clues and then judging veracity based on the acquired evidence. Accordingly, we propose SIEVE, a framework for Sparse Interactive Evidence Verification via Extraction in multimodal video misinformation detection. An evidence-seeking agent actively explores the available multimodal evidence and constructs a compact evidence package, which is then used by a verifier to determine veracity. The agent is trained with supervised evidence-seeking trajectories and an evidence-aware reinforcement learning objective that promotes informative evidence acquisition while discouraging unnecessary or invalid interactions. Experiments on multiple video misinformation benchmarks show that SIEVE consistently outperforms the evaluated baselines and supports reliable verification using compact evidence packages. Moreover, the resulting acquisition process provides an explicit and inspectable evidence trail, improving the transparency and groundedness of multimodal misinformation detection.","authors":["Haochen Zhao","Yongxiu Xu","Xinkui Lin","Dong Xie","Jiarui Lu","Yuqi Qian","Yubin Wang","Hongbo Xu","Gaopeng Gou"],"published":"2026-07-20T15:48:31Z","updated":"2026-07-20T15:48:31Z","abstract_url":"https://arxiv.org/abs/2607.18080v1","html_url":"https://arxiv.org/html/2607.18080v1","pdf_url":"https://arxiv.org/pdf/2607.18080v1.pdf","matched_keywords":["video","agent","multimodal"],"source_used":"html","source_text_chars":71542,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, agent, multimodal 相关；摘要显示其主要贡献为：Multimodal video misinformation detection is commonly formulated as a holistic video-understanding task, where the entire video and its associated content are processed and judged in a single pass. However, real-world misinformation often exhibits a sparse an...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-21T04:12:07+00:00","status":"fallback"},"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.18078v1","title":"VGOcc: Learning Visual-Geometric Gaussians for Vision-Centric 3D Driving Occupancy Prediction","abstract":"Vision-only occupancy prediction requires recovering a semantic 3D occupancy field from calibrated surround-view images, where each view provides observations with ambiguous depth along camera rays. Existing methods have progressed from dense structured representations to sparse Gaussian primitives, improving the efficiency of 3D scene representation. However, Gaussian learning still relies primarily on image domain features, which provide limited explicit geometric information for volumetric reasoning. Our key observation is that effective Gaussian occupancy modeling requires not only sparse primitives, but also richer geometric and semantic learning cues. In this paper, we propose VGOcc, which learns visual and geometric cues from foundation models for Gaussian modeling. VGOcc incorporates these cues into primitive initialization and refinement, yielding a representation termed Visual-Geometric Gaussians tailored to semantic occupancy prediction. Specifically, we propose Visual-Geometric Gaussian Birth to form spatially balanced Gaussian centers from ray depth hypotheses, while visual semantic features initialize primitive attributes. Next, we design Pose-Aware Feature Learning to combine foundation tokens with camera embeddings and calibrated ray information. Features from neighboring views are then aggregated at projected 3D locations for each Gaussian refinement stage. Finally, Gaussian decoder refines birth Gaussians with pose-aware features and renders them into semantic occupancy. Experiments on nuScenes demonstrate that VGOcc achieves state-of-the-art performance in vision-only 3D occupancy prediction. Codes will be available at https://github.com/JHLin42in/VGOcc.","authors":["Junhong Lin","Xianda Guo","Kangli Wang","Yuqi Ye","Xiaoyu Liang","Yanlun Peng","Wei Gao"],"published":"2026-07-20T15:46:30Z","updated":"2026-07-20T15:46:30Z","abstract_url":"https://arxiv.org/abs/2607.18078v1","html_url":"https://arxiv.org/html/2607.18078v1","pdf_url":"https://arxiv.org/pdf/2607.18078v1.pdf","matched_keywords":["3d","representation"],"source_used":"html","source_text_chars":50048,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d, representation 相关；摘要显示其主要贡献为：Vision-only occupancy prediction requires recovering a semantic 3D occupancy field from calibrated surround-view images, where each view provides observations with ambiguous depth along camera rays. Existing methods have progressed from dense structured repre...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-21T04:12:07+00:00","status":"fallback"},"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.18067v1","title":"QIRF Quantum-Inspired Non-Orthogonal Function-Space Compression for 3D Gaussian Splatting","abstract":"3D Gaussian Splatting (3DGS) achieves high-quality real-time rendering by representing a scene with a large collection of anisotropic Gaussian primitives. However, complex scenes often require millions of Gaussians, resulting in substantial storage and rendering costs. Existing compression methods mainly reduce redundancy through primitive-wise pruning, attribute quantization, clustering, or neural coding, while redundancy caused by strongly overlapping and non-orthogonal Gaussian basis functions remains largely unexplored. We present QIRF, a quantum-inspired non-orthogonal function-space compression method for 3D Gaussian Splatting. QIRF models neighboring Gaussian primitives as a local non-orthogonal basis and formulates primitive reduction as a subspace-aware selection problem. Specifically, an analytic Gaussian overlap matrix and a radiance-response density matrix are constructed to characterize functional redundancy and rendering relevance. Generalized eigendecomposition is then used to identify the dominant local subspace and select representative Gaussian primitives. An RRDM-based response model and detail-aware safeguarding further preserve visually important high-frequency structures under aggressive pruning. Experiments on 13 scenes from Mip-NeRF 360, Tanks and Temples, and Deep Blending show that QIRF reduces the Gaussian count and raw PLY storage by 71.7 percent on average, corresponding to approximately 3.54 times compression, while maintaining reconstruction quality comparable to 3DGS and achieving a marginal average PSNR improvement of 0.10 dB. QIRF also improves the average rendering speed over 3DGS by 34.3 percent. These results suggest that non-orthogonal function-space redundancy is an important yet underexplored source of representational redundancy in explicit Gaussian radiance fields.","authors":["Shizeng Jiang","Hao Zhang","Xuerui Ma","Ying Hu","Tao Zhang"],"published":"2026-07-20T15:34:45Z","updated":"2026-07-20T15:34:45Z","abstract_url":"https://arxiv.org/abs/2607.18067v1","html_url":"https://arxiv.org/html/2607.18067v1","pdf_url":"https://arxiv.org/pdf/2607.18067v1.pdf","matched_keywords":["3d","representation"],"source_used":"html","source_text_chars":44702,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d, representation 相关；摘要显示其主要贡献为：3D Gaussian Splatting (3DGS) achieves high-quality real-time rendering by representing a scene with a large collection of anisotropic Gaussian primitives. However, complex scenes often require millions of Gaussians, resulting in substantial storage and render...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-21T04:12:07+00:00","status":"fallback"},"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.18062v1","title":"UniETP: Unifying Environments for Generalizable Embodied Task Planning","abstract":"This paper focuses on the problem of Embodied Task Planning, where an agent is required to execute a sequence of atomic actions within an interactive environment to complete a user-specified task. Though a variety of simulators and datasets have previously been built for this task, these efforts are largely isolated, with each using its own observation format, action type, and task domain. This fragmentation complicates comprehensive model evaluation and hinders the scalability of training data. As an effort towards generalizable embodied planning, we propose UniETP, a unified interface integrating four commonly-used simulators (AI2-THOR, VirtualHome, Habitat, BEHAVIOR). UniETP is characterized by both standardization and diversity. On one hand, it formalizes all the simulators into a consistent observation and action space, and builds an evaluation system to support complicated task goal. On the other hand, it enhances task diversity and complexity across dimensions like task logic, instance grounding, and instruction understanding, constructing a new dataset with varied levels of difficulty in an automatic manner. Extensive experiments on the proposed benchmark are conducted to evaluate the embodied planning capabilities of recent models and analyze the performance bottlenecks. Codes and data will be available at https://github.com/woyut/UniETP .","authors":["Peiran Xu","Jiaqi Zheng","Ziyou Wang","Yadong Mu"],"published":"2026-07-20T15:30:16Z","updated":"2026-07-20T15:30:16Z","abstract_url":"https://arxiv.org/abs/2607.18062v1","html_url":"https://arxiv.org/html/2607.18062v1","pdf_url":"https://arxiv.org/pdf/2607.18062v1.pdf","matched_keywords":["agent","instance"],"source_used":"html","source_text_chars":61544,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 agent, instance 相关；摘要显示其主要贡献为：This paper focuses on the problem of Embodied Task Planning, where an agent is required to execute a sequence of atomic actions within an interactive environment to complete a user-specified task. Though a variety of simulators and datasets have previously be...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-21T04:12:07+00:00","status":"fallback"},"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.18040v1","title":"When 2D Cues Fail: Improving Image Manipulation Localization with Reliable 3D Geometry","abstract":"Existing image manipulation localization (IML) methods rely heavily on 2D forensic cues, such as low-level artifacts, noise traces, and semantic inconsistencies in the manipulated image. While effective in many cases, these cues become much less discriminative when manipulated regions are well blended with their surrounding context in appearance. In such cases, a manipulated region may remain locally appearance-consistent, but still violate the geometric structure of the surrounding scene. This limitation motivates us to go beyond purely 2D evidence and introduce geometric reasoning into IML. To this end, we leverage monocular reconstruction to obtain auxiliary geometric cues, including depth and surface normals. However, a key challenge lies in the fact that reconstructed geometry on manipulated images is inherently noisy and cannot be used naively. Rather than treating depth and normals as direct evidence, we estimate their reliability and exploit them selectively for localization. Based on this principle, we design a geometry-aware framework (GFrame) that fuses reliable geometric cues with RGB features and propagates them across scales to improve fine-grained localization. Extensive experiments show that the proposed method achieves excellent performance under limited budget constraints. These results indicate that reliable 3D geometry provides complementary forensic evidence beyond traditional 2D cues for IML. Related code will be released.","authors":["Guofeng Yu","Zhiqing Guo","Dan Ma","Gaobo Yang"],"published":"2026-07-20T15:08:46Z","updated":"2026-07-20T15:08:46Z","abstract_url":"https://arxiv.org/abs/2607.18040v1","html_url":"https://arxiv.org/html/2607.18040v1","pdf_url":"https://arxiv.org/pdf/2607.18040v1.pdf","matched_keywords":["3d"],"source_used":"html","source_text_chars":48516,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d 相关；摘要显示其主要贡献为：Existing image manipulation localization (IML) methods rely heavily on 2D forensic cues, such as low-level artifacts, noise traces, and semantic inconsistencies in the manipulated image. While effective in many cases, these cues become much less discriminativ...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-21T04:12:07+00:00","status":"fallback"},"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.18033v1","title":"Benchmarking NACTI Species Recognition in Long-Tailed Regimes","abstract":"As with most ``in the wild'' collections of the natural world, the North America Camera Trap Images (NACTI) dataset exhibits long-tailed class imbalance, with the largest class covering over 50% of its 3.7M images. Building on the PyTorch Wildlife model, we systematically evaluate Long-Tail Recognition (LTR) methodologies to benchmark species recognition performance, including specialised loss functions and LTR-sensitive regularisation. Our optimised configuration achieves state-of-the-art 99.40% Top-1 accuracy on the NACTI test split, significantly outperforming standard baselines and previously reported top performances. To assess robustness under domain shifts (e.g., night-time captures, occlusion, motion-blur), we extend our evaluation across three independent reduced-bias test sets (including ENA-Detection, Caltech Camera Traps and Missouri Camera Traps). Across these out-of-distribution (OOD) evaluations, our LTR-enhanced model consistently demonstrates substantially stronger generalisation capabilities compared to standard cross-entropy approaches. However, qualitative and quantitative analyses underline that current LTR optimisations cannot fully overcome representational bottlenecks, resulting in catastrophic predictive breakdown for rare `Tail' classes under severe domain shift. For maximum reproducibility, all dataset splits, key code, and network weights are published with this paper at https://github.com/ZehuaLiuY/Species-Classification.","authors":["Zehua Liu","Tilo Burghardt"],"published":"2026-07-20T15:00:53Z","updated":"2026-07-20T15:00:53Z","abstract_url":"https://arxiv.org/abs/2607.18033v1","html_url":"https://arxiv.org/html/2607.18033v1","pdf_url":"https://arxiv.org/pdf/2607.18033v1.pdf","matched_keywords":["representation"],"source_used":"html","source_text_chars":47428,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 representation 相关；摘要显示其主要贡献为：As with most ``in the wild'' collections of the natural world, the North America Camera Trap Images (NACTI) dataset exhibits long-tailed class imbalance, with the largest class covering over 50% of its 3.7M images. Building on the PyTorch Wildlife model, we s...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-21T04:12:07+00:00","status":"fallback"},"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.18014v1","title":"SAMRI-3D: Adapting SAM2 for 3D MRI Segmentation with Global Volume Tokens","abstract":"Foundation models such as Segment Anything Model 2 (SAM2) have transformed natural-image and video segmentation, and recent work has begun adapting them to medical imaging. These adaptations, however, are largely general-purpose models that treat MRI as one modality among many; large-scale, MRI-specific modelling and benchmarking remain limited, even though MRI's low soft-tissue contrast leaves many boundaries effectively invisible on individual slices. We present SAMRI-3D, a benchmark and method for 3D MRI segmentation with SAM2. The SAMRI-3D benchmark is the largest MRI-only evaluation to date - 10,392 volumes from 34 datasets (27 public, 7 in-house) spanning 12 anatomical domains and 10+ sequences, with explicit seen/unseen splits. Freezing the image encoder and fine-tuning only the lightweight decoder and memory modules raises mean Dice from 0.58 (zero-shot SAM2) to 0.76, surpassing recent SAM-based medical models (SAMed-2 0.69, Medical-SAM2 0.49, SAM-Med3D 0.37) with strong statistical significance. To target invisible boundaries, we introduce Global Volume Tokens (GVT): persistent memory tokens trained with a Truncated Signed Distance Field (TSDF) reconstruction objective that is discarded at inference (zero added cost). This full model, SAMRI-3D, attains the best accuracy (0.78) and lowest variance across all 34 datasets and, uniquely, shows no drop on 8 held-out datasets (0.79 unseen vs. 0.78 seen); per-sequence analysis confirms the TSDF objective helps most where per-slice contrast is weakest. We will release the benchmark, code, and models in this paper.","authors":["Zhao Wang","Wei Dai","Hongfu Sun","Craig Engstrom","Shekhar S. Chandra"],"published":"2026-07-20T14:48:11Z","updated":"2026-07-20T14:48:11Z","abstract_url":"https://arxiv.org/abs/2607.18014v1","html_url":"https://arxiv.org/html/2607.18014v1","pdf_url":"https://arxiv.org/pdf/2607.18014v1.pdf","matched_keywords":["video","3d"],"source_used":"html","source_text_chars":141455,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, 3d 相关；摘要显示其主要贡献为：Foundation models such as Segment Anything Model 2 (SAM2) have transformed natural-image and video segmentation, and recent work has begun adapting them to medical imaging. These adaptations, however, are largely general-purpose models that treat MRI as one m...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-21T04:12:07+00:00","status":"fallback"},"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17999v1","title":"Do Maps Still Matter for Machines: Revisiting the Role of Choropleth Maps in Foundation Model Spatial Understanding","abstract":"Spatial understanding is crucial for foundation models (FMs), and maps have long helped humans organize and reason about geographic information. This study examines whether choropleth maps remain useful for machine spatial understanding when models can directly process structured geodata. We introduce ChoroplethMap-Bench, a controlled benchmark containing 2,400 synthetic choropleth maps, corresponding GeoJSON data, and 12,000 questions across five cognitive dimensions: Identify, Spatial Recognition, Compare, Rank, and Delineate. We evaluate 22 open-source and proprietary models under three input conditions: Data Only, Map Only, and Data + Map. The results show that maps substantially improve spatial reasoning, especially when combined with symbolic data and for tasks requiring higher-level understanding of spatial patterns. We further analyze the effects of map type, color hue, and spatial structure, as well as prompting strategies, language, geographic context, decoding settings, classification methods, and response stability. Overall, the Data + Map condition achieves the strongest performance, demonstrating that maps remain valuable external representations for foundation model spatial reasoning.","authors":["Zhiwei Wei","Yonghe Sun","Zhenjia Liu","Wenjia Xu","Chao He","Weihua Dong","Chunbo Liu","Hua Liao"],"published":"2026-07-20T14:32:10Z","updated":"2026-07-20T14:32:10Z","abstract_url":"https://arxiv.org/abs/2607.17999v1","html_url":"https://arxiv.org/html/2607.17999v1","pdf_url":"https://arxiv.org/pdf/2607.17999v1.pdf","matched_keywords":["representation"],"source_used":"html","source_text_chars":100970,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 representation 相关；摘要显示其主要贡献为：Spatial understanding is crucial for foundation models (FMs), and maps have long helped humans organize and reason about geographic information. This study examines whether choropleth maps remain useful for machine spatial understanding when models can direct...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-21T04:12:07+00:00","status":"fallback"},"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17994v1","title":"HAS: Highlight-guided Attention Steering for Multimodal LLM Video Summarization","abstract":"Video understanding has become more and more important with the growth of Artificial Intelligence (AI) for video generation. Recently, Multimodal Large Language Model(M-LLM) has shown its capability in video understanding. Video summarization, a specific domain of video understanding, has proven its importance for efficient navigation and retrieval. Both video understanding and video summarization require a good selection of key frames in a video. Current video summarization methods heavily focus on the selected key frames and correlated segment captions. However, existing approaches overlook the perspective of treating the importance of the frames globally. We argue that using discrete selected frames for summarization will not only reduce the understanding coherence, but also lost important information in the video, as well as wasting the original capacity of the MLLMs. In this paper, we propose HAS, a Highlight-guided Attention Steering method for video summarization. We consider a challenging but practical setting where the video given to MLLMs for summarize should be continuous but with highlight guidance. HAS mainly consists of two parts: The first part is to find a continuous frame-level highlight distribution for the video globally. The second part is to apply the highlight distribution as an attention steering vector for the MLLM, targeting a better understanding of the video, and thus during the model inference time, putting more attention on the highlighted frames, while avoiding lost entire information on less highlighted frames through putting less attention instead of forgetting them. We evaluated HAS on a variety of benchmarks, and it has shown convincing performance in video summarization.","authors":["Rui Chu","Yingjie Lao"],"published":"2026-07-20T14:27:06Z","updated":"2026-07-20T14:27:06Z","abstract_url":"https://arxiv.org/abs/2607.17994v1","html_url":"https://arxiv.org/html/2607.17994v1","pdf_url":"https://arxiv.org/pdf/2607.17994v1.pdf","matched_keywords":["video","retrieval","multimodal"],"source_used":"html","source_text_chars":43458,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, retrieval, multimodal 相关；摘要显示其主要贡献为：Video understanding has become more and more important with the growth of Artificial Intelligence (AI) for video generation. Recently, Multimodal Large Language Model(M-LLM) has shown its capability in video understanding. Video summarization, a specific doma...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-21T04:12:07+00:00","status":"fallback"},"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17985v1","title":"Keyframe-Anchored Identity Preservation for Sequential-Action Video Generation","abstract":"Identity-preserving text-to-video generation aims to synthesize a video that accurately follows a textual description while maintaining the recognizability of a user-specified subject throughout. The IPVG26 challenge extends this framework from a single holistic prompt to a temporally structured specification. The model additionally receives a sequence of timestamped action captions and must render the subject performing these actions in the specified order. This temporal structure presents a challenge not encountered in previous identity-preserving generation tasks, as the subject must continuously perform a scripted sequence of distinct actions while maintaining a consistent identity. However, end-to-end video generators are prone to appearance drift as motion accumulates and the depicted actions change. We address this challenge with a training-free, three-stage pipeline framework. An action-aware prompt polishment stage first rewrites the inputs into image-generation prompts that specify the terminal state of each action. An identity-preserving generation stage then produces the keyframe sequence by conditioning each frame jointly on the reference identity and its predecessor, thereby decoupling time-invariant appearance from time-varying pose. Finally, an identity-aware inference enhancement stage synthesizes the intermediate segments using multi-reference guidance and identity-driven noise searching, both of which reinforce identity fidelity during sampling. Our method ranked third on the official Track 2 leaderboard, demonstrating competitive performance and strong generality.","authors":["Zhenjie Liu","Binyan Chen","Hao Chen","Tong Pan","Shangfei Wang"],"published":"2026-07-20T14:16:49Z","updated":"2026-07-20T14:16:49Z","abstract_url":"https://arxiv.org/abs/2607.17985v1","html_url":"https://arxiv.org/html/2607.17985v1","pdf_url":"https://arxiv.org/pdf/2607.17985v1.pdf","matched_keywords":["video"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17967v1","title":"Fine-Detail Monocular Geometry Estimation with Self-Guided Sparse Volumetric Refinement","abstract":"Monocular geometry estimation has recently achieved impressive performance across diverse scenes. However, state-of-the-art models still face notable distortion in local 3D structure, especially in fine details, like thin structures and small objects. We attribute this limitation to an architectural mismatch: most current models decode 3D geometry within a 2D parameterization, where feature interactions are governed by image-plane proximity rather than true 3D spatial relationships. This inadvertently mixes features from geometrically distant surfaces, resulting in over-smoothed geometry particularly around thin or elongated structure. In this paper, we propose a fine-detail monocular geometry estimation with Self-Guided Sparse 3D Refinement (SSR) that lifts monocular geometry modeling from 2D image space to 3D space for high-fidelity metric-scale point maps. Our model lifts the coarse point map from a foundation base model onto a sparse voxel shell and refines it via SSR. The SSR employs sparse convolutions that aggregate features based on 3D spatial locality, avoiding feature mixing across depth discontinuities. Extensive experiments on diverse datasets demonstrate that our method significantly outperforms existing approaches in recovering fine detailed 3D geometry across both quantitative metrics and qualitative visualizations.","authors":["Lingyu Kong","Ruicheng Li","Ruicheng Wang","Sicheng Xu","Chengtang Yao","Jianfeng Xiang","Jiaolong Yang"],"published":"2026-07-20T14:07:32Z","updated":"2026-07-20T14:07:32Z","abstract_url":"https://arxiv.org/abs/2607.17967v1","html_url":"https://arxiv.org/html/2607.17967v1","pdf_url":"https://arxiv.org/pdf/2607.17967v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17965v1","title":"Exploration Matters for Escaping the Blur Trap in 3D Gaussian Splatting","abstract":"3D Gaussian Splatting (3DGS) employs Gaussian primitives for explicit scene representation, facilitating real-time, high-fidelity reconstruction and novel view synthesis of complex scenes. However, the explicit modeling inherent in 3DGS introduces a gradient bias during optimization, rendering its non-convex optimization process highly susceptible to convergence toward local suboptimal solutions. This constitutes a fundamental limitation in 3DGS optimization, which we term the Blur Trap. To address this limitation, we integrate simple explicit exploration into the 3DGS optimization framework. First, through rigorous mathematical analysis of the 3DGS optimization formulation, we identify the underlying optimization bias responsible for the Blur Trap and categorize it into two distinct subtypes: the Far-Side Blur Trap and the Near-Side Blur Trap. Subsequently, we propose two highly straightforward exploration strategies (Random Seeding and Random Splitting) to mitigate the far-side and near-side blur traps, respectively. Experimental validation demonstrates that the incorporation of these exploration operators effectively and complementarily overcome the Blur Trap, achieving high-quality rendering performance across multiple datasets. Project page: https://chengbo-wang.github.io/ExploreGS/","authors":["Chengbo Wang","Guozheng Ma","Jinhong Wu","Tie Ji","Yizhen Lao"],"published":"2026-07-20T14:05:54Z","updated":"2026-07-20T14:05:54Z","abstract_url":"https://arxiv.org/abs/2607.17965v1","html_url":"https://arxiv.org/html/2607.17965v1","pdf_url":"https://arxiv.org/pdf/2607.17965v1.pdf","matched_keywords":["3d","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17938v1","title":"MuViSeg: Multi-View Segment Correspondences from Dense Geometry Priors","abstract":"Classical image correspondence is solved at the level of sparse keypoints or dense pixels, but the systems that consume these matches - object-level mapping, topological navigation, scene-graph maintenance - reason about whole objects. Recent work narrows this gap by matchng directly at the level of instance segments: a class-agnostic segmenter partitions each image, and per-segment descriptors are obtained by pooling features from large 3D foundation models over the masks. We build on this segment-level matching paradigm and propose three learned matching heads: a LightGlue-style attention head with DoubleSoftmax scoring on frozen MASt3R descriptors; a DPT-style multi-scale fusion module that exposes layered spatial detail from the VGGT foundation model before pooling; and - as our main contribution - a multi-view extension that performs joint self-attention over segments drawn from several views at once, recovering transitive correspondences that strictly pairwise matchers cannot reach. Under a stratified zero-shot protocol on Replica and Virtual KITTI 2 with controlled viewpoint baselines from 0 deg to 180 deg, the LightGlue-style head improves over a parameter-free Sinkhorn matcher on the same MASt3R backbone by +4.85 AUPRC on Replica and +25.9 AUPRC on Virtual KITTI 2. Dropped into the RoboHop topological navigation pipeline on the Habitat-Matterport 3D (HM3D) Instance Image Navigation benchmark without retraining, our multi-view variant raises success rate from 50% to 70%, and our LightGlue-style head raises SPL from 45.7 to 59.1.","authors":["Denis Fatykhoph","Timur Akhtyamov","Konstantin Pakulev","German Devchich","Gonzalo Ferrer"],"published":"2026-07-20T13:35:48Z","updated":"2026-07-20T13:35:48Z","abstract_url":"https://arxiv.org/abs/2607.17938v1","html_url":"https://arxiv.org/html/2607.17938v1","pdf_url":"https://arxiv.org/pdf/2607.17938v1.pdf","matched_keywords":["3d","instance"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17916v1","title":"Packet-Loss Robust 3D Gaussian Compression via Atomic Packaging and GNN-based Error Concealment","abstract":"3D Gaussian Splatting (3DGS) and recent compression schemes such as HAC++ enable high-fidelity real-time neural rendering, but their bitstreams are fragile under packet loss during network streaming. Existing compression methods often separate correlated anchor attributes into independent streams, so losing one packet can create attribute-inconsistent broken anchors and severe rendering artifacts. We propose a packet-loss robust 3DGS transmission and error concealment framework. On the encoder side, anchor-level atomic packaging jointly encapsulates all attributes of each anchor, converting corrupted-attribute failures into clean missing-anchor erasures. Stratified random grouping further disperses packet losses across the spatial domain to avoid large contiguous voids. On the decoder side, we formulate recovery as prior-aware attribute inpainting. A Context-Aware Residual Interpolation (CARI) branch uses hash-grid prior predictions and neighboring residuals to build a robust baseline, while a lightweight two-layer graph neural network with cross-attention over hash-grid priors refines high-frequency attribute residuals. Attribute-wise confidence control falls back to interpolation when learned predictions are unreliable. Experiments under 20 percent random packet loss on BungeeNeRF, Mip-NeRF 360, and Tanks and Temples show that the proposed method substantially improves over no-concealment transmission and limits average PSNR degradation to about 3 dB relative to the lossless HAC++ reference.","authors":["Yuxuan Tao","Xuerui Ma","Hao Zhang","Chunhua Peng"],"published":"2026-07-20T13:13:38Z","updated":"2026-07-20T13:13:38Z","abstract_url":"https://arxiv.org/abs/2607.17916v1","html_url":"https://arxiv.org/html/2607.17916v1","pdf_url":"https://arxiv.org/pdf/2607.17916v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17896v1","title":"Locality-Aware Density Control for Efficient Gaussian-based Image Representation","abstract":"2D Gaussian Splatting is an attractive direction for image representation due to its explicit formulation, fast rasterization, and favorable decoding efficiency. The representation quality of this paradigm depends on the proper allocation of Gaussian capacity to the demanding regions. However, existing methods fail to allocate Gaussian capacity efficiently during optimization: under-reconstructed content is often refined in a fragmented pixel-wise manner, while neighboring optimized Gaussians with similar attributes are redundantly retained. This inefficiency motivates the need for a density control framework that jointly addresses insufficient allocation in under-reconstructed regions and redundant allocation in over-reconstructed regions. Our key insight is that this framework should exploit two complementary forms of locality: the local continuity of reconstruction errors in image space for improved Gaussian allocation, and the local similarity of neighboring Gaussians in Gaussian space for redundant elimination. Based on this insight, we propose Locality-Aware Density Control (LocoADC), a plug-and-play framework that improves Gaussian capacity utilization through Region-wise Gaussian Densification (RGD) and Similarity-Driven Gaussian Merging (SDGM) strategies, together with a local color consistency constraint for more reliable merging. Extensive experiments on diverse datasets show that LocoADC consistently improves multiple baselines by enabling more effective local Gaussian allocation, including a 2.93 dB PSNR gain over GI on the CLIC dataset under the same 30k Gaussian budget. Code is available at: \\textit{https://github.com/ChenJiaCong-1005/LocoADC}.","authors":["Jiacong Chen","Qingyu Mao","Xiandong Meng","Shuai Liu","Chao Li","Fanyang Meng","Youneng Bao","Yongsheng Liang"],"published":"2026-07-20T12:44:12Z","updated":"2026-07-20T12:44:12Z","abstract_url":"https://arxiv.org/abs/2607.17896v1","html_url":"https://arxiv.org/html/2607.17896v1","pdf_url":"https://arxiv.org/pdf/2607.17896v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17849v1","title":"AlphaOracle: Oracle bone script decipherment via human-workflow-inspired deep learning","abstract":"Approximately 3,000 of the 4,500 oracle bone script (OBS) characters remain undeciphered due to fragmentary inscriptions and sparse evidence. Current AI approaches fail to replicate expert workflows that integrate form analysis, contextual semantics, and philological reasoning. We introduce AlphaOracle, a human-workflow-inspired framework that systematizes OBS decipherment using the largest digitized corpus to date. Its multi-stage pipeline comprises: (i) rubbing parsing; (ii) radical-based morphological analysis with diachronic modeling; (iii) contextual retrieval with semantic alignment; and (iv) philological validation against classical sources. Each stage generates explicit, confidence-weighted evidence chains, culminating in interpretable reports for scholarly verification. Across multiple test characters, AlphaOracle's readings strongly agreed with expert interpretations. In a study of 86 domain specialists, it reduced analysis time by 64% and 79% of participants rated it highly useful. Notably, AlphaOracle resolves the character \"Lao\" as a toponymic or clan designation, offering concrete revisions to Shang administrative and social interpretations. These results suggest that computational methods aligned with philological practice can facilitate OBS research and provide a conceptual reference for studies of other undeciphered scripts.","authors":["Yuliang Liu","Haisu Guan","Pengjie Wang","Xinyu Wang","Jinpeng Wan","Kaile Zhang","Handong Zheng","Xingchen Liu","Zhebin Kuang","Huanxin Yang","Bang Li","Yongge Liu","Lianwen Jin","Xiang Bai"],"published":"2026-07-20T11:46:00Z","updated":"2026-07-20T11:46:00Z","abstract_url":"https://arxiv.org/abs/2607.17849v1","html_url":"https://arxiv.org/html/2607.17849v1","pdf_url":"https://arxiv.org/pdf/2607.17849v1.pdf","matched_keywords":["retrieval"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17842v1","title":"CaT-GS: Efficient 3DGS Rendering for Large Scale Scenes via Inter-frame Caching and Tile Scheduling","abstract":"Recent breakthroughs in 3D Gaussian Splatting (3DGS) have advanced neural rendering with high fidelity and speed. However, its performance degrades significantly in large-scale scenes due to the computational burden of tile-based rasterization. Existing optimization efforts either require costly scene re-training or focus on narrow aspects of the pipeline, overlooking critical inefficiencies in real-world deployments. Through a comprehensive analysis, we identify three primary sources of redundancy and low GPU utilization: redundant inter-frame pre-processing, viewpoint-based occlusion redundancy, and severe tile-level load imbalance. To address these issues, we propose CaT-GS, a novel and efficient 3DGS rendering pipeline. CaT-GS introduces a speculative multi-frame preprocessing method to eliminate redundant computations across consecutive frames, and an inter-frame caching mechanism to eliminate viewpoint redundant rendering stages. Furthermore, it refactors rasterization tasks with a dedicated kernel to mitigate tile load imbalance, significantly boosting GPU utilization. Extensive experiments demonstrate that CaT-GS achieves a speedup of up to 10 times over the original 3DGS and up to 70% over previous state-of-the-art methods, establishing a new benchmark for high-fidelity, real-time rendering of large-scale scenes.","authors":["Tingjia Zhang","Bo Chen","Shengzhong Liu","Fan Wu","Guihai Chen"],"published":"2026-07-20T11:33:51Z","updated":"2026-07-20T11:33:51Z","abstract_url":"https://arxiv.org/abs/2607.17842v1","html_url":"https://arxiv.org/html/2607.17842v1","pdf_url":"https://arxiv.org/pdf/2607.17842v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17833v1","title":"Consistent Feature Transport for Image Relighting","abstract":"Image relighting modifies illumination while preserving non-lighting content such as identity and geometry. Existing diffusion-based methods often suffer from unstable illumination changes or inconsistent content preservation under complex lighting, as they lack an explicit mechanism to learn feature transformations between images. We reformulate relighting as an illumination feature transport problem and introduce Consistent Feature Transport (CFT), a training principle that explicitly enforces illumination-consistent transport between source and target image distributions. Built upon rectified flow, CFT jointly models noise-to-image generation and illumination-consistent source-to-target transport through trajectory-level supervision. This dual-transport formulation encourages isolation of illumination-specific variations while preserving content-aligned features. To support complex lighting scenarios, we construct a large-scale portrait relighting dataset with diverse relighting effects. Experiments show consistent improvements over existing state-of-the-art relighting approaches and demonstrate that CFT can generalize to other editing tasks, including style transfer. Code is available at https://github.com/Dixin-Lab/CFT.","authors":["Bohan Zhang","Huanwei Liang","Yuhan He","Hongteng Xu","Quxiao Chao","Luoqi Liu","Dixin Luo","Ting Liu"],"published":"2026-07-20T11:25:36Z","updated":"2026-07-20T11:25:36Z","abstract_url":"https://arxiv.org/abs/2607.17833v1","html_url":"https://arxiv.org/html/2607.17833v1","pdf_url":"https://arxiv.org/pdf/2607.17833v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17810v1","title":"Vis2Reg: Visibility-Aware Landmark-Free Geometric 3D--2D Registration for Liver Laparoscopy","abstract":"Accurate 3D--2D liver registration, which aligns preoperative 3D models to partial, view-dependent intraoperative surface observations, is critical for AR-guided laparoscopic surgery but remains challenging due to severe occlusion, limited visibility, and the lack of 3D ground-truth supervision. Existing landmark-free approaches perform partial-to-complete geometric alignment, yet robust self-supervision under extreme partial visibility remains difficult. We propose Vis2Reg, a visibility-aware registration framework that explicitly constrains deformation using mask-consistent visible regions. We introduce a visibility-aware self-supervision that derives a visible-domain 3D supervision signal from intraoperative masks, enabled by differentiable point rasterization and mask-guided back-projection. This formulation improves robustness under severe occlusion while maintaining fully self-supervised learning. Vis2Reg combines a robust geometric rigid initialization module with an implicit neural deformation field for stable alignment. Vis2Reg achieves a Dice score of 92.6\\% and a Chamfer Distance of 1.43 mm on real intraoperative datasets, with 111 ms per-frame inference time, demonstrating both accuracy and practical efficiency.","authors":["Jiaming Feng","Xukun Zhang","Shahid Farid","Sharib Ali"],"published":"2026-07-20T10:56:52Z","updated":"2026-07-20T10:56:52Z","abstract_url":"https://arxiv.org/abs/2607.17810v1","html_url":"https://arxiv.org/html/2607.17810v1","pdf_url":"https://arxiv.org/pdf/2607.17810v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17803v1","title":"FF-ProCams: Feed-Forward Gaussian Splatting for Projector-Camera System","abstract":"Projector-camera (ProCams) systems achieve active scene perception and controllable appearance manipulation via structured illumination, serving as a core infrastructure for spatial augmented reality, projection mapping, and surface reflectance acquisition. Existing inverse-rendering methods for ProCams deliver high-fidelity results but rely on time-consuming per-scene optimization, while mainstream feed-forward 3D reconstruction models produce baked appearance that cannot adapt to spatially varying projector illumination. To resolve this accuracy-efficiency trade-off, we propose FF-ProCams, a Feed-Forward 3D Gaussian inverse-rendering framework for ProCams. A hybrid Mamba2-Transformer encoder aggregates cross-view geometric and photometric cues from sparse multi-view observations, and lightweight heads predict a relightable Gaussian representation in a single forward pass. We further design a projector-aware differentiable renderer to synthesize camera observations under arbitrary active illumination and ProCams poses. To enable feed-forward training, we construct a large-scale synthetic ProCams dataset covering diverse object geometries and surface materials. Experiments show FF-ProCams achieves high-fidelity projector-aware rendering, generalizes to unseen patterns, and supports novel projector-camera poses. Using only 8 input views, it outperforms optimization-based baselines with 297 views while reducing test-time reconstruction to 0.13 seconds (a three-to-five-order-of-magnitude speedup). The code and data are available at https://github.com/CPREgroup/FF-ProCams/.","authors":["Ziyao Wang","Yuqi Li","Wenxing Zheng","Jiaying Chen","Chong Wang"],"published":"2026-07-20T10:42:16Z","updated":"2026-07-20T10:42:16Z","abstract_url":"https://arxiv.org/abs/2607.17803v1","html_url":"https://arxiv.org/html/2607.17803v1","pdf_url":"https://arxiv.org/pdf/2607.17803v1.pdf","matched_keywords":["3d","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17790v1","title":"ReViV: Reconstructing the Viewer and the View in 4D from Monocular Egocentric Video","abstract":"Egocentric devices, such as wearable front-facing cameras, provide a unique perspective for capturing the continuous interaction between a human viewer and the surrounding environment. A holistic and efficient multimodal model capable of reconstructing this 4D representation is therefore highly desirable. However, existing approaches often rely on auxiliary inputs such as pre-computed camera trajectories, treat scene perception and human ego-motion modeling as separate problems despite their strong interdependency, and suffer from slow inference time. To address these limitations, we present ReViV, the first unified framework for holistic egocentric 4D reconstruction that extracts both viewer and view dynamics from a single monocular RGB video. We formulate the task as learning the full joint probability distribution over multimodal signals, including RGB video, camera trajectory, gaze direction, full-body motion, hand motion, and depth. Powered by a Masked Generative Egocentric Transformer, ReViV operates within a single feed-forward architecture to simultaneously reconstruct the temporally consistent 4D reconstruction across the viewer and the view with fast inference speed. Extensive experiments on diverse benchmarks, including HoloAssist, HOT3D, ARCTIC, Aria Digital Twin, and TACO, demonstrate that ReViV achieves state-of-the-art accuracy and efficiency across holistic ego-body, hand, and gaze reconstruction, camera tracking, while maintaining highly competitive egocentric depth estimation without relying on heavy task-specific priors. Code and models are fully open-sourced: https://reviv4d.github.io/.","authors":["Xiaozhong Lyu","Gen Li","Zhiyin Qian","Xucong Zhang","Marc Pollefeys","Siyu Tang"],"published":"2026-07-20T10:22:53Z","updated":"2026-07-20T10:22:53Z","abstract_url":"https://arxiv.org/abs/2607.17790v1","html_url":"https://arxiv.org/html/2607.17790v1","pdf_url":"https://arxiv.org/pdf/2607.17790v1.pdf","matched_keywords":["video","3d","representation","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17782v1","title":"BrainNext: A General-Purpose Self-Supervised Foundation Model for Brain MRI Analysis","abstract":"Foundation models pretrained using self-supervised learning have transformed computer vision by learning transferable representations from large-scale unlabeled data. However, existing foundation models for neuroimaging remain limited by task-specific training, slice-based learning strategies, or relatively small pretraining datasets, restricting their generalizability across diverse brain MRI applications. In this work, we present BrainNext, a general-purpose self-supervised foundation model for volumetric brain MRI analysis. BrainNext combines masked autoencoder (MAE) pretraining with a native three-dimensional Bi-Directional xLSTM-UNet architecture to learn rich anatomical representations from 60,551 unlabeled brain MRI examinations spanning multiple MRI modalities. The pretrained model is subsequently adapted to downstream tasks through lightweight task-specific fine-tuning. We evaluate BrainNext on the Foundation Models for Medical Imaging (FOMO) 2025 Method Track, encompassing classification, segmentation, and brain-age estimation, where it achieved second place overall and ranked first in the meningioma segmentation task on the official FOMO 2025 challenge leaderboard, demonstrating strong transferability across heterogeneous neuroimaging tasks. These results highlight the potential of large-scale self-supervised pretraining to learn robust and transferable volumetric representations, establishing BrainNext as a scalable foundation model for diverse brain MRI applications.","authors":["Moona Mazher","Abdul Qayyum","Steven A. Niederer","Daniel C. Alexander"],"published":"2026-07-20T10:15:02Z","updated":"2026-07-20T10:15:02Z","abstract_url":"https://arxiv.org/abs/2607.17782v1","html_url":"https://arxiv.org/html/2607.17782v1","pdf_url":"https://arxiv.org/pdf/2607.17782v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17778v1","title":"CDIS: Cross-Dimensional Class-Agnostic 3D Instance Segmentation via 2D Mask Tracking and 3D-2D Projection Merging","abstract":"Class-agnostic 3D instance segmentation is critical for robotic systems operating in unknown environments, enabling perception of previously unseen objects for reliable manipulation and navigation. Existing approaches typically project per-frame 2D instance masks into 3D and merge them, which often breaks object identities across time and yields fragmented 3D instances. We introduce Cross-Dimensional Class-Agnostic 3D Instance Segmentation (CDIS), a zero-shot framework that explicitly tracks 2D instance masks across frames and associates them with 3D superpoints, creating a feedback loop between 2D and 3D. This cross-dimensional reasoning links temporally stable 2D tracks with spatially coherent 3D regions, producing globally consistent 3D instance labels without any 3D-specific training. Experiments on benchmark datasets demonstrate that CDIS achieves higher accuracy and consistency than state-of-the-art zero-shot methods, while remaining efficient and scalable to diverse real-world environments.","authors":["Juno Kim","Hye-Jung Yoon","Yesol Park","Byoung-Tak Zhang"],"published":"2026-07-20T10:09:12Z","updated":"2026-07-20T10:09:12Z","abstract_url":"https://arxiv.org/abs/2607.17778v1","html_url":"https://arxiv.org/html/2607.17778v1","pdf_url":"https://arxiv.org/pdf/2607.17778v1.pdf","matched_keywords":["3d","instance"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17770v1","title":"Measuring Monosemanticity in Sparse Autoencoders via Latent Activation Coherence","abstract":"Within Explainable Artificial Intelligence, mechanistic interpretability uses Sparse Autoencoders (SAEs) to extract more interpretable features from neural representations. However, assessing their monosemanticity, and thus explanation quality, remains challenging. Existing metrics require external concept labels or depend on pretrained embedding models, making them sensitive to encoder's geometry. We introduce the Tversky Monosemanticity Score (TMS), a label-free metric that operationalizes monosemanticity as activation-set coherence of binarized SAE latents, and does not require external embedding encoders. We evaluate TMS on SAEs trained on features from pretrained vision and vision-language models (DINOv3, CLIP, BLIP2), two common SAE regimes (TopK, BatchTopK), multiple sparsity levels, and expansion factors. Our results show that TMS is less affected by encoder anisotropy than its embedding-based alternative, while remaining aligned with established monosemanticity indicators. TMS also reveals distinct SAE training dynamics across base models. Moreover, under encoder anisotropy, TMS provides a stronger indication of probe-based concept deletion effectiveness, while being competitive otherwise.","authors":["Katarzyna Filus","Sebastian Pokuciński"],"published":"2026-07-20T10:03:37Z","updated":"2026-07-20T10:03:37Z","abstract_url":"https://arxiv.org/abs/2607.17770v1","html_url":"https://arxiv.org/html/2607.17770v1","pdf_url":"https://arxiv.org/pdf/2607.17770v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17769v1","title":"From Sign Language Generation to Humanoid Execution: Vision-Language Guided Retargeting with Collision Mitigation","abstract":"Recent sign language generation (SLG) systems increasingly output dense 3D body representations, which better preserve full-body kinematics and geometry for downstream embodiment on humanoid robots. However, these generated motions frequently exhibit self-intersections such as hand-hand and hand-torso penetration. While such artifacts may be tolerated in offline rendering, they become critical in humanoid execution as they lead to infeasible inverse-kinematics (IK) solutions, collisions, and unstable retargeted trajectories. We present a system-level framework that bridges SLG outputs to humanoid joint-space execution via two components. First, we introduce a volumetric SMPL-X collision-mitigation module that projects generated signing motions toward physically plausible configurations while minimally deviating from the original trajectory. Second, we propose a vision-language-guided retargeting algorithm built on an IK backbone: a VLM serves as a visual critic over rendered humanoid motion, identifies embodiment-specific failure modes, and triggers targeted task-space corrections. Our results highlight collision handling and perception-guided refinement as key missing components for reliable humanoid signing.","authors":["Nabeela Khan","Bowen Wu","Runwu Shi","Benjamin Yen","Takeshi Ashizawa","Carlos Toshinori Ishi","Takashi Minato","Kazuhiro Nakadai"],"published":"2026-07-20T10:02:18Z","updated":"2026-07-20T10:02:18Z","abstract_url":"https://arxiv.org/abs/2607.17769v1","html_url":"https://arxiv.org/html/2607.17769v1","pdf_url":"https://arxiv.org/pdf/2607.17769v1.pdf","matched_keywords":["3d","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17768v1","title":"To Blend In, First Decouple: Rethinking Camouflage Image Generation via Context-Decoupled Representations","abstract":"Camouflage image generation (CIG) focuses on generating visually concealed objects that seamlessly blend into their backgrounds. Existing methods typically follow either background-guided paradigms that adapt object appearance via style transfer, or foreground-guided strategies that outpaint surrounding regions conditioned on object features. However, they still suffer from appearance discrepancy and background artifacts. We attribute these limitations to cross-context representation leakage, where object and background cues are entangled in a coupled conditional space, resulting in ambiguous control and degraded camouflage fidelity. To tackle this, we propose a new context-decoupled generative paradigm, termed CamoDreamer, which aims to isolate contextual conditional guidance and explicitly decouple latent camouflage features into coordinated object and background control streams. First, a Contrast-aware Contextual Bridge is designed to model cross-context discrepancies and construct contrast-aware dual conditional guidance. Second, Context-Decoupled Assimilation Streams are employed to separate generative interactions conditioned on the dual guidance, while facilitating background rendering with target-aware cues in the latent space. Finally, a Frequency-Adaptive Contextual Blend module integrates complementary high-frequency textures and low-frequency structures from decoupled features to improve holistic coherence. Extensive experiments demonstrate that CamoDreamer consistently outperforms existing methods with a substantial margin, while maintaining a relatively lightweight design.","authors":["Wenzhuang Wang","Yifan Zhao","Mingcan Ma","Yunlong Che","Haoran Chen","Ming Liu","Jia Li"],"published":"2026-07-20T10:01:36Z","updated":"2026-07-20T10:01:36Z","abstract_url":"https://arxiv.org/abs/2607.17768v1","html_url":"https://arxiv.org/html/2607.17768v1","pdf_url":"https://arxiv.org/pdf/2607.17768v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17754v1","title":"DA-Fusion: Deformable Attention-Based RGB-D Fusion Transformer for Unseen Object Instance Segmentation","abstract":"In logistics automation, precise segmentation of unseen objects is crucial for efficient robotic manipulation in cluttered environments. Tasks such as bin-picking and shelf-picking require robust perception to handle occlusions, varying object shapes, and complex spatial arrangements. Traditional RGB-based methods tend to over-segment objects due to their reliance on texture, while depth-based methods often under-segment by focusing primarily on geometric features. To address these limitations, we propose DA-Fusion, a deformable attention-based RGB-D fusion Transformer designed for unseen object instance segmentation. DA-Fusion effectively combines the strengths of both RGB and depth data, enhancing segmentation accuracy in cluttered and multi-layered object environments. We also introduce the Object Clutter Bin Dataset (OCBD), a benchmark dataset specifically tailored for evaluating bin-picking scenarios in top-down views. Extensive evaluations demonstrate that DA-Fusion outperforms state-of-the-art methods across diverse environments, making it particularly suited for real-world logistics tasks.","authors":["Yesol Park","Hye-Jung Yoon","Juno Kim","Byoung-Tak Zhang"],"published":"2026-07-20T09:47:16Z","updated":"2026-07-20T09:47:16Z","abstract_url":"https://arxiv.org/abs/2607.17754v1","html_url":"https://arxiv.org/html/2607.17754v1","pdf_url":"https://arxiv.org/pdf/2607.17754v1.pdf","matched_keywords":["instance"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17718v1","title":"PC-Seg: Progressive Cross-View Consistency for 3D OCT Segmentation from Sparse 2D Annotations","abstract":"Volumetric segmentation of optical coherence tomography (OCT) images is essential for diagnosing ocular diseases but requires labor-intensive voxel-wise annotations. While semi-supervised learning (SSL) can reduce annotation costs, most existing methods process data slice by slice and fail to exploit the inherent 3D spatial context. We propose PC-Seg, a progressive cross-view consistency framework that learns high-accuracy 3D segmentation models from sparse 2D annotations. Unlike conventional multi-view approaches, PC-Seg uses a single 2D model to learn cross-view consistency from standard B-scans and orthogonal slices, thereby generating reliable volumetric pseudo-labels. These pseudo-labels are then distilled into a 3D model, followed by a co-training stage in which the 2D and 3D models mutually refine each other through ensemble pseudo-labeling. Experiments on the MSHC and Duke DME datasets demonstrate that PC-Seg achieves accuracy comparable to fully supervised learning while using labels for only about 0.7% of the training data, outperforming state-of-the-art semi-supervised and retinal layer segmentation methods. Our code is publicly available at https://github.com/gsisaoki/pc-seg-official.","authors":["Tsubasa Konno","Takahiro Ninomiya","Yukun Zhou","Koichi Ito","Siegfried K. Wagner","Yiqun Lin","Pearse A. Keane","Toru Nakazawa","Takafumi Aoki"],"published":"2026-07-20T09:12:04Z","updated":"2026-07-20T09:12:04Z","abstract_url":"https://arxiv.org/abs/2607.17718v1","html_url":"https://arxiv.org/html/2607.17718v1","pdf_url":"https://arxiv.org/pdf/2607.17718v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17675v1","title":"ShotPlan: Cinematic Video Generation with Learnable Planning Token","abstract":"Current video generation models achieve impressive results in single-shot generation, yet remain limited in cinematic video generation, where coherent narratives and effective multi-shot composition require explicit shot planning. To address this challenge, we propose ShotPlan, a framework for explicit multi-shot cinematic video generation built upon a video diffusion foundation model. Our method introduces learnable planning tokens that capture shot-level transition cues and can be seamlessly integrated with the original video generation tokens to control transition timestamps. Unlike standard video generation tokens, the proposed planning tokens are equipped with Fractional Temporal Rotary Position Embedding (FRoPE), enabling shot transitions to be modeled at the frame level. Experiments demonstrate that ShotPlan significantly outperforms existing cinematic video generation methods, offering more flexible shot management and stronger inter-shot consistency.","authors":["Su Guo","Guangce Liu","Haosen Yang","Jiepeng Wang","Cong Liu","Junqi Liu","Haibin Huang","Hongxun Yao","Chi Zhang","Xuelong Li"],"published":"2026-07-20T08:27:18Z","updated":"2026-07-20T08:27:18Z","abstract_url":"https://arxiv.org/abs/2607.17675v1","html_url":"https://arxiv.org/html/2607.17675v1","pdf_url":"https://arxiv.org/pdf/2607.17675v1.pdf","matched_keywords":["video","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17669v1","title":"Attention from Above: A Multimodal Model for Drone-Based Object Localization","abstract":"Drone-based object detection technology has advanced rapidly, becoming increasingly sophisticated and efficient. Recently, research trends have expanded beyond the detection of predefined objects toward the identification of specified target objects. For example, desired targets can be specified through textual prompts, enabling accurate detection of objects of interest. To address this demand, this paper proposes an efficient multimodal-based object detection model aimed at improving small object detection performance. The proposed method is built upon the YOLO-World framework and replaces the C2f layers used in the YOLOv8 backbone with attention-based A2C2f layers. This modification enables more precise representation of local features, particularly for small objects or objects with well-defined boundaries. In addition, the incorporation of attention mechanisms and parallel processing structures significantly enhances the model's computational accuracy. Comparative experiments conducted on the VisDrone dataset demonstrate that the proposed model outperforms the original YOLO-World model. Specifically, precision increases from 43.0% to 45.1%, recall from 32.8% to 35.0%, the F1 score from 37.2% to 39.4%, mAP@0.5 from 32.5% to 35.2%, and mAP@0.5-0.95 from 18.5% to 19.9%, confirming a substantial improvement in detection accuracy. These results verify that the proposed approach provides an effective and highly accurate solution for object detection in drone-based image and video application environments.","authors":["Hyun-Ki Jung"],"published":"2026-07-20T08:21:12Z","updated":"2026-07-20T08:21:12Z","abstract_url":"https://arxiv.org/abs/2607.17669v1","html_url":"https://arxiv.org/html/2607.17669v1","pdf_url":"https://arxiv.org/pdf/2607.17669v1.pdf","matched_keywords":["video","representation","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17660v1","title":"RayOcc: Occlusion-Aware Ray Occupancy Estimation via Gaussian Mixture Intensity","abstract":"Camera-only 3D semantic occupancy prediction aims to infer voxel-wise scene semantics from multi-view images, yet remains fundamentally challenging due to depth ambiguity and occlusion. Along a single camera ray, multiple spatially separated surfaces may coexist, making occupancy inherently a multi-label existence problem rather than a single-depth estimation task. However, most existing approaches favor a single dominant depth hypothesis per ray, limiting their ability to model volumetric scenes under complex occlusion. To address this limitation, we introduce RayOcc, an occlusion-aware ray occupancy framework that reformulates ray modeling as multi-label existence prediction. Instead of predicting a categorical depth distribution, RayOcc estimates a non-normalized Gaussian mixture intensity along each ray and converts it into interval-wise occupancy probabilities via a Poisson event formulation, allowing multiple occupied hypotheses to coexist without enforcing mutual competition across depth. The predicted mixture components are interpreted as occupancy hypotheses to initialize sparse 3D Gaussian primitives, which are refined and rasterized for semantic occupancy prediction. Experiments on the nuScenes benchmark show that RayOcc achieves state-of-the-art overall IoU and mIoU among the compared Gaussian-based occupancy methods.","authors":["Junho Kim","Seongwon Lee"],"published":"2026-07-20T08:10:58Z","updated":"2026-07-20T08:10:58Z","abstract_url":"https://arxiv.org/abs/2607.17660v1","html_url":"https://arxiv.org/html/2607.17660v1","pdf_url":"https://arxiv.org/pdf/2607.17660v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17657v1","title":"OrientSAM: Mitigating Camera-Centric Shortcut in Multimodal Spatial Reasoning via Orientation-Aware Spatial Alignment","abstract":"Multimodal large language models (MLLMs) still struggle with spatial reasoning that requires perspective transformation. In particular, they often rely on camera-centric cues rather than reasoning from the reference object's viewpoint, leading to systematic errors in non-camera reference settings. In this paper, we first analyze this failure mode and show that object orientation is a key factor underlying such camera-centric shortcut behavior. To address this issue, we propose OrientSAM, an orientation-aware spatial alignment framework for multimodal models. OrientSAM injects explicit orientation information into multimodal representations through orientation-aware tokens and Fourier-based angle encoding, and further adopts a curriculum learning strategy to progressively improve perspective-aware reasoning. In addition, we build a spatial data construction pipeline to generate orientation-aware spatial supervision from large-scale images. Experiments on Spatial-MM, ViewSpatial, and 3DSRBench show that OrientSAM consistently outperforms strong baselines, especially on non-camera-view, person-centric, and orientation-sensitive tasks. The results further demonstrate that explicit orientation modeling is important for mitigating camera-centric shortcut behavior and enabling more robust allocentric spatial reasoning in multimodal models.","authors":["Wenxiao Fan","Hang Yin","Kan Li"],"published":"2026-07-20T08:07:22Z","updated":"2026-07-20T08:07:22Z","abstract_url":"https://arxiv.org/abs/2607.17657v1","html_url":"https://arxiv.org/html/2607.17657v1","pdf_url":"https://arxiv.org/pdf/2607.17657v1.pdf","matched_keywords":["3d","representation","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17656v1","title":"BMFA: Boundary-Minority Free-Energy Adaptive Screening","abstract":"Vision Transformers process spatially redundant tokens efficiently only when coarse token summaries preserve the evidence required by exponential attention aggregation. We identify a boundary-minority underestimation failure in which a spatially small, high-response region contributes dominant Gibbs mass while remaining nearly invisible to a block mean. We formalize the failure through the discrepancy between normalized log-mean-exp free energy and mean summarization, prove that minority Gibbs mass can remain non-vanishing as its spatial support and mean contribution vanish, and characterize the limitations of finite-order moment corrections. Building on the resulting analysis, we introduce Boundary-Minority Free-Energy Adaptive Screening (BMFA), which constructs a hierarchical piecewise-constant approximation and recursively refines blocks according to a computable lower-bound increment of local free energy. Controlled synthetic tests, COCO and LVIS diagnostic probes, closed-loop DeiT-Tiny evaluations, and ImageNet-1K experiments establish a consistent evidence chain. BMFA reduces the mean synthetic underestimate from 2.582 to 0.261 at a 5.794% leaf ratio, lowers the COCO image-edge mean gap from 2.254 to 0.526, and preserves 71.520% ImageNet Top-1 accuracy at a 55.861% leaf ratio. The current prototype evaluates selection quality after full QK computation; the reported leaf ratio therefore characterizes representation granularity rather than verified sparse-kernel speedup.","authors":["Wenyan Xu","Alizer Wong"],"published":"2026-07-20T08:07:18Z","updated":"2026-07-20T08:07:18Z","abstract_url":"https://arxiv.org/abs/2607.17656v1","html_url":"https://arxiv.org/html/2607.17656v1","pdf_url":"https://arxiv.org/pdf/2607.17656v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17639v1","title":"Direct Clinical Joint Angle Extraction from Parametric Body Model Rotation Matrices","abstract":"Quantitative joint angles are rarely available in routine care because the tools are slow, costly, or confined to a laboratory. We show that clinical joint angles can be read directly from the per-segment rotation matrices a parametric body model already produces, with no inverse-kinematics or musculoskeletal-model fitting step. On the OpenCap LabValidation cohort, using the GEM-X body-model estimator on single-smartphone video, our pooled mean absolute error is 4.50 degrees over the fifteen joint angles that match the OpenCap Monocular reference set, the same accuracy range as OpenCap Monocular's 4.8 degrees on the same cohort and reference standard, from a much simpler pipeline. The step that connects a body model to clinical angles is a small calibration table rather than an optimisation, so the same procedure transfers unchanged to other body models: repeating it on SAM 3D Body, changing only the table, gives 4.66 degrees, statistically indistinguishable from GEM-X, and runs in real time from a live single-camera stream. The method needs no per-recording inputs beyond the video itself: no participant height, no camera-intrinsics database, no per-subject model scaling. This broadens where movement analysis is practical, from in-clinic and at-home recording to telerehabilitation and large-scale decentralised studies.","authors":["Joey Páolo Kardolus","Daan Hendriks","Jaap Jansen"],"published":"2026-07-20T07:47:56Z","updated":"2026-07-20T07:47:56Z","abstract_url":"https://arxiv.org/abs/2607.17639v1","html_url":"https://arxiv.org/html/2607.17639v1","pdf_url":"https://arxiv.org/pdf/2607.17639v1.pdf","matched_keywords":["video","3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17638v1","title":"Reviving Ancient Paintings via Poem: A Colorization Framework for Aligning Cultural Semantics","abstract":"The irreversible fading of ancient paintings disrupts the \"congruence between poems and paintings\", a core aesthetic principle where visual imagery harmonizes with literary inscriptions. Although diffusion models provide strong generative priors, restoring historically faithful colors remains difficult: visual restoration is inherently ambiguous, while direct text guidance often causes modern semantic bias, over-saturation, and cross-boundary color leakage. To address this, we propose PoemColor, a poem-guided ancient painting colorization framework. Our method aligns poetic cultural semantics with painting restoration through two key designs. First, the Poetic Painting Projector (P3) converts implicit poetic context into a classical color-aware condition via poem-to-palette pretraining, reducing the ambiguity of poem-to-color mapping. Second, Structure-Aware Semantic Attention (SASA) regulates how poetic color semantics are injected into the diffusion backbone by jointly controlling their propagation direction and regional injection strength. In addition, we construct a hybrid restoration dataset that integrates synthetic degradation with expert-restored artifacts, providing both scalable supervision and real classical color references. Extensive experiments demonstrate that our framework significantly outperforms state-of-the-art methods, delivering controllable colorization that revives both historical authenticity and poetic semantics.","authors":["Junming Gao","Biao Zhu","Xiaosong Wang","Tan Tang"],"published":"2026-07-20T07:46:37Z","updated":"2026-07-20T07:46:37Z","abstract_url":"https://arxiv.org/abs/2607.17638v1","html_url":"https://arxiv.org/html/2607.17638v1","pdf_url":"https://arxiv.org/pdf/2607.17638v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17634v1","title":"MixDiffusion: Mixing Diffusion-based Uni-condition Text-to-Image Generation Models for Multi-condition Image Synthesis","abstract":"Recent advances in text-to-image (T2I) generation have enabled controllable image synthesis by incorporating conditions beyond text. However, most existing diffusion-based methods are limited to a single type of control condition (e.g., bounding boxes or keypoints), which restricts their flexibility. To address this limitation, we propose MixDiffusion, a training-free diffusion framework for multi-condition T2I generation. MixDiffusion theoretically supports an arbitrary number of control conditions, including bounding boxes, keypoints, sketches, depth maps, reference images, and text, by collaboratively integrating multiple pre-trained uni-condition diffusion models. The key insight of the proposed approach is to derive the predicted noise distribution in each denoising step of the diffusion-based multi-condition image generation model from the predicted noise distributions of multiple diffusion-based uni-condition models with a derived integration formula, which is supported by rigorous theory proof. Owing to its training-free nature, MixDiffusion is easy to deploy and readily extensible to new control modalities.","authors":["Pengcheng Wan","Liang Han","Lin Xu","Bowen Xiao","Liqiang Nie"],"published":"2026-07-20T07:40:56Z","updated":"2026-07-20T07:40:56Z","abstract_url":"https://arxiv.org/abs/2607.17634v1","html_url":"https://arxiv.org/html/2607.17634v1","pdf_url":"https://arxiv.org/pdf/2607.17634v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17625v1","title":"Brain-Aligned Multi-Stream Video Transformers with Sparse Self-Selection","abstract":"Modern video transformers typically ignore principles from primate vision and are rarely evaluated against neural data, limiting their biological interpretability. We introduce a sparse winner-takes-all token selection module that replaces dense self-attention to improve efficiency and approximate competitive routing observed in biological visual circuits. We further propose a neuro-inspired split-and-fuse video transformer which uses two complementary pathways: a high-resolution, low-frame-rate \"what\" stream and a low-resolution, high-frame-rate \"where\" stream, fused before classification. On Kinetics-400 and Something-Something V2, our best variant operates on the Pareto frontier of accuracy versus inference time among models of comparable scale and pretraining, and showing improved robustness to spatial perturbations. Using representational similarity analysis between model embeddings and time-resolved EEG recordings for the same video stimuli, our model attains a peak brain-model correlation of 0.18 (about 78% of the noise ceiling) and consistently outperforms strong video transformer baselines, suggesting that pathway specialization and sparse competition are useful inductive biases for efficient, brain-aligned video understanding.","authors":["Amir Hosein Fadaei","Mahyar Maleki","Mohammad-Reza A. Dehaqani"],"published":"2026-07-20T07:30:16Z","updated":"2026-07-20T07:30:16Z","abstract_url":"https://arxiv.org/abs/2607.17625v1","html_url":"https://arxiv.org/html/2607.17625v1","pdf_url":"https://arxiv.org/pdf/2607.17625v1.pdf","matched_keywords":["video","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17612v1","title":"Rarity-Aware Discrete Diffusion with Spatially Consistent Decoding for Photo-Realistic Image Super-Resolution","abstract":"Continuous diffusion models have become the dominant paradigm for photo-realistic image Super-Resolution (SR), but they typically formulate reconstruction as continuous signal-level denoising and incorporate semantic priors through external conditioning modules. This makes it less direct to exploit the unified token-based scaling paradigm of modern multimodal models. Autoregressive models provide a more native semantic representation by modeling images as discrete visual tokens, yet their causal decoding is inefficient for high-resolution reconstruction. Discrete diffusion offers a promising middle ground by enabling non-causal, parallel prediction over visual tokens. However, directly adapting discrete diffusion to SR remains non-trivial due to two task-specific challenges: (1) the long-tailed distribution of visual tokens, which under-represents rare but perceptually critical textures; and (2) spatially inconsistent parallel decoding, which may introduce isolated artifacts. To address these issues, we propose DiMOO-SR, a rarity-aware multimodal discrete diffusion framework for photo-realistic image SR. During training, Inverse Frequency Sampling (IFS) prioritizes under-represented but information-rich tokens. During inference, Spatial Consistency Ranking (SCR) refines token confidence using local neighborhood agreement to improve structural coherence. Extensive experiments on widely used real-world SR benchmarks demonstrate that DiMOO-SR achieves competitive perceptual quality with only a few parallel decoding steps, highlighting the potential of discrete diffusion for generative image super-resolution. The code will be released upon publication.","authors":["Ao Li","Yapeng Du","Yi Xin","Lei Zhu","Le Zhang","Guangtao Zhai","Ce Zhu","Xiaohong Liu"],"published":"2026-07-20T07:01:01Z","updated":"2026-07-20T07:01:01Z","abstract_url":"https://arxiv.org/abs/2607.17612v1","html_url":"https://arxiv.org/html/2607.17612v1","pdf_url":"https://arxiv.org/pdf/2607.17612v1.pdf","matched_keywords":["representation","multimodal","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17611v1","title":"Coarse-to-fine Framework for Generative MEF via Implicit Neural Representation","abstract":"Multi-exposure fusion (MEF) expands the luminance range beyond what a single exposure can capture. Combining images taken at different exposure levels requires handling geometric differences while naturally merging their complementary brightness information. It often demands generative completion where details are missing. Diffusion-based generative methods address these challenges, however, they are computationally expensive and struggle to preserve fine structures in saturated regions. We propose LIIFusion, a coarse-to-fine framework that balances fusion quality and efficiency in generative MEF. The coarse stage performs low resolution generative fusion, enhanced by an adaptive exposure correction that recovers structure lost in saturated over-exposed areas. The fine stage adapts a local implicit image function into a multi-exposure fusion function: conditioned on the HR OE/UE sources and the coarse output, it queries arbitrary target coordinates and fuses source evidence regardless of the HR input resolution. LIIFusion achieves up to 3.5$\\times$ speed-up over existing generative methods while maintaining or improving structural fidelity and perceptual quality. We believe this framework provides an effective pathway toward making generative MEF more practical in real-world applications.","authors":["Sangmin Han","Jinho Kim","Jinwoo Kim","Dongyoung Kim","Seon Joo Kim"],"published":"2026-07-20T07:00:47Z","updated":"2026-07-20T07:00:47Z","abstract_url":"https://arxiv.org/abs/2607.17611v1","html_url":"https://arxiv.org/html/2607.17611v1","pdf_url":"https://arxiv.org/pdf/2607.17611v1.pdf","matched_keywords":["representation","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17599v1","title":"ConsiSpace: Learning Geometric Consistency Matters for Video Spatial Reasoning","abstract":"Video spatial reasoning is essential for navigation-oriented perception and long-video question answering, where models must infer spatial relations across long horizons under changing viewpoints. However, existing multimodal large language models (MLLMs) remain largely semantic-centric, and often fail to reliably aggregate consistent spatial evidence from redundant video observations, leading to inefficient or unstable reasoning. To address these issues, we propose ConsiSpace, a geometry-consistency-aware framework for geometry-sensitive video spatial reasoning that turns spatial consistency into both an evidence organization principle and an explicit post-SFT learning signal. We build a geometry-consistent memory (GCM) including implicit evidence tokens and explicit geometric cues, and leverage efficient organization strategies to compactly preserve task-related spatial evidence. Furthermore, we utilize unified consistency self-supervised reinforcement learning (UC-SSRL) after supervised fine-tuning to improve cross-view stability, with answer-, metric-, and topology-consistency rewards. Extensive experiments on three spatial-reasoning benchmarks, VSI-Bench, OSI-Bench, and MMSI-Video-Bench, show consistent gains, improving the average score by 12.6 points over the strongest baselines.","authors":["Ting Huang","Zhenyu Zhang","Wenyuan Huang","Jian Yang","Hao Tang"],"published":"2026-07-20T06:40:45Z","updated":"2026-07-20T06:40:45Z","abstract_url":"https://arxiv.org/abs/2607.17599v1","html_url":"https://arxiv.org/html/2607.17599v1","pdf_url":"https://arxiv.org/pdf/2607.17599v1.pdf","matched_keywords":["video","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17585v1","title":"Pixel-Space Diffusion Transformers","abstract":"Latent diffusion models (LDMs) enable efficient high-resolution image synthesis by denoising in a VAE-compressed latent space. However, fixed visual tokenizers can discard fine textures and structural details, while separate representation and diffusion training creates a mismatch between reconstruction and generation objectives. These limitations have renewed interest in pixel-space diffusion, which models raw pixels directly, removes the VAE bottleneck, and supports end-to-end optimization. This formulation better matches the demands of high-fidelity generation but introduces challenges in high-dimensional modeling, including noise scheduling, loss weighting, token efficiency, and scalable architecture design. Pixel-space modeling also offers a promising basis for unified multimodal systems: raw pixels, text, and task conditions can be represented in a shared token space and jointly processed by a single Transformer, narrowing the gap between visual understanding and generation. This paper reviews Pixel-Space Diffusion Transformers (pDiTs) from the perspectives of model architecture, continuous generative mechanisms, and unified multimodal modeling. We summarize representative methods, identify key technical challenges, and discuss future directions toward high-fidelity, end-to-end vision foundation models that integrate generation and understanding.","authors":["Renye Yan","Jikang Cheng","You Wu","Ling Liang","Wei Peng","Athanasios V. Vasilakos","Qingyu Zhao","Yu Zhang","Ehsan Adeli","Kilian M. Pohl","Guoying Zhao"],"published":"2026-07-20T06:04:08Z","updated":"2026-07-20T06:04:08Z","abstract_url":"https://arxiv.org/abs/2607.17585v1","html_url":"https://arxiv.org/html/2607.17585v1","pdf_url":"https://arxiv.org/pdf/2607.17585v1.pdf","matched_keywords":["representation","multimodal","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17572v1","title":"AGG: Jacobian-Aggregated Group Gradient for Efficient GRPO Training of Diffusion Models","abstract":"Group Relative Policy Optimization (GRPO) is a powerful reinforcement learning algorithm for aligning generative models with human preferences. While successful in large language models~\\cite{shao2024deepseekmathpushinglimitsmathematical}, its extension to diffusion and flow matching models introduces a severe computational bottleneck: gradients must be back-propagated through the high-capacity DiT backbone at \\emph{every} timestep of the sampling trajectory, making high-resolution text-to-image (T2I) training prohibitively expensive. Training-free DiT inference acceleration methods (e.g., $Δ$-DiT, ScalingCache) exploit the fact that DiT hidden states and velocity predictions vary \\emph{smoothly and nearly linearly} along the trajectory. We ask whether the same linearity can reduce the backward-pass cost of DiT RL training, and answer affirmatively with \\textbf{JAGG} (\\textbf{J}acobian-\\textbf{A}ggregated \\textbf{G}roup \\textbf{G}radient), which reduces full transformer backward passes from $W$ to $2$ per group of $W$ consecutive steps. JAGG approximates intermediate-step Jacobians via $t$-weighted interpolation of the endpoint Jacobians, then aggregates per-step upstream signals into two composite gradients applied through a single joint backward pass. We prove this interpolation is \\emph{exact} when the velocity is linear in $(z,t)$, and a cosine-similarity routing rule (\\texttt{jagg\\_frac}) deploys JAGG only where the assumption holds. Experiments on T2I benchmarks show JAGG delivers $\\sim$2$\\times$ backward speedup with negligible quality degradation.","authors":["Ruiyi Ding","Jie Li","He Kang","Ziyan Liu","Chengru Song","Yuan chen"],"published":"2026-07-20T05:30:40Z","updated":"2026-07-20T05:30:40Z","abstract_url":"https://arxiv.org/abs/2607.17572v1","html_url":"https://arxiv.org/html/2607.17572v1","pdf_url":"https://arxiv.org/pdf/2607.17572v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17563v1","title":"FlexiGrad: Adaptive Gradient Modulation for Hierarchical Fine-Grained Classification","abstract":"Many fine-grained recognition tasks contain hierarchical labels such as order, family and species. Although this supervision should be beneficial, jointly optimising all levels often leads to unstable training because coarse and fine classifiers impose inconsistent gradients on the shared backbone. This hierarchical gradient conflict prevents the model from learning a coherent coarse-to-fine representation. In this paper, we propose FlexiGrad, a simple and parameter-free method that regulates gradient interactions during backpropagation. FlexiGrad removes only the harmful conflicting component when tasks disagree and reinforces the shared direction when they partially agree through a smooth hierarchy-aware weighting function. This produces stable optimisation and preserves both global structure and fine-grained discriminative cues. FlexiGrad integrates into existing architectures without modification while improves multi-granularity accuracy on CUB-200-2011, FGVC-Aircraft and Stanford Cars. The code will be available at PRIS-CV/FlexiGrad.","authors":["Zilu Zhou","Dongliang Chang","Junhan Chen","Zhanyu Ma"],"published":"2026-07-20T05:18:19Z","updated":"2026-07-20T05:18:19Z","abstract_url":"https://arxiv.org/abs/2607.17563v1","html_url":"https://arxiv.org/html/2607.17563v1","pdf_url":"https://arxiv.org/pdf/2607.17563v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17551v1","title":"Hierarchy-Aware and Anatomy-Guided Learning for Lung Ultrasound Video Classification","abstract":"Lung ultrasound (LUS) is a bedside tool for assessing pulmonary edema in patients at risk due to heart failure or impaired kidney function. However, automated LUS analysis remains challenging because of speckle noise, imaging artifacts, and operator-dependent acquisition variability. In this work, we present a deep learning framework for multi-class LUS video classification that explores two components: hierarchy-aware training, and anatomy-guided learning. Starting from a strong baseline, we introduce hierarchical training strategies and then introduce pleural line mask supervision to guide model attention toward anatomically relevant regions. We study four clinically relevant classes--healthy, B-lines, consolidations, and mixed B-lines with consolidations--using an open-access dataset of 1,886 videos from 219 patients, evaluated with patient-level five-fold cross-validation. Results show that hierarchy-aware training improves pathological separation relative to flat classification, while mask-guided attention supervision achieves the highest mean macro-F1 of 65.7\\% and produces more localized attention patterns. Transfer experiments on the external COVID-BLUeS dataset further show competitive and parameter-efficient adaptation while preserving pleural-focused attention behavior. These findings suggest that combining clinically structured objectives with anatomy-guided supervision is a practical approach to robust, interpretable LUS video analysis. Code and model implementations are available at https://github.com/Alya-Almsouti/LUS-video-classification.","authors":["Alya Almsouti","Lotfi Mecharbat","Noha Aboukhater","Yousef Alabrach","Siddiq Anwar","Andre Kumar","Ibrahim Almakky","Mohammad Yaqub"],"published":"2026-07-20T04:55:28Z","updated":"2026-07-20T04:55:28Z","abstract_url":"https://arxiv.org/abs/2607.17551v1","html_url":"https://arxiv.org/html/2607.17551v1","pdf_url":"https://arxiv.org/pdf/2607.17551v1.pdf","matched_keywords":["video"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17523v1","title":"Thinking in Video: Can Video Generators Really Reason About the Real World?","abstract":"Recent advances in world models and video generation have given rise to an emerging reasoning paradigm that leverages video generative models to simulate, predict, and reason about real-world dynamics. We redefine this paradigm as Thinking in Video, where video is not merely an output artifact but a medium for constructing, extending, and verifying causal thought. However, this promise remains unverified: convincing rollouts may reflect memorized appearances rather than causal understanding, while existing metrics separate perceptual fidelity from semantic logic. To evaluate whether video generators support such reasoning, we introduce the Causal-Generative Dual-Judge (CGDJ), auditing World Model Consistency from two perspectives. Explicit Causal Perception tests whether a generator reads a video scenario as a reasoning problem through spatio-temporal flattened visual question answering, while Implicit Generative Perception-Prediction Gap evaluates whether it renders the causal consequence as a consistent future video. Applying CGDJ to representative open- and closed-source generators reveals a clear Perception-Prediction Gap: open-source models produce plausible dynamics despite near-zero explicit causal perception, whereas advanced closed-source systems show stronger but still limited alignment between reasoning and generation. Further analysis exposes audio-visual misalignment, where models verbalize correct causal logic more reliably than they render it, challenging the \"world simulator\" narrative.","authors":["Yongheng Zhang","Guang Yang","Ruihan Hou","Qiguang Chen","Ziang Liu","Xiaolong Liu","Manman Zhang","Yanchao Hao","Zheng Wei","Hao Wu","Libo Qin","Peishan Dai","Yinghui Li","Di Yin","Xing Sun"],"published":"2026-07-20T03:56:43Z","updated":"2026-07-20T03:56:43Z","abstract_url":"https://arxiv.org/abs/2607.17523v1","html_url":"https://arxiv.org/html/2607.17523v1","pdf_url":"https://arxiv.org/pdf/2607.17523v1.pdf","matched_keywords":["video"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17504v1","title":"DecoyFace: Beyond Obfuscation via Controllable and Imperceptible Identity Misdirection for Privacy-Preserving Face Recognition","abstract":"Split face recognition reduces client-side computation but exposes intermediate features to feature inversion attacks and unauthorized analysis by honest-but-curious (HBC) servers. Existing privacy-preserving face recognition methods mainly aim to resist unauthorized reconstruction, typically producing features whose inversion yields visibly degraded results, which may reveal the existence of protection and motivate adaptive attacks. To address this issue, we propose DecoyFace, an imperceptible decoy-oriented framework that steers unauthorized reconstruction toward a plausible but incorrect identity while preserving recognition utility. The key idea is to decompose the intermediate representation into a reconstruction-sensitive subspace and its complementary subspace. The client injects decoy identity cues into the reconstruction-sensitive subspace, while limited recognition-relevant evidence from the true sample is retained in the complementary subspace. On the server side, an authorized canonicalization module suppresses decoy-dominant components and recovers a recognition-friendly representation. This design addresses both attacker-side inversion from intercepted features and HBC server-side reconstruction from canonicalized representations. Experiments show that DecoyFace preserves competitive recognition accuracy while substantially reducing identity leakage to 2.93% under U-Net attacks and 0.74% under Flow-Matching attacks while yielding visually plausible and imperceptible reconstructions, with over 99.78% face validity on LFW dataset.","authors":["Zhihan Ren","Lijun He","Xinyao Wang","Xinzhu Fu","Fan Li"],"published":"2026-07-20T03:19:00Z","updated":"2026-07-20T03:19:00Z","abstract_url":"https://arxiv.org/abs/2607.17504v1","html_url":"https://arxiv.org/html/2607.17504v1","pdf_url":"https://arxiv.org/pdf/2607.17504v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17482v1","title":"Generative Transmission: Rethinking Computation, Bandwidth, and Memory in Communication","abstract":"Under the AI Flow framework, communication is shifting from transmitting fidelity-oriented information flows toward delivering task-oriented and perception-oriented token flows across heterogeneous network resources. Video communication is a fundamental component of modern information networks. However, under ultra-low-bandwidth and weak-network conditions, conventional video coding and transmission methods, which are primarily optimized for pixel-level fidelity, often struggle to balance visual usability, transmission efficiency, and robustness to unstable links. With the rapid advancement of generativemodels, video communication is also moving from precise signal reconstruction toward receiver-side perceptual utility and system-level usability. In this paper, we propose Generative Transmission (GenTrans) for video communication under ultra-low-bandwidth and weak-network conditions. Built upon Generative Video Compression (GVC), GenTrans formulates video transmission as a joint optimization problem involving bandwidth, computation, and memory, rather than treating it merely as a signal coding task. By leveraging generative priors, cross-clip memory reuse, runtime state reuse, and weak-network-aware transport, GenTrans significantly reduces transmission overhead while enabling visually coherent and practically useful reconstruction. Experimental results show that GenTrans supports effective video transmission under ultra-low-bitrate and weak-network conditions, achieving improved transmission efficiency, decoding efficiency, and robustness while preserving perceptual quality.","authors":["Xiangyu Chen","Jixiang Luo","Yuankai Fan","Haibin Huang","Chi Zhang","Xuelong Li"],"published":"2026-07-20T02:11:26Z","updated":"2026-07-20T02:11:26Z","abstract_url":"https://arxiv.org/abs/2607.17482v1","html_url":"https://arxiv.org/html/2607.17482v1","pdf_url":"https://arxiv.org/pdf/2607.17482v1.pdf","matched_keywords":["video"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17467v1","title":"DA-MergeLoRA: Hypernetwork-Based LoRA Merging for Few-Shot Test-Time Domain Adaptation","abstract":"Few-shot Test-Time Domain Adaptation (FSTT-DA) seeks to adapt models to novel domains using only a handful of unlabeled target samples. This setting is more realistic than typical domain adaptation setups, which assume access to target data during source training. However, prior FSTT-DA approaches fail to effectively leverage source domain-specific knowledge, relying on shallow batch normalization updates, prompt-based methods that treat the model as a black box, or ensembling strategies that do not capture cross-domain relationships. To address these limitations, we introduce a new FSTT-DA framework that integrates LoRA fine-tuning with model merging. In our approach, separate LoRA modules are fine-tuned on CLIP's vision encoder for each source domain. Since LoRA modifies only a small fraction of the model's parameters, it retains the base model's generalized knowledge while internally learning domain-specific features. To adapt the learned knowledge to a specific target domain, we propose a hypernetwork trained via meta-learning that generates per-column merging factors to combine LoRA modules. Given a small batch of target images, the hypernetwork produces merging weights that fuse source LoRA modules into a single adapted representation. Our results demonstrate state-of-the-art performance across various domain adaptation datasets. Our code is publicly available at https://github.com/nahbois4321/DA-MergeLoRA.","authors":["Siobhan Reid","Zhixiang Chi","Li Gu","Omid Reza Heidari","Ziqiang Wang","Yang Wang"],"published":"2026-07-20T01:45:37Z","updated":"2026-07-20T01:45:37Z","abstract_url":"https://arxiv.org/abs/2607.17467v1","html_url":"https://arxiv.org/html/2607.17467v1","pdf_url":"https://arxiv.org/pdf/2607.17467v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"},{"id":"2607.17441v1","title":"An Explainable FFT-Based Spatial-Frequency Fusion Framework for Deepfake Detection","abstract":"Deepfake generation has raised growing concerns regarding digital media authenticity, misinformation, identity fraud, and public trust. Recent studies show that combining spatial and frequency features leads to stronger detection results than using independently. This paper presents MSCA-FFT, a Fast Fourier Transform (FFT)-based multi-scale cross-attention framework for image-level deepfake detection. The model combines a partially fine-tuned Xception spatial branch with an FFT-based frequency branch. The frequency branch processes the log-scaled FFT magnitude spectrum through shallow convolutional layers, avoiding inverse frequency-to-image reconstruction used in DCT-based pipelines. The spatial and frequency representations are refined by transformer encoders, fused through cross-attention, and passed to an MLP classifier for real/fake prediction. Experimental results show that MSCA-FFT achieves consistently higher performance than the DCT-based state-of-the-art spatial-frequency fusion method and the compared baseline models. The ablation study further indicates that the FFT-based frequency branch provides complementary spectral cues when fused with spatial features. In addition, FFT-based frequency analysis and Grad-CAM/LIME explanations show consistent evidence around manipulation-sensitive facial regions, including the eyes, mouth, nose, and facial boundaries.","authors":["Pamela Kirui","Cho Hyuk","Qingzhong Liu","Haodi Jiang"],"published":"2026-07-19T23:45:40Z","updated":"2026-07-19T23:45:40Z","abstract_url":"https://arxiv.org/abs/2607.17441v1","html_url":"https://arxiv.org/html/2607.17441v1","pdf_url":"https://arxiv.org/pdf/2607.17441v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-21T04:12:05+00:00","last_seen_at":"2026-07-21T04:12:05+00:00"}],"tracked_paper_count":60,"storage_mode":"latest_overwrite"}};
